// Rules DB synced from TOW en 1 (name EN + desc FR via RULES_DESC_FR fallback EN).
window.RULES_DB = {"da-skull-smasha":{"name":"Frakass' Crânes","desc":"Deux profils ; choisir au début du premier round de combat. — Marteau : Combat, Force F+2, PA -1. Règles spéciales : Arme Perforante (2), Attaques Magiques. — Bec-de-corbin : Combat, Force F, PA -2. Règles spéciales : Arme Perforante (2), Attaques Magiques, Blessures Multiples (2). Note : arme de Kiknik Toofsnatcha (Arcane Journal)."},"massive-gob":{"name":"Gueule Immense","desc":"Profil : Combat, Force F, PA -1. Règles spéciales : Arme Perforante (1), Coup Fatal. Note : arme naturelle du Squig des Cavernes Géant."},"huge-gob":{"name":"Immense gueule","desc":"Profil : Combat, Force F, PA -1. Règles spéciales : Arme Perforante (1). Note : arme naturelle des Squigs des Cavernes (Troupeaux de Squigs) et des Squigs Bondissants."},"colossal-fang-filled-gob":{"name":"Colossale gueule garnie de crocs","desc":"Profil : Combat, Force F, PA -2. Règles spéciales : Coup Fatal. Note : arme naturelle du Squig Broyeur."},"venom-surge":{"name":"Injection de venin","desc":"Profil : Combat, Force F, PA -2. Règles spéciales : Blessures Multiples (D6), Attaques Empoisonnées, Frappe en Premier. Note : la figurine peut effectuer une de ses attaques par tour avec cette arme (Arachnarok)."},"troll-vomit":{"name":"Vomi de Troll","desc":"Profil : Combat, Force 3, PA -2. Note : un Troll ou une Mégère Trollesse au contact d'un ennemi peut effectuer une attaque supplémentaire par tour avec cette arme ; elle est effectuée en dernier (après toutes les autres, y compris les Attaques de Piétinement) mais touche automatiquement."},"swamp-breath":{"name":"Souffle marécageux","desc":"Profil : Tir, Portée N/A, Force 3, PA -2. Règles spéciales : Arme à Souffle. Note : toute unité subissant une blessure non sauvegardée doit faire un test de Panique comme si elle avait subi de lourdes pertes (Mégère Trollesse)."},"bonegrinder-giant-s-club":{"name":"Massue de Géant Broyeur d'Os","desc":"Profil : Combat, variable. La Force, la PA et les règles de la massue dépendent du résultat obtenu sur le Tableau d'Attaques de Géant Broyeur d'Os (ex. Puissant Revers — D6+1 touches à F+1, PA -2 ; Raclée — 1 attaque à F+3, PA -4, Blessures Multiples (2D3)). Voir la règle Attaques de Géant Broyeur d'Os."},"fanatic-ball-chain":{"name":"Boulet de Fanatique","desc":"Pas de table de profil. Toute unité (amie ou ennemie) traversée par un Fanatique en mouvement, ou qui traverse un Fanatique, subit D6 touches de Force 5, chacune avec une PA de -3. (Fanatique Gobelin de la Nuit.)"},"bolt-thrower":{"name":"Baliste","desc":"Baliste standard (Balistes Gobelines). Elle utilise le profil et les règles de Baliste du livre de règles de Warhammer: The Old World (tir de trait unique / volée) ; aucun profil propre à l'armée n'est imprimé dans le livre O&G."},"stone-thrower":{"name":"Lance-rocs","desc":"Catapulte standard (Lance-Rocs Gobelins). Elle utilise le profil de catapulte et les règles de Bombardement du livre de règles ; aucun profil propre à l'armée n'est imprimé dans le livre O&G."},"doom-diver-catapult":{"name":"Catapulte à Plongeurs de la Mort","desc":"Compte comme une catapulte (Bombardement). De plus, elle a la règle spéciale Plongeur de la Mort, qui permet d'ajuster le tir après dispersion et de tirer indirectement (voir la règle Plongeur de la Mort)."},"doom-diver":{"name":"Plongeur de la Mort","desc":"En tirant avec une catapulte à Plongeurs de la Mort (Bombardement), après l'étape de Déviation vous pouvez jeter un D3 et déplacer le gabarit de 3 ps d'autant de pouces dans n'importe quelle direction (le Plongeur guide son vol). En tir indirect, l'adresse des servants n'affecte pas la précision ; sur un « Hit! », utilisez la flèche pour la direction, puis déplacez le gabarit d'un nombre de pouces égal au dé d'Artillerie moins D3 (minimum 0)."},"it-run":{"name":"'Arrcèlement","desc":"S'ils gagnent un round de combat, Kiknik et toute Bande de Gobelins sur Loups qu'il a rejointe peuvent choisir de Se Replier en Bon Ordre au lieu d'effectuer un mouvement de suite ou de poursuite."},"lore-of-troll-magic":{"name":"Domaine de Magie Troll","desc":"Tradition fétide et primitive maniée par les Mégères Trollesses et quelques Chamanes Orques et Gobelins. Outre les Domaines de Magie du livre de règles, les Sorciers ayant une affinité avec les Trolls peuvent connaître des sorts du Domaine de la Magie Troll ; comme d'habitude, si un Sorcier peut connaître des sorts d'un Domaine parmi plusieurs, choisissez-en un en rédigeant votre liste. (Sort emblématique : Grocervô ; voir les sorts du domaine.)"},"spiked-ball-chains":{"name":"Chaînes & Boulets","desc":"Les Touches d'Impact causées par cette figurine ont une caractéristique de PA de -3. (Squig Broyeur.)"},"bog-wood-staff":{"name":"Bâton en Morta","desc":"Profil : Combat, Force F+2, PA -1. Règles spéciales : Attaques Magiques, Arme à Deux Mains. Note : chaque blessure non sauvegardée causée par cette arme permet à Ogdruz Swampdigga de récupérer un Point de Vie perdu. (Équipement nommé — à ne pas confondre avec l'objet « Bâton de Badoumm ».)"},"da-boss-s-trophy-rack":{"name":"Le Râtelier à Trophées du Chef","desc":"Lors d'un tour où il a chargé, Kiknik et toute Bande de Gobelins sur Loups qu'il a rejointe causent la Peur et reçoivent un bonus de +1 au résultat de combat. (Équipement nommé de Kiknik — à distinguer du « Râtelier à Trophées Macabres » générique.)"},"trollhide-shawl":{"name":"Châle en Peau de Troll","desc":"Ogdruz Swampdigga améliore sa valeur d'armure de 1 et gagne les règles spéciales Régénération (5+) et Inflammable."},"steam-cannonade":{"name":"Steam Cannonade","desc":"Une canonnade à vapeur (Démon de Fer) est une arme de Tir : Portée 18\", Force 5, PA -1, avec Arme Perforante (1), Canonnade et Encombrant. Notes : cette arme n'a pas de ligne de vue à 360° ; elle ne peut tirer que dans l'arc frontal du Démon de Fer. Canonnade : lancez deux dés d'Artillerie avant les jets pour Toucher ; le nombre de tirs égale leur total. Si un dé fait un Incident, tous les tirs subissent -1 pour Toucher ; si les deux dés font un Incident, aucun tir n'est effectué et la figurine perd un PV."},"demolition-rockets":{"name":"Fusées de Démolition","desc":"Profil : Tir, Portée 12-48 ps, Force 3 (6), PA - (-3). Règles spéciales : Arme Perforante (1), Bombardement, Encombrant, Mouvement ou Tir, Blessures Multiples (D6). Note : tire comme une catapulte avec un gabarit de 3 ps et le tableau d'Incidents de Tir des Armes à Poudre ; Blessures Multiples (D6) ne touche que la figurine sous le trou central. L'un des deux types de fusées du Lance-Fusées Hurlemort."},"infernal-incendiaries":{"name":"Fusées Incendiaires Infernales","desc":"Profil : Tir, Portée 12-48 ps, Force 3, PA -. Règles spéciales : Bombardement, Encombrant, Attaques Enflammées, Mouvement ou Tir. Note : tire comme une catapulte avec un gabarit de 5 ps et le tableau d'Incidents de Tir des Armes à Poudre ; toute unité subissant une blessure non sauvegardée doit faire un test de Panique comme si elle avait subi de lourdes pertes. L'un des deux types de fusées du Lance-Fusées Hurlemort."},"dreadquake-mortar":{"name":"Mortier Trembleffroi","desc":"Profil : Tir, Portée 12-72 ps, Force 3 (6), PA - (-3). Règles spéciales : Bombardement, Encombrant, Mouvement ou Tir, Blessures Multiples (D6), Secousses, Rechargement Lent. Note : tire comme une catapulte avec un gabarit de 5 ps et le tableau d'Incidents de Tir des Armes à Poudre. Secousses : jusqu'à votre prochain Début de Tour, toute unité à 2D6 ps du trou central subit -1 en Mouvement et ne peut pas utiliser Rapide. Rechargement Lent : si elle a tiré au tour précédent, lancez 1D6 avant de tirer ; sur 1-2 elle ne tire pas (un Pourvoyeur Ogre donne +1)."},"goring-horns":{"name":"Cornes Empaleuses","desc":"Profil : Combat, Force F+1, PA -3. Règles spéciales : Attaques Enflammées, Frappe en Premier. Note : la figurine peut effectuer une de ses attaques par tour avec cette arme (Sombre Taurus / Grand Taurus)."},"trampling-hooves":{"name":"Sabots Piétineurs","desc":"Profil : Combat, Force F, PA -1. Règles spéciales : Attaques Enflammées. Note : attaques naturelles du Sombre Taurus / Grand Taurus."},"sorcerer-s-curse":{"name":"Malédiction du Sorcier","desc":"Si cette figurine subit un Fiasco, elle doit immédiatement effectuer un test d'Endurance. En cas d'échec, au lieu de consulter le tableau des Fiascos, elle perd un Point de Vie et gagne un modificateur de +1 à son Endurance. En cas de réussite, elle consulte normalement le tableau des Fiascos."},"brass-bound-hooves":{"name":"Sabots sertis d'airain","desc":"Profil : Combat, Force F, PA -2. Aucune règle spéciale. Note : Écraseurs de Sang / Juggernauts de Khorne (avec peau d'airain, compte comme un caparaçon)."},"cannon-of-khorne":{"name":"Canon de Khorne","desc":"Machine de guerre à deux modes de tir. Tir solide : Portée 36 ps, Force 8, PA -2. Règles spéciales : Arme Perforante (2), Tir au Canon, Encombrant, Blessures Multiples (D3). Tir de mitraille : Portée N/A, Force 4, PA -1. Règles spéciales : Arme à Souffle. Note : tire comme un canon (Tir au Canon) ; sur un Incident de Tir au dé d'Artillerie, la figurine perd un Point de Vie au lieu de consulter un tableau. Montée sur le Canon à Crânes de Khorne."},"daemonic-talons":{"name":"Serres démoniaques","desc":"Profil : Combat, Force F, PA -1. Aucune règle spéciale. Note : Gargouilles du Chaos."},"ensorcelled-weapon":{"name":"Arme ensorcelée","desc":"Profil : Combat, Force F, PA -1. Aucune règle spéciale. Note : équipement du Prince Démon."},"harvester-cannon":{"name":"Canon moissonneur","desc":"Machine de guerre. Portée 12 ps, Force 4, PA -1. Règles spéciales : Encombrant, Plus de Clous. Note : tire comme un canon en tir de mitraille ; sur un Incident de Tir, la figurine perd un Point de Vie. Équipement du Broyeur d'Âmes."},"impaling-claws":{"name":"Pinces empaleuses","desc":"Profil : Combat, Force F, PA -2. Règles spéciales : Coup Fatal, Frappe en Premier. Note : équipement du Gardien des Secrets."},"iron-claw":{"name":"Griffe de fer","desc":"Profil : Combat, Force F, PA -3. Règles spéciales : Coup Fatal. Note : équipement du Broyeur d'Âmes."},"venomous-tail":{"name":"Queue venimeuse","desc":"Profil : Combat, Force F, PA -. Règles spéciales : Attaques Empoisonnées, Frappe en Premier. Note : Suave de Slaanesh ; doit effectuer une de ses attaques à chaque tour avec cette arme."},"warpflame":{"name":"Warpflame","desc":"Touches aléatoires réduites de D6 à D3+1."},"writhing-tentacles":{"name":"Tentacules frétillants","desc":"Profil : Combat, Force F. — Bête de Nurgle : PA -1, Arme Perforante (1). — Kharibdyss Elfe Noir (Légende) : PA -2, Attaques Empoisonnées."},"chaos-armour":{"name":"Armure du Chaos","desc":"Cette figurine a une sauvegarde Invulnérable de 4+ contre toute blessure subie. De plus, un Sorcier ayant cette règle spéciale peut porter une armure sans pénalité."},"daemons-of-khorne":{"name":"Démons de Khorne","desc":"Les Démons de Khorne ont la règle spéciale Haine (Démons de Slaanesh). De plus, lors d'un tour où il a effectué un mouvement de charge, un Démon de Khorne (mais pas sa monture) gagne un modificateur de +1 à sa Force."},"daemons-of-nurgle":{"name":"Démons de Nurgle","desc":"Les Démons de Nurgle ont la règle spéciale Haine (Démons de Tzeentch). De plus, toute figurine ennemie qui dirige ses attaques contre un Démon de Nurgle à la phase de Combat doit relancer tout jet pour Toucher d'un 6 naturel."},"daemons-of-slaanesh":{"name":"Démons de Slaanesh","desc":"Les Démons de Slaanesh ont la règle spéciale Haine (Démons de Khorne). De plus, ils augmentent leur portée de charge maximale de 1 ps et ont un modificateur de +1 au résultat de tout jet de Charge ou de Poursuite."},"daemons-of-tzeentch":{"name":"Démons de Tzeentch","desc":"Les Démons de Tzeentch ont la règle spéciale Haine (Démons de Nurgle). De plus, un Démon de Tzeentch qui est aussi un Sorcier peut appliquer un modificateur de +1 à tout jet de Lancement (modificateur du résultat — n'annule pas un double 1 naturel)."},"cavernous-maw":{"name":"Gueule caverneuse","desc":"Profil : Combat, Force F, PA -2. Règles spéciales : Arme Perforante (1), Coup Fatal. Note : arme naturelle du Kharibdyss ; la figurine doit effectuer une de ses attaques à chaque round avec cette arme."},"noxious-breath":{"name":"Souffle toxique","desc":"Profil : Tir, Portée N/A, Force 4, PA N/A. Règles spéciales : Arme à Souffle. Note : souffle du dragon Elfe Noir."},"petrifying-gaze":{"name":"Regard pétrificateur","desc":"Profil : Tir, Portée 18 ps, Force 2, PA N/A. Règles spéciales : Attaques Magiques, Blessures Multiples (D3). Note : arme de la Méduse ; le jet pour Blesser utilise l'Initiative de la cible au lieu de son Endurance. Aucune sauvegarde d'armure n'est autorisée."},"serrated-maw":{"name":"Gueule dentelée","desc":"Profil : Combat, Force F, PA -. Règles spéciales : Arme Perforante (2), Blessures Multiples (2). Note : arme naturelle du dragon Elfe Noir."},"hekarti-s-blessing":{"name":"Bénédiction d'Hekarti","desc":"Une fois par partie, une figurine avec cette règle spéciale peut relancer un seul jet de Lancement raté."},"hidden":{"name":"Caché","desc":"Un Assassin ayant cette règle (Maître Assassin du Clan Eshin ou Assassin Khainite) n’est pas déployé en début de partie ; il est « caché » dans une unité amie d’infanterie de Puissance d’Unité 10+ (Elfes Noirs : hors Harpies). Notez dans quelle unité il se trouve. Il peut être révélé pendant n’importe quelle sous-phase de Début de Tour ou au début de n’importe quelle phase de Combat, placé comme un personnage rejoignant l’unité. Si cette unité est détruite ou fuit avant la révélation, l’Assassin est retiré comme perte. Un Assassin ne peut pas être le général de l’armée."},"fiery-breath":{"name":"Souffle enflammé","desc":"Profil : Tir, Portée N/A, Force 4, PA -1. Règles spéciales : Arme à Souffle, Attaques Enflammées. Note : arme naturelle de la Salamandre."},"great-horns":{"name":"Grandes cornes","desc":"Profil : Combat, Force F, PA -3. Aucune règle spéciale. Note : arme naturelle du Stégadon."},"thunderous-bludgeon":{"name":"Balayage furieux","desc":"Profil : Combat, Force F, PA -3. Règles spéciales : Frappe en Dernier. Note : arme naturelle du Bastiladon."},"venomous-talons":{"name":"Serres venimeuses","desc":"Profil : Combat, Force F, PA -2. Règles spéciales : Attaques Empoisonnées. Note : arme naturelle du Troglodon."},"chill-breath":{"name":"Souffle glacial","desc":"Profil : Tir, Portée N/A, Force 2, PA -1. Règles spéciales : Arme à Souffle, Blessures Multiples (D3)."},"flaming-breath":{"name":"Souffle enflammé","desc":"Profil : Tir, Portée N/A, Force 4, PA -1. Règles spéciales : Arme à Souffle, Attaques Enflammées."},"great-tusks":{"name":"Grandes défenses","desc":"Profil : Combat, Force F, PA -1. Règles spéciales : Arme Perforante (2)."},"horns-of-stone":{"name":"Cornes de pierre","desc":"Profil : Combat, Force F, PA -2. Aucune règle spéciale."},"monstrous-tusks":{"name":"Défenses monstrueuses","desc":"Profil : Combat, Force F, PA -1. Règles spéciales : Arme Perforante (1)."},"wicked-claws":{"name":"Griffes cruelles","desc":"Profil : Combat, Force F, PA -2. Aucune règle spéciale."},"traps-snares":{"name":"Pièges & Collets","desc":"Les trappeurs Gnoblars déploient pièges et collets partout où ils vont. Toute figurine ennemie qui termine son mouvement de charge au contact socle à socle d'une figurine avec cette règle spéciale doit effectuer un test de Terrain Dangereux."},"plagueclaw-catapult":{"name":"Catapulte de la Peste","desc":"Profil : Tir, Portée 12-72 ps, Force 2 (4), PA -3. Règles spéciales : Bombardement, Encombrant, Mouvement ou Tir. Note : tire comme une catapulte (Bombardement) avec un gabarit d'explosion de 5 ps et le tableau des Incidents de Tir des Catapultes. Un 6 naturel pour Blesser blesse toujours, quelle que soit l'Endurance."},"warpstone-claws":{"name":"Griffes de Malepierre","desc":"Profil : Combat, Force F, PA -1. Règles spéciales : Arme Perforante (1), Attaques Magiques. Note : attaques naturelles de l'Abomination de Malefosse."},"crane-gun":{"name":"Crane Gun","desc":"Un canon grue est une arme de Tir (Portée 36\", Force 6, PA -2) dotée des règles Arme Perforante (2), Encombrant et Mouvement ou Tir."},"iron-hail-gun":{"name":"Iron Hail Gun","desc":"Un canon grêle de fer est une arme de Tir (Portée 12\", Force 3, PA -1) dotée des règles Mouvement & Tir et Tirs Multiples (D3). Notes : une figurine armée d'un canon grêle de fer ne subit aucun malus pour Toucher en tir à longue portée, en utilisant Tirs Multiples (D3), ou lors d'une réaction de charge Maintenir la Position & Tirer."},"fire-rain-rocket":{"name":"Fusées Pluie de Feu","desc":"La Batterie de Fusées Pluie de Feu tire 1 des 2 types de fusées à chaque tour. — Fusées Bastion : Portée 12-48 ps, Force 4 (5), PA -1 (-3). Règles spéciales : Arme Perforante (1), Bombardement, Encombrant, Mouvement ou Tir, Blessures Multiples (D6). Tire comme une catapulte (Bombardement) avec un gabarit d'explosion de 3 ps et le tableau d'Incidents de Tir des Armes à Poudre ; Blessures Multiples (D6) ne s'applique qu'à la seule figurine dont le socle est sous le trou central. — Batterie de Fusées : Portée 12-48 ps, Force 3 (4), PA -1. Règles spéciales : Arme Perforante (1), Bombardement, Encombrant, Attaques Enflammées, Mouvement ou Tir, Esprits Hurleurs. Tire avec un gabarit d'explosion de 5 ps. Esprits Hurleurs : toute unité qui subit une ou plusieurs blessures non sauvegardées de cette arme doit effectuer un test de Panique comme si elle avait subi de lourdes pertes."},"grand-cannon":{"name":"Grand Canon Cathayen","desc":"Profil : Tir, Portée 48 ps, Force 10, PA -3. Règles spéciales : Arme Perforante (3), Tir au Canon, Encombrant, Mouvement ou Tir, Blessures Multiples (D3+1), Impact Tonitruant. Note : n'utilise pas la Capacité de Tir des servants ; tire via Tir au Canon et le tableau des Incidents de Tir des Machines à Poudre. Impact Tonitruant : jusqu'à votre prochaine sous-phase de Début du Tour, toute unité qui était à 2D6 ps du point d'impact subit -1 en Mouvement et ne peut pas utiliser Rapide (effet non cumulable)."},"great-blade":{"name":"Grande Lame","desc":"La Grande Lame de la Sentinelle Cathayenne a DEUX profils ; choisissez-en un au début de chaque round de combat. — Coup de Fauche : Combat, Force F, PA -2. Règles spéciales : Arme Perforante (1), Attaques Supplémentaires (+2D3), Frappe en Dernier. — Frappe Mortelle : Combat, Force F+1, PA -4. Règles spéciales : Coup Fatal, Tueur de Monstres, Blessures Multiples (D3)."},"dragon-fire":{"name":"Feu de Dragon","desc":"Profil : Tir (souffle), Force 4, PA -1. Règles spéciales : Arme à Souffle, Attaques Enflammées. Note : souffle de Miao Ying, utilisable sous forme de Dragon uniquement."},"talons-of-the-storm":{"name":"Serres de la Tempête","desc":"Profil : Combat, Force F, PA -2. Règles spéciales : Arme Perforante (1), Attaques Magiques, Frappe en Premier. Note : arme de Miao Ying, portée sous forme Humaine et sous forme de Dragon."},"crown-of-horns":{"name":"Couronne de cornes","desc":"Profil : Combat, Force F, PA -1. Règles spéciales : Arme Perforante (1). Note : attaque de cornes du Grand Esprit Longma."},"iron-talons":{"name":"Serres de fer","desc":"Profil : Combat, Force F, PA -1. Règles spéciales : Frappe en Premier. Note : équipement du Seigneur Shugengan / Général Shugengan."},"harmony-of-stone-steel":{"name":"Harmonie de la Pierre & de l'Acier","desc":"Une unité rejointe par un personnage ayant cette règle spéciale peut relancer tout test de Commandement raté quand elle tente de se reformer après avoir piétiné l'ennemi, quand elle tente de rediriger une charge, ou quand elle effectue un test de Retenue."},"fire-flee":{"name":"Tir & Fuite","desc":"Si la majorité des figurines d'une unité armée de projectiles ont cette règle, l'unité peut déclarer Tirer & Fuir comme réaction de charge : Tenir la Position & Tirer, puis fuir. En fuyant, lancez deux D6 et écartez le résultat le plus bas. Si la distance jusqu'à l'unité qui charge est inférieure au Mouvement de celle-ci, l'unité doit Tenir la Position ou Fuir à la place."},"warp-lightning-cannon":{"name":"Warp Lightning Cannon","desc":"Le Canon à Malefoudre tire en utilisant la règle spéciale « Éclair de Malefoudre ». Toute figurine (amie ou ennemie) dont le socle se trouve sous la ligne de 8D6\" subit une touche d'une Force égale au résultat d'un dé d'Artillerie (PA -2). Si un Incident de Tir est obtenu en déterminant la Force de cette arme, faites immédiatement un jet sur le Tableau d'Incidents de Tir du Canon à Malefoudre ci-dessous."},"cathayan-lance":{"name":"Cathayan Lance","desc":"Une lance cathayenne est une arme de Combat (Force +1, PA -1) dotée des règles Arme Perforante (1) et Combat sur Plusieurs Rangs. Notes : cette arme ne peut être utilisée que par des figurines dont le type de troupe est « cavalerie », « monstre » ou « char ». Les modificateurs de Force et de Pénétration d'Armure de la lance cathayenne ne s'appliquent qu'au tour où le porteur a chargé l'ennemi."},"celestial-blade":{"name":"Celestial Blade","desc":"Une Lame Céleste est une arme de Combat (Force +1, PA -1) dotée de la règle Frappe en Premier."},"dragonfire-pistol":{"name":"Pistolet feu du dragon","desc":"Profil : Tir, Portée 12 ps, Force 5, PA -1. Règles spéciales : Attaques Enflammées, Tirs Multiples (2), Tir Rapide."},"gunpowder-bomb":{"name":"Bombe de poudre à canon","desc":"Profil : Tir, Portée 9 ps, Force 3, PA -. Règles spéciales : Arme Perforante (1), Mouvement & Tir, Tir Rapide. Note : si le jet pour Toucher réussit, cause D3 touches au lieu d'une."},"dragonfire-bomb":{"name":"Bombe de feu du dragon","desc":"Profil : Tir, Portée 9 ps, Force 4, PA -1. Règles spéciales : Arme Perforante (1), Attaques Enflammées, Mouvement & Tir, Tir Rapide. Note : si le jet pour Toucher réussit, cause D3+1 touches au lieu d'une."},"fireglaive":{"name":"Fireglaive","desc":"Un glaive ardent est une arquebuse à répétition compacte munie d'une lame, avec deux profils. Tir : Portée 18\", Force 4, PA -1, Arme Perforante (1). Combat : Force +1, PA -1, Arme Perforante (1), Nécessite Deux Mains. Notes : un glaive ardent possède deux profils, traduisant sa double fonction d'arme de tir et de combat."},"hailshot-blunderbuss":{"name":"Hailshot Blunderbuss","desc":"Un tromblon grêle-de-tir est une arme de Tir (Portée 12\", Force 3, PA -1) dotée des règles Tirs Multiples (D3) et Tir en Salve. Notes : une figurine ainsi armée ne subit aucun malus pour tirer à longue portée, pour utiliser Tirs Multiples (D3), ou lors d'une réaction Maintenir la Position & Tirer. De plus, si 20 figurines ou plus d'une même unité tirent sur la même cible avec des tromblons grêle-de-tir, elles peuvent relancer les 1 naturels pour Blesser."},"naptha-bombs":{"name":"Naptha Bombs","desc":"Les bombes au naptha sont une arme de Tir (Portée 6\", Force 3, PA -) dotées des règles Attaques Enflammées, Pesant et Tir Rapide. Notes : si le jet pour Toucher est réussi, une bombe au naptha cause D3+1 touches à l'unité ennemie ciblée au lieu d'une seule."},"dread-halberd":{"name":"Hallebarde d'effroi","desc":"Profil : Combat, Force +1, PA -1. Règles spéciales : Arme Perforante (1), Combat sur Plusieurs Rangs, Arme à Deux Mains. Note : une figurine armée d'une Hallebarde d'effroi ne peut pas effectuer d'attaque de soutien au tour où elle a chargé."},"har-ganeth-greatsword":{"name":"Grande épée d'Har Ganeth","desc":"Profil : Combat, Force +2, PA -1. Règles spéciales : Coup de Fendoir, Arme à Deux Mains."},"lash-and-buckler":{"name":"Lanières & bocle","desc":"Profil : Combat, Force du porteur, PA -1. Règles spéciales : Arme Perforante (1), Combat sur Plusieurs Rangs, Arme à Deux Mains. Note : une figurine équipée de lanières & bocle améliore sa valeur d'armure de 1."},"ravager-harpoon":{"name":"Harpon ravageur","desc":"Profil : Tir, Portée 24 ps, Force 6, PA -3. Règles spéciales : Encombrant, Blessures Multiples (D3), Incommode. Note : à la phase de Tir, un membre de l'équipage Aurige Belluaire peut tirer avec cette arme au lieu de son arbalète à répétition."},"giant-bow":{"name":"Arc géant","desc":"Profil : Tir, Portée 36 ps, Force 5, PA -2. Règles spéciales : Blessures Multiples (D3), Attaques Empoisonnées."},"blowpipe":{"name":"Sarbacane","desc":"Profil : Tir, Portée 12 ps, Force 3, PA -. Règles spéciales : Tirs Multiples (2), Attaques Empoisonnées."},"razor-barbs":{"name":"Épines acérées","desc":"Profil : Tir, Portée 18 ps, Force 4, PA -1. Règles spéciales : Mouvement & Tir, Tirs Multiples (D3), Tir Rapide."},"giant-blowpipes":{"name":"Sarbacanes géantes","desc":"Profil : Tir, Portée 18 ps, Force 3, PA -. Règles spéciales : Encombrant, Tirs Multiples (2D6), Attaques Empoisonnées."},"grimfrost-weapon":{"name":"Arme de Sinistregivre","desc":"Profil : Combat, Force du porteur, PA -1. Règles spéciales : Arme Perforante (1), Attaques Magiques."},"great-throwing-spear":{"name":"Javelots géants","desc":"Profil : Tir, Portée 12 ps, Force +1, PA -1. Règles spéciales : Mouvement & Tir, Tir Rapide."},"chaintrap":{"name":"Croque-monsieur","desc":"Profil : Tir, Portée 12 ps, Force +1, PA -. Règle spéciale : Coup Fatal."},"harpoon-launcher":{"name":"Lance-harpon","desc":"Profil : Tir, Portée 36 ps, Force 6, PA -2. Règles spéciales : Blessures Multiples (D3), Incommode. Note : une énorme arbalète qui tire de longs et lourds carreaux barbelés."},"giant-s-club":{"name":"Massue de Géant","desc":"Profil : Combat — variable. Les caractéristiques et règles spéciales de la massue varient selon ce que le Géant en fait, comme décrit dans la règle spéciale Attaques de Géant."},"ironfist":{"name":"Ironfist","desc":"Un Poing d’Acier est une arme de base additionnelle (Combat : Force F, PA -, Attaques Supplémentaires (1), Arme à Deux Mains). De plus, une figurine équipée d’un Poing d’Acier améliore sa valeur d’armure de 1. Notes : un Poing d’Acier ne peut être utilisé avec une arme magique pour gagner l’attaque supplémentaire ni le bonus de valeur d’armure."},"plague-censer":{"name":"Encensoir à Peste","desc":"Profil : Combat, Force +2, PA -1. Règles spéciales : Attaques Empoisonnées, Arme à Deux Mains. Note : le modificateur de Force ne s'applique qu'au premier round de chaque combat ; en combat, une figurine équipée d'un encensoir à peste peut relancer ses jets pour Blesser obtenant un 1 naturel."},"warplock-jezzail":{"name":"Jezzail","desc":"Profil : Tir, Portée 36 ps, Force 6, PA -3. Règles spéciales : Attaques Magiques, Encombrant, Mouvement ou Tir. Note : si le porteur fait un 1 naturel pour Toucher au tir, jetez un nouveau D6 ; sur un 1, l'Équipe de Jezzail est retirée comme perte."},"poisoned-wind-globes":{"name":"Globes de vent empoisonné","desc":"Profil : Tir, Portée 9 ps, Force 2, PA -. Règles spéciales : Mouvement & Tir, Vent Empoisonné, Tir Rapide. Note : si le jet pour Toucher réussit, cause D3 touches au lieu d'une ; sur un 1 naturel pour Toucher, jetez un D6 — sur un 1, l'unité qui tire subit D3 touches."},"warpfire-thrower":{"name":"Lance-Feu","desc":"Profil : Tir, Portée 6 ps, Force 4, PA -1. Règles spéciales : Attaques Enflammées, Colonne de Feu, Encombrant. Note : tire comme un lance-flamme (règle « Colonne de Feu » + tableau des Incidents de Tir des Machines à Poudre) ; toute unité subissant au moins une blessure non sauvegardée doit faire un test de Panique comme si elle avait subi de lourdes pertes."},"billowing-death":{"name":"Mort tourbillonnante","desc":"Profil : Arme à Souffle, Force 2. Règles spéciales : Arme à Souffle, Attaques Magiques. Note : un 6 naturel pour Blesser réussit toujours quelle que soit l'Endurance ; aucune sauvegarde d'armure n'est autorisée contre les blessures de cette arme (Invulnérable et Régénération possibles)."},"dragon-fire-pistol":{"name":"Dragon Fire Pistol","desc":"Un pistolet feu du dragon est une arme de Tir (Portée 12\", Force 5, PA -1) dotée des règles Attaques Enflammées, Tirs Multiples (2) et Tir Rapide."},"blessing-of-hekarti":{"name":"Blessing of Hekarti","desc":"Les sorcières Elfes Noirs font des dévotions à Hekarti, la Reine Hydre et déesse elfique des conjurations. Une fois par partie, une figurine dotée de cette règle spéciale peut relancer un seul jet de Lancement raté."},"blood-of-hashut":{"name":"Blood Of Hashut","desc":"Usage unique. Au lieu d'attaquer normalement, une figurine dotée d'une fiole de Sang de Hashut peut en consommer une pour effectuer une attaque unique : un seul jet pour Toucher ; en cas de réussite, l'ennemi subit D6 touches. Pour Blesser, le seuil est égal à la valeur d'armure de la/des figurine(s) touchée(s). Aucune sauvegarde d'armure n'est permise (Invulnérable et Régénération autorisées). Ces touches ont les règles Attaques Enflammées et Attaques Magiques."},"darkforged-weapon":{"name":"Darkforged Weapon","desc":"Une arme de Sombreforge est une arme de base utilisable avec la règle Armes Ensorcelées. Après le déploiement mais avant le premier tour, lancez sur la table des Armes de Sombreforge pour déterminer un attribut (ex. Lame Infernale, Malin, Fléau de Vie, Sangsue de Sorts, Forgé aux Enfers, Tissé de Sorts) que l'arme conserve pour la bataille."},"dreadquake":{"name":"Dreadquake","desc":"Un mortier trembleffroi est une arme de Tir : Portée 12-72\", Force 3 (6), PA - (-3), avec Bombardement, Encombrant, Mouvement ou Tir, Blessures Multiples (D6), Séisme et Rechargement Lent. Notes : tire comme une catapulte avec un gabarit de 5\". Blessures Multiples (D6) ne s'applique qu'à une figurine sous le trou central. Séisme : jusqu'à votre prochain Début de Tour, toute unité à 2D6\" du trou central subit -1 en Mouvement et ne peut pas utiliser Rapide. Rechargement Lent : si elle a tiré au tour précédent, lancez un D6 avant de tirer ; sur 1-2 elle ne tire pas (un Servant Ogre donne +1 à ce jet)."},"leadbelcher-guns":{"name":"Leadbelcher Gun","desc":"Un canon crache-plomb est une arme à poudre noire à deux profils. Balle : Portée 24\", Force 5, PA -2, avec Arme Perforante (1), Encombrant et Blessures Multiples (2). Grenaille : Portée 18\", Force 3, PA -, avec Arme Perforante (1). Notes : deux profils, représentant ses deux modes de tir. Si le jet pour Toucher est réussi en grenaille, le canon inflige D3 touches à l’unité ennemie ciblée au lieu d’une seule."},"cannon-of-the-sky-titans":{"name":"Cannon Of The Sky-Titans","desc":"Le Canon des Titans Célestes (Boute-fer) a deux profils. Boulet : Portée 36\", Force 10, PA -3, avec Arme Perforante (2), Tir au Canon, Encombrant et Blessures Multiples (D3+1). Grenaille : Force 4, PA -1, Arme à Souffle. Notes : en tir de boulet, tire comme un canon (Tir au Canon) et utilise la table d’Incident du Boute-fer — 1 : Kaboom ! (figurine détruite) ; 2-3 : Krrack ! (ne peut plus tirer de la partie) ; 4-6 : Ack ! (ne tire pas ce tour ni au tour suivant)."},"scraplauncher-catapult":{"name":"Scraplauncher Catapult","desc":"La catapulte lance-ferraille est une arme de Tir : Portée 12-48\", Force 3 (4), PA - (-2), avec Bombardement, Encombrant et Blessures Multiples (2). Notes : tire comme une catapulte (Bombardement), gabarit de 5\", table d’Incident du Lance-ferraille ; les valeurs entre parenthèses (F4, PA -2) et Blessures Multiples (2) ne s’appliquent qu’à la figurine sous le trou central. Table — 1 : Kerr-unch ! (figurine détruite) ; 2-3 : Snap ! (ne peut plus tirer de la partie) ; 4-6 : Splang ! (ne tire pas ce tour ni au tour suivant)."},"distensible-jaw":{"name":"Distensible Jaw","desc":"La mâchoire extensible est une arme de Combat (Force F, PA -) dotée de la règle Coup Fatal. Notes : en combat, cette figurine doit effectuer une de ses attaques chaque tour avec cette arme."},"brace-of-ogre-pistols":{"name":"Brace Of Ogre Pistols","desc":"Une paire de pistolets Ogres a deux profils. Tir : Portée 24\", Force 4, PA -1, avec Arme Perforante (1), Tirs Multiples (2) et Tir Rapide. Combat : Force F, PA -, avec Attaques Supplémentaires (1) et Arme à Deux Mains. Notes : les deux profils représentent l’usage à distance et au corps-à-corps."},"longspear":{"name":"Longspear","desc":"Une longue lance est une arme de Combat. Une figurine maniant une longue lance peut Combattre sur un Rang Supplémentaire et possède la règle Frappe en Premier. Notes : cette arme ne peut être utilisée que par des figurines dont le Type de Troupe est « infanterie ». Une figurine maniant une longue lance ne peut pas effectuer d'attaque de soutien lors d'un tour où elle a chargé, et la règle Frappe en Premier d'une longue lance ne s'applique que contre les unités ennemies qui chargent."},"gunpowder-bombs":{"name":"Gunpowder Bombs","desc":"Les bombes de poudre à canon sont une arme de Tir (Portée 6\", Force 3, PA -1) dotées des règles Arme Perforante (1), Mouvement & Tir et Tir Rapide. Notes : si le jet pour Toucher est réussi, les bombes de poudre causent D3 touches à l'unité ennemie ciblée au lieu d'une seule."},"celestial-armour":{"name":"Celestial Armour","desc":"La figurine dotée de cette règle spéciale bénéficie d'une sauvegarde Invulnérable contre toute blessure subie ; la valeur de cette Invulnérable est indiquée entre parenthèses après le nom de la règle (X+). De plus, un Sorcier doté de cette règle peut porter une armure sans pénalité."},"elemental-winds":{"name":"The Elemental Winds","desc":"À chacune de ses sous-phases de Début de Tour, le joueur du Grand Cathay jette un D6 pour déterminer quels Vents Élémentaires soufflent le plus fort. 1-2 : les Vents tombent, rien ne se produit. 3-4 (Vents du Yang) : jusqu'à votre prochaine phase de Début de Tour, les Sorciers ayant le Domaine du Yang augmentent leur portée de Dissipation et celle de tout sort d'Enchantement qu'ils connaissent de 3\", et les figurines amies ayant Volonté des Dragons gagnent +1 Mouvement ou +1 Initiative. 5-6 (Vents du Yin) : les Sorciers ayant le Domaine du Yin augmentent de 3\" la portée de tout sort de Maléfice ou de Projectile Magique qu'ils connaissent, et les figurines Volonté des Dragons gagnent +1 Capacité de Combat ou +1 Commandement."},"celestial-forged-armour-x":{"name":"Armure Forgée Céleste","desc":"Créée dans les armureries de Wei-jin, l'Armure Forgée Céleste est faite du minerai météorique de Kunlan. Une figurine ayant cette règle bénéficie d'une sauvegarde invulnérable contre toute blessure subie, dont la valeur est indiquée entre parenthèses après le nom de la règle. De plus, un Sorcier ayant cette règle peut porter une armure sans malus."},"harmony-of-stone-and-steel":{"name":"Harmonie de Pierre et d'Acier","desc":"Quand deux unités complémentaires de Cathay sont adjacentes, elles gagnent +1 en Sauvegarde d'Armure ou +1 en Commandement."},"will-of-the-dragons":{"name":"Volonté des Dragons","desc":"Une unité ayant cette règle peut relancer un test de Panique raté quand une unité amie est détruite à moins de 6 ps d'elle, ou quand une unité amie fuit à travers elle."},"detachment-special-rules":{"name":"Règles de Détachement","desc":"Les détachements de l'Empire bénéficient de contre-charges gratuites et peuvent effectuer des manœuvres de flanc offensives."},"elementalism":{"name":"Élémentalisme","desc":"Domaine de magie universelle axé sur les forces naturelles. Sorts qui manipulent feu, eau, terre, air et foudre."},"illusion":{"name":"Lore of Illusion","desc":"Domaine de magie commun à de nombreuses armées. Sorts qui trompent l'esprit, créent des mirages et aveuglent les ennemis."},"blackshard-armour":{"name":"Armure d'Éclat Noir","desc":"Rayonnant éternellement de la flamme de sa forge, l'armure d'Éclat Noir protège son porteur du feu et de la chaleur. Une figurine ayant cette règle bénéficie d'une sauvegarde invulnérable de 5+ contre toute blessure causée par une attaque ayant les Attaques Enflammées. De plus, un Sorcier ayant cette règle peut porter une armure sans malus."},"daemonic-psychology":{"name":"Daemonic Psychology","desc":"Les figurines Démoniaques réussissent automatiquement tout test de Peur ou de Terreur. Lorsqu'une unité devrait normalement faire un test de Panique, un test de Moral, ou choisit de Fuir en réaction de charge, elle effectue à la place un test d'Instabilité Démoniaque. Si une unité Démoniaque Fuit pour quelque raison que ce soit, elle Cède toujours du Terrain en Bon Ordre à la place. Khorne : Panique auto-réussie, pas de Fuite. Nurgle : doit tester la Panique, pas de Fuite. Slaanesh : Panique auto-réussie, peut Fuir. Tzeentch : peut choisir de rater la Panique sans tester l'instabilité, peut Fuir."},"arcane-shield":{"name":"Bouclier Arcanique","desc":"Ce personnage a une sauvegarde invulnérable de 5+ contre toute blessure subie."},"wisdom-of-the-old-ones":{"name":"Wisdom of the Old Ones","desc":"Une fois par tour, relance un D6 de lancement (pas un fiasco) ; connaît un sort de plus que son Niveau."},"palanquin":{"name":"Palanquin","desc":"Peut rejoindre une unité avec Gardiens malgré le Vol (placé au 2e rang) ; tant qu'il n'est pas au contact d'un ennemi, ne compte pas dans un rang combattant et lance/dissipe normalement (pas de sorts d'Assaut) ; vision 360° et ignore les figurines de l'unité pour la LdV."},"aquatic":{"name":"Aquatique","desc":"L'unité peut se déplacer normalement à travers les terrains aquatiques sans malus. Traite l'eau comme un terrain découvert."},"obsidian-blades":{"name":"Lames d'Obsidienne","desc":"Armes des Elfes Noirs taillées en obsidienne volcanique. Confèrent Perforant (2) ou un effet similaire de pénétration d'armure."},"predatory-fighter":{"name":"Predatory Fighter","desc":"Sur un 6 naturel pour toucher au corps à corps, la figurine (pas sa monture) génère 1 Attaque supplémentaire (résolue normalement ; ne peut pas en générer d'autres)."},"skink-riders":{"name":"Skink Riders","desc":"Les attaques contre cette unité sont résolues contre la CC la plus élevée entre le cavalier, l'équipage ou le monstre."},"arcane-vassal":{"name":"Vassal Arcanique","desc":"L'unité peut utiliser un personnage-magicien allié dans son unité pour lancer ou soutenir des sorts. Partage les niveaux de magie."},"ogre-kingdoms-charge":{"name":"Ogre Kingdoms Charge","desc":"Les Touches d'Impact d'une figurine d'Infanterie ayant cette règle améliorent leur Force et leur AP du bonus de rang actuel de l'unité. De plus, après un jet de Charge/Poursuite de 6 ps+ incluant un 6 naturel, l'unité gagne Touches d'Impact (1) et traite les obstacles linéaires bas comme du terrain dégagé ce tour-ci."},"ogre-club":{"name":"Ogre Club","desc":"Une arme de base non magique portée par la figurine a un AP de -1. Ne s'applique pas à la monture, ni si un Poing-de-Fer des Royaumes Ogres (ou une autre arme) est utilisé à la place."},"ogre-kingdoms-ironfist":{"name":"Ogre Kingdoms Ironfist","desc":"Renommé ; désormais un bouclier à deux profils de combat (au choix chaque round) : Frappe (F, AP -1, Nécessite Deux Mains) ou Fracasse (F, Attaques Supplémentaires +1, Nécessite Deux Mains). En corps à corps, s'il sert d'arme, +1 à la valeur d'armure (max 3+) ; conserve les bénéfices du bouclier."},"armoured-hide-2":{"name":"Armoured Hide (2)","desc":"L'unité Gorger bénéficie d'une sauvegarde d'armure naturelle 2+."},"regeneration-6":{"name":"Regeneration (6+)","desc":"Les blessures subies peuvent être guéries sur un 6+."},"verminous-valour":{"name":"Valeur des Nuisibles","desc":"Sauf s'il est engagé dans un duel, un personnage ayant cette règle qui a rejoint une unité de Puissance d'Unité 10 ou plus peut volontairement se 'retirer' à l'arrière de l'unité à tout moment. Dans ce cas, il n'est plus dans le rang combattant : il ne peut ni porter d'attaques ni en subir. L'unité peut toutefois continuer à utiliser son Commandement."},"weapon-teams":{"name":"Weapon Teams","desc":"Les Équipes d'Armes gagnent la règle Détachement et peuvent ignorer le nombre minimal de figurines requises pour former un Détachement. Elles ne peuvent former que le nombre de Détachements d'Équipe d'Armes noté dans la description de leur unité-mère. Les règles précédemment supprimées (Déploiement des Équipes d'Armes & Commandement des Équipes d'Armes) ne s'appliquent plus."},"pushed-into-battle":{"name":"Pushed Into Battle","desc":"Un Char Lourd ayant cette règle peut rejoindre une unité d'Infanterie de PU 10+ malgré son statut de Char Lourd. S'il le fait, il doit toujours être placé au centre du premier rang et perd la règle Pesant. Une seule figurine ayant cette règle peut rejoindre chaque unité. Remplace la règle Traîné dans la Bataille sur la Cloche et l'Autel."},"expendable":{"name":"Expendable","desc":"Si toutes les figurines skavens amies engagées dans un combat ont cette règle, les unités skavens amies peuvent cibler les unités ennemies engagées dans ce combat lors de la phase de Tir. Résolvez tous les jets pour toucher normalement. Puis, en utilisant tous les jets pour toucher ratés, faites les jets pour blesser sur une unité ayant la règle Sacrifiable engagée dans le combat, choisie par votre adversaire. Avec un gabarit d'explosion : centrez le gabarit sur un rang de combat de façon à toucher amis et ennemis aussi équitablement et nombreusement que possible. Avec un Projectile Magique ciblant une unité ennemie engagée avec une unité amie ayant cette règle : les jets de lancement ratés (mais pas les sorts dissipés ni les fiascos) comptent comme lancés avec succès sur une unité amie Sacrifiable engagée dans le combat, choisie par votre adversaire."},"will-of-the-gods":{"name":"Will of the Gods","desc":"Un Char Lourd ayant cette règle peut rejoindre une unité d'Infanterie de PU 10+, placé au centre du premier rang, et perd la Destruction Lourde. Un seul par unité."},"hatred-all-enemies":{"name":"Hatred (All Enemies)","desc":"Relance les jets pour toucher ratés au corps à corps contre tous les ennemis."},"wailing-dirge":{"name":"Lamentation Funèbre","desc":"Lors de la phase de Tir de son tour (sauf si elle a marché), cette figurine peut effectuer une Lamentation Funèbre contre une unité ennemie à moins de 8 ps dans sa ligne de vue. La cible effectue un test de Commandement avec un modificateur de -2. En cas d'échec, elle subit autant de blessures que la marge d'échec, sans sauvegarde d'armure ni de Régénération (la sauvegarde invulnérable reste permise)."},"mortis-engine":{"name":"Mortis Engine","desc":"Reliquaire Maudit et Tome Blasphématoire ne sont pas cumulatifs avec d'autres Moteurs de Mort."},"dark-acolyte":{"name":"Dark Acolyte","desc":"S'il n'est pas déjà un Sorcier, compte comme un Sorcier Niveau 1 pour cette règle."},"dark-vitality":{"name":"Vitalité des Ténèbres","desc":"Les Vampires et les Nécromanciens sont des êtres puissants capables d'exister sans la volonté animatrice d'un autre. Les figurines ayant cette règle ne sont pas soumises à la règle de la Mort du Général. De plus, à moins d'avoir rejoint une unité ne l'ayant pas, elles (et leurs montures) peuvent marcher normalement."},"subterranean-ambush":{"name":"Subterranean Ambush","desc":"Si l'armée inclut une unité de Miners, après déploiement et avant le 1er tour, placer deux marqueurs de Mine (32mm) +1 par unité de Miners supplémentaire, hors zone adverse, à >12\" d'un autre marqueur ami, >6\" d'un ennemi, >3\" d'un élément spécial/objectif. Une unité de Miners arrivant en réserve peut être placée à <6\" d'un marqueur (pas à <6\" d'un ennemi) ; ne peut charger ce tour, compte comme ayant bougé."},"ancient-enemies":{"name":"Ancient Enemies","desc":"Toutes les unités d'une armée Host of Talsyn gagnent Hatred (Beastmen Brayherds)."},"the-awakened-wood":{"name":"The Awakened Wood","desc":"Dans une armée Host of Talsyn, n'importe quel nombre d'unités de Dryads et Tree Kin peut avoir Ambushers pour +1 pt/figurine ; les Treemen et Treeman Ancient pour +10 pts."},"chieftains-of-the-hunter-king":{"name":"Chieftains of the Hunter-King","desc":"Les Wood Elf Nobles d'une armée Orion's Wild Hunt peuvent avoir Talismanic Tattoos pour 10 pts/figurine."},"courage-beyond-compare":{"name":"Courage Beyond Compare","desc":"Si ce personnage rejoint une unité de Guardians of Talsyn, l'unité gagne Immune to Psychology. S'il la quitte, l'unité la perd."},"daughters-of-eternity":{"name":"Daughters of Eternity","desc":"Les modèles avec cette règle (Sisters of the Thorn) ont une sauvegarde Ward 4+ contre toute blessure."},"deepwood-coven":{"name":"Deepwood Coven","desc":"Une unité de Sisters of the Thorn connaît un sort aléatoire (Battle Magic ou Elementalism), ou le sort signature au choix. Lançable en Bound spell : Power Level 1 avec une Handmaiden of the Thorn ; PL 2 avec Handmaiden + porte-étendard ; sinon PL 0."},"guardians-of-the-wildwood":{"name":"Guardians of the Wildwood","desc":"Au contact socle d'un ennemi causant la Peur ou la Terreur, un modèle avec cette règle gagne +1 en Attaques (max 10) et Multiple Wounds (2)."},"hawk-eyed-archer":{"name":"Hawk-eyed Archer","desc":"Un modèle avec cette règle peut cibler tout personnage ennemi en ligne de vue (ignorant les règles des personnages isolés). De plus, il peut viser une figurine précise dans l'unité cible (champion ou personnage)."},"in-tune-with-nature":{"name":"In Tune With Nature","desc":"En plus de leurs Lores habituels, les Mages, Treeman Ancients et Branchwraiths d'une armée Host of Talsyn peuvent connaître des sorts du Lore of the Wilds."},"parry-wood-elves":{"name":"Parry (Wood Elves)","desc":"En combattant avec arme de main + bouclier, ou Asrai spear + bouclier, cette unité améliore sa valeur d'armure de 1."},"protectors-of-the-ancient-wood":{"name":"Protectors of the Ancient Wood","desc":"Tant qu'elle contrôle un élément spécial (special feature), une unité d'une armée Host of Talsyn peut relancer les jets pour Toucher et pour Blesser de 1 naturel en phase de Combat."},"spectral-hounds":{"name":"Spectral Hounds","desc":"Les Hounds of Orion ne peuvent être blessés que par des Magical Attacks. De plus, tant qu'un Hound subsiste, Orion ne peut être ciblé par le tir ennemi."},"the-spirit-of-kurnous":{"name":"The Spirit of Kurnous","desc":"0-1 unité de Glade Riders, Warhawk Riders ou Wood Elf Beast Packs par 1000 pts peut avoir Furious Charge et Impetuous pour +10 pts/unité. Ne s'applique pas à la monture."},"talismanic-tattoos":{"name":"Talismanic Tattoos","desc":"Donne au porteur une sauvegarde Ward 6+ contre toute blessure."},"tree-whack":{"name":"Tree Whack","desc":"1×/tour en phase de Combat, un modèle avec cette règle peut utiliser une de ses Attaques pour une attaque 'Tree Whack' : désigner une figurine ennemie engagée qui fait un test d'Initiative. Raté = D3 touches de la Force du modèle, sans armure (Ward/Régén OK) ; réussi = esquivé."},"troubadour-of-loec":{"name":"Troubadour of Loec","desc":"Un Shadowdancer qui rejoint une unité de Wardancers est considéré avoir la règle Dances of Loec tant qu'il reste avec l'unité."},"woodland-ambush":{"name":"Woodland Ambush","desc":"Après le placement du décor, le joueur Wood Elf peut placer un bois supplémentaire (3\" à 9\" de large) n'importe où hors de la zone de déploiement adverse et à plus de 12\" du centre du champ de bataille."},"worthy-of-kurnous":{"name":"Worthy of Kurnous","desc":"Après déploiement, avant le 1er tour : désigner un personnage ou un monstre ennemi. Tous les modèles d'une armée Orion's Wild Hunt amie relancent les jets pour Toucher de 1 naturel (Tir/Combat) contre cette unité. +100 PV si le modèle désigné est tué ou fuit en fin de partie."},"spirit-of-galrauch":{"name":"Spirit of Galrauch","desc":"En sous-phase de Start of Turn de chacun de vos tours, faire un test de Cd pour Galrauch. Réussi : contrôlé normalement. Raté (l'esprit se rebelle) : Niveau de Magie réduit à 1 (un seul sort/tour), soumis à Random Movement (2D6), et s'il est au combat il doit diriger D3 de ses attaques contre lui-même (les blessures qu'il s'inflige s'ajoutent au résultat de combat ennemi)."},"hellcannon-misfire-table":{"name":"Hellcannon Misfire Table","desc":"Jet D6 : 1 Free at Last! (le Daemon se libère : chaque unité ami/ennemi à 3D6\" subit D6 touches de Force 5, AP -1, puis le Hellcannon est retiré) ; 2-4 Chomp! (retirer un Chaos Dwarf Handler) ; 5-6 Blooood! (le Hellcannon bouge de 3D6\" comme en Random Movement / Mouvements Obligatoires)."},"steeds-of-darkness":{"name":"Steeds of Darkness","desc":"Quand une unité de cavalerie ou char de cette armée fait un jet de Charge, de Fuite ou de Poursuite, elle peut relancer les dés montrant un 1 naturel, avant d'écarter les dés à écarter."},"warped-form":{"name":"Warped Form","desc":"Quand le combat de cette unité (Skin Wolves) est choisi (Étape 1.1 Choose & Fight), choisir une Transfiguration jusqu'au prochain Start of Turn : Enlarged Claws (+1 AP des armes + Armour Bane (2)) ; Barbed Protrusions (Extra Attacks (+1)) ; Toughened Flesh (+1 Endurance et +2 à la valeur d'armure)."},"warpfire-aura":{"name":"Warpfire Aura","desc":"Les autres modèles (ami et ennemi) n'ont droit à aucune sauvegarde Ward tant qu'ils sont à moins de 3\" de ce modèle."},"mark-of-khorne":{"name":"Mark of Khorne","desc":"Les modèles avec la Marque de Khorne ont la règle Frénésie (Frenzy)."},"mark-of-nurgle":{"name":"Mark of Nurgle","desc":"Toute figurine ennemie qui dirige ses attaques contre un modèle avec la Marque de Nurgle en phase de Combat doit relancer ses jets pour Toucher de 6 naturel."},"mark-of-slaanesh":{"name":"Mark of Slaanesh","desc":"Les modèles avec la Marque de Slaanesh ont +1 en Initiative au premier round de combat. De plus, si la majorité de l'unité a la Marque de Slaanesh, l'unité réussit automatiquement ses tests de Panique."},"mark-of-tzeentch":{"name":"Mark of Tzeentch","desc":"Les modèles avec la Marque de Tzeentch ont Flaming Attacks et Magic Resistance (-1). De plus, un Magicien avec la Marque ayant rejoint une unité de même Marque (Force d'Unité 10+) applique +1 à ses jets d'Incantation (perdu s'il quitte l'unité ou si FU < 10)."},"favour-of-the-gods":{"name":"Favour of the Gods","desc":"Dans une armée Wolves of the Sea, si un personnage tue son adversaire en défi, il jette immédiatement sur la table Gaze of the Gods. De plus, si une unité capture l'étendard ennemi comme trophée, elle jette sur Gaze of the Gods ('ce modèle' → 'cette unité')."},"cursed-by-the-gods":{"name":"Cursed by the Gods","desc":"Les Gigantic Spawn adoptent les traits du dieu qui les a maudits : voir Gigantic Spawn of Khorne / Nurgle / Slaanesh / Tzeentch."},"praising-the-gods":{"name":"Praising the Gods","desc":"1×/partie, en sous-phase de Commandement, une unité d'un Chaotic Cult peut implorer son patron via un test de Cd. Réussi : jusqu'au prochain Start of Turn, les modèles du Culte gagnent le bénéfice de leur Culte (Bloodied Hound / Carrion Crow / Slithering Serpent / Fell Raptor)."},"relentless-warriors":{"name":"Relentless Warriors","desc":"Un modèle avec cette règle a une sauvegarde Ward 6+ contre les blessures causées par une attaque ennemie non magique."},"forsaken-by-khorne":{"name":"Forsaken by Khorne","desc":"L'unité a la règle Hatred (tous les ennemis)."},"forsaken-by-nurgle":{"name":"Forsaken by Nurgle","desc":"L'unité a la règle Peur (Fear)."},"forsaken-by-slaanesh":{"name":"Forsaken by Slaanesh","desc":"L'unité a la règle Swiftstride."},"forsaken-by-tzeentch":{"name":"Forsaken by Tzeentch","desc":"L'unité a la règle Magic Resistance (-3)."},"gigantic-spawn-of-khorne":{"name":"Gigantic Spawn of Khorne","desc":"Les Gigantesques Engeances de Khorne ont Impacts de Charge (D3) et Coup Fatal."},"gigantic-spawn-of-nurgle":{"name":"Gigantic Spawn of Nurgle","desc":"Les Gigantesques Engeances de Nurgle ont Attaques Empoisonnées et Régénération (5+)."},"gigantic-spawn-of-slaanesh":{"name":"Gigantic Spawn of Slaanesh","desc":"Les Gigantesques Engeances de Slaanesh ont Contre-Charge et Frappe en Premier."},"gigantic-spawn-of-tzeentch":{"name":"Gigantic Spawn of Tzeentch","desc":"Les Gigantesques Engeances de Tzeentch ont Attaques Enflammées, Attaques Magiques et Résistance à la Magie (-2)."},"spawn-of-khorne":{"name":"Spawn of Khorne","desc":"Les Spawn of Khorne ont la règle Killing Blow."},"spawn-of-nurgle":{"name":"Spawn of Nurgle","desc":"Les Spawn of Nurgle ont la règle Poisoned Attacks."},"spawn-of-slaanesh":{"name":"Spawn of Slaanesh","desc":"Les Spawn of Slaanesh ont la règle Strike First."},"spawn-of-tzeentch":{"name":"Spawn of Tzeentch","desc":"Les Engeances de Tzeentch ont Attaques Enflammées et Attaques Magiques."},"chaotic-cults":{"name":"Chaotic Cults","desc":"Les Marauder Tribes ont la Marque de Chaos Indivis ; certains peuvent la remplacer par la Marque d'un dieu. Les Chaos Marauders et Marauder Horsemen peuvent à la place appartenir à un 'Chaotic Cult'. Un modèle n'appartient qu'à un seul Culte ; un perso marqué peut rejoindre une unité de n'importe quel Culte."},"cult-of-the-bloodied-hound":{"name":"Cult of the Bloodied Hound","desc":"Les modèles de ce Chaotic Cult gagnent +1 en Capacité de Combat (WS)."},"cult-of-the-carrion-crow":{"name":"Cult of the Carrion Crow","desc":"Les modèles de ce Chaotic Cult gagnent +1 en Endurance (T)."},"cult-of-the-fell-raptor":{"name":"Cult of the Fell Raptor","desc":"Les modèles de ce Chaotic Cult gagnent une sauvegarde Ward 6+ contre les blessures causées par une attaque ennemie non magique."},"cult-of-the-slithering-serpent":{"name":"Cult of the Slithering Serpent","desc":"Les modèles de ce Chaotic Cult gagnent la règle Poisoned Attacks."},"mounted-host":{"name":"Mounted Host","desc":"Tous les personnages d'une armée Heralds of Darkness doivent être montés ou avoir Fly (X)."},"sea-born-raiders":{"name":"Sea-Born Raiders","desc":"Dans une armée Wolves of the Sea, les Chaos Marauders et Marauder Horsemen peuvent avoir Ambushers pour +1 pt/figurine ; les Aspiring Champions d'infanterie/cavalerie pour +10 pts."},"explosive-demise":{"name":"Explosive Demise","desc":"Quand un Warpfire Dragon perd son dernier PV, avant de le retirer, chaque unité (ami/ennemi) à <6\" subit D6 touches de Force 5, AP -2."},"fire-and-chaos":{"name":"Fire & Chaos","desc":"Les Warpfire Dragons ont une sauvegarde Ward 5+ contre les blessures causées par une attaque ayant Magical Attacks ou Flaming Attacks."},"the-shadow-grows":{"name":"The Shadow Grows","desc":"Pour chaque personnage avec une Marque de Chaos (autre qu'Indivis), l'armée doit inclure une unité non-personnage de même Marque, et inversement."},"warriors-duel":{"name":"Warriors' Duel","desc":"Au lieu du roll-off du premier tour, défier l'adversaire à un Warrior's Duel. Accepté : chaque joueur choisit un champion d'unité (PV 1, infanterie/cavalerie) ; ils combattent comme en défi jusqu'à un vainqueur, dont le joueur prend le 1er tour. Décliné : l'armée Wolves of the Sea gagne le 1er tour. (Bretonnie qui accepte = a prié pour la Bénédiction ; qui décline = la perd.)"},"breath-of-change":{"name":"Breath of Change","desc":"1×/partie, au lieu de Dark Fire of Chaos / Fumes of Contagion, Galrauch peut utiliser le Breath of Change : gabarit de souffle ; toute figurine touchée (ami/ennemi) fait un test d'Endurance ; raté = retirée comme perte ; réussi = aucun effet."},"caged-fury":{"name":"Caged Fury","desc":"En sous-phase de Start of Turn de chacun de vos tours, faire un test de Commandement pour ce modèle (Hellcannon). Raté = jet immédiat sur la table de Hellcannon Misfire."},"accursed-weapons":{"name":"Accursed Weapons","desc":"Une arme de main portée par un modèle avec cette règle gagne Magical Attacks et un Armour Piercing de -1."},"balefire-brazier":{"name":"Balefire Brazier","desc":"Les Magiciens ennemis à <15\" d'un ou plusieurs modèles avec cette règle doivent augmenter de 1 la valeur d'incantation de leurs sorts."},"banner-of-the-count":{"name":"Banner of the Count","desc":"Un Vampire Thrall Porteur de la Bannière de Bataille remplace « Hold Your Ground » : les unités amies à portée de Commandement relancent les tests de Cd ratés ET réduisent de D3 les PV perdus par Unstable. Non cumulatif avec Indomitable (prendre le plus haut)."},"bestial-fury":{"name":"Bestial Fury","desc":"Les unités ennemies ne peuvent réclamer aucun point de résultat de combat pour être engagées sur le flanc ou l'arrière de ce modèle (Varghulf)."},"bound-spirits":{"name":"Bound Spirits","desc":"Contrairement aux autres swarms, cette unité n'est pas soumise à Undisciplined : elle peut bénéficier de l'Inspiring Presence du Général et du « Hold Your Ground » d'une Bannière de Bataille."},"the-death-of-a-general":{"name":"The Death of a General","desc":"Le Général d'une armée Vampire Counts doit être un Magicien. S'il est tué : toutes les unités Necromantic Undead amies perdent Regeneration ; et à la fin de la phase de sa mort puis à chaque Start of Turn, chaque unité Necromantic Undead fait un test de Cd — raté = perte de PV égale à la marge d'échec."},"implacable-defence":{"name":"Implacable Defence","desc":"Une unité avec cette règle en Close Order équipée de boucliers et choisissant de les utiliser peut choisir de ne pas Céder du Terrain si elle perd un round de combat. Exception : si la Force d'Unité du gagnant est plus du double de celle du perdant, elle doit Céder du Terrain normalement."},"martial-pride":{"name":"Martial Pride","desc":"Chaque figurine d'une unité de Blood Knights peut lancer et accepter des défis comme un personnage. Mais l'unité ne peut refuser un défi : si un défi est lancé et qu'une figurine peut l'accepter, elle doit l'accepter."},"spectral-coach":{"name":"Spectral Coach","desc":"Un Black Coach peut devenir 'Incorporeal' en sous-phase de Commandement, jusqu'au prochain Start of Turn. Incorporeal : perd Impact Hits (D6+2), gagne Ethereal et Fly (10)."},"spectral-reapers":{"name":"Spectral Reapers","desc":"Une unité avec cette règle (Hexwraiths) peut faire une attaque 'Spectral Reapers' contre une unité ennemie non engagée en la survolant en sous-phase de Mouvements Restants : la cible subit, par figurine ayant survolé, une touche de Force 4 sans armure (Ward/Régén OK), avec Flaming Attacks et Magical Attacks."},"warped-tintinnabulation":{"name":"Warped Tintinnabulation","desc":"Quand une unité amie à <15\" récupère des PV via Invocation of Nehek, jet D6 : sur 4+ elle récupère 1 PV de plus. De plus, les unités amies à <15\" réduisent de 1 les PV perdus par Unstable. Cumulatif avec Indomitable."},"wight-banner":{"name":"Wight Banner","desc":"Un Wight Lord Porteur de la Bannière de Bataille remplace « Hold Your Ground » : les unités amies à portée de Commandement relancent les tests de Cd ratés ET réduisent de D3 les PV perdus par Unstable. Non cumulatif avec Indomitable."},"authority-of-the-hierophant":{"name":"Authority of the Hierophant","desc":"Une armée Mortuary Cult doit inclure au moins un Liche Priest comme Hierophant ; ce Hierophant doit aussi être le Général, même s'il n'a pas le plus haut Commandement."},"banner-of-the-king":{"name":"Banner of the King","desc":"Un Royal Herald porté en Porteur de la Bannière de Bataille remplace « Hold Your Ground » par : les unités amies à portée de Commandement relancent les tests de Cd ratés ET réduisent de D3 les PV perdus par Unstable. Non cumulatif avec Indomitable (prendre la plus haute valeur)."},"commander-of-legions":{"name":"Commander of Legions","desc":"Settra gagne la règle Arise! et, contrairement aux autres, peut l'utiliser même engagé au combat."},"eternal-taskmaster":{"name":"Eternal Taskmaster","desc":"En sous-phase de Commandement, test de Cd ; réussi : jusqu'au prochain Start of Turn, ce personnage et l'unité rejointe gagnent Extra Attacks (+1) et Hatred (tous ennemis)."},"grind-them-down":{"name":"\"Grind Them Down!\"","desc":"À portée de Commandement du Général, les modèles amis de type Char peuvent relancer le dé déterminant le nombre d'Impact Hits qu'ils causent."},"harmonious-incantations":{"name":"Harmonious Incantations","desc":"Si un Liche Priest d'une armée Mortuary Cult utilise Arise! à portée de Commandement d'un ou plusieurs autres Liche Priests amis, le nombre de PV récupérés est augmenté de 1."},"herald-of-despair":{"name":"Herald of Despair","desc":"Toute unité ennemie au contact de Nekaph (ou d'une unité qu'il a rejointe) jette un D6 supplémentaire lors d'un test de Peur ou Terreur, et écarte le résultat le plus bas."},"the-hierophant":{"name":"The Hierophant","desc":"L'armée doit inclure un Liche Priest comme Hierophant (le plus haut Niveau de Magie). S'il est tué : toutes les unités Nehekharan Undead amies perdent Regeneration ; et à la fin de la phase de sa mort puis à chaque Start of Turn, chaque unité Nehekharan Undead fait un test de Cd — raté = perte de PV égale à la marge d'échec."},"the-language-of-the-priests":{"name":"The Language of the Priests","desc":"Le Général d'un Nehekharan Royal Host doit être un Tomb King ou Tomb Prince. Pour +35 pts, il peut avoir Arise! et être Magicien Niveau 1 (Lore de Necromancy) et devient l'Hierophant. Un Magicien avec cette règle peut porter une armure sans pénalité."},"lay-in-wait":{"name":"Lay In Wait","desc":"0-1 unité de Skeleton Skirmishers par 1000 pts peut avoir Ambushers gratuitement."},"masterful-outriders":{"name":"Masterful Outriders","desc":"0-1 unité de Skeleton Horse Archers par 1000 pts peut avoir Chariot Runners gratuitement."},"my-will-be-done":{"name":"My Will Be Done","desc":"En sous-phase de Commandement, test de Cd ; réussi : choisir un modificateur jusqu'au prochain Start of Turn pour ce personnage, sa monture et l'unité rejointe (max 10) — Forward to Glory! (+D3 M), My Worthy Champions! (+1 CC), Strike like the Cobra! (+D3 I). Non cumulatif."},"nehekharan-phalanx":{"name":"Nehekharan Phalanx","desc":"Une unité avec cette règle en Close Order équipée de boucliers et choisissant de les utiliser peut choisir de ne pas Céder du Terrain (Give Ground) si elle perd un round de combat. Exception : si la Force d'Unité du gagnant est plus du double de celle du perdant, elle doit Céder du Terrain normalement."},"resurrecting-the-fallen":{"name":"Resurrecting the Fallen","desc":"Soin/résurrection dans un ordre strict : 1) personnages rejoints (un personnage mort ne peut être ressuscité) ; 2) figurines à plusieurs PV (chacune soignée à fond avant la suivante) ; 3) champion, puis porte-étendard, puis musicien ; 4) figurines de base. Au moins une figurine doit subsister ; jamais au-delà de la taille de départ."},"scarab-prince":{"name":"Scarab Prince","desc":"Si Prince Apophas perd son dernier PV, avant de le retirer, toutes les unités ennemies à 2D6\" subissent 2D6 touches de Force 2, AP -1."},"screaming-skulls":{"name":"Screaming Skulls","desc":"Toute unité subissant une ou plusieurs blessures non sauvegardées de cette arme doit faire un test de Panique comme si elle avait subi de lourdes pertes."},"sepulchral-animus":{"name":"Sepulchral Animus","desc":"Une fois par tour, avant un jet d'Incantation, un Liche Priest d'une armée Mortuary Cult peut puiser dans un construct mort-vivant ami à portée de Commandement (swarm/monstrueux/monstre/behemoth) : l'unité nominée perd 1 PV, puis le prêtre applique +1 à son jet d'Incantation (ne nie pas un double 1 naturel)."},"settra-does-not-kneel":{"name":"Settra Does Not Kneel!","desc":"Settra doit toujours accepter un défi, sauf si Nekaph est engagé dans le même combat — auquel cas Nekaph doit accepter le défi à sa place."},"settra-the-great":{"name":"Settra the Great","desc":"Si l'armée inclut Settra, il doit être le Général et l'Hierophant (même sans le plus haut Niveau de Magie). De plus, Settra a une portée de Commandement de 18\"."},"settras-champion":{"name":"Settra's Champion","desc":"Nekaph doit toujours lancer et accepter les défis si possible ; ses défis ne peuvent être refusés. Engagé dans un défi, il porte un Killing Blow sur un 5 ou 6 naturel pour Blesser (au lieu du 6 habituel)."},"skulls-of-the-foe":{"name":"Skulls of the Foe","desc":"Jusqu'au prochain Start of Turn, toute unité ennemie à 2D6\" du centre du gabarit (après déviation) subit -1 en Commandement (min 2)."},"soul-reaper":{"name":"Soul Reaper","desc":"Après le déploiement mais avant le 1er tour, désigner un personnage ennemi. Ce modèle peut relancer ses jets pour Toucher de 1 naturel contre le personnage désigné."},"steadfast-discipline":{"name":"Steadfast Discipline","desc":"Une unité avec cette règle peut faire un Volley Fire lors d'un tour où elle a bougé, ou en réaction de charge Stand & Shoot."},"stone-shaper":{"name":"Stone Shaper","desc":"En sous-phase de Commandement, hors combat, ce personnage nomme un Necrolith Colossus, Necrosphinx, ou une unité d'Ushabti/Venerable Ushabti ami(e) à portée de Commandement : jusqu'à la fin du tour, l'unité améliore de 1 sa valeur de Régénération."},"sworn-protector":{"name":"Sworn Protector","desc":"Si un Monarque de Nehekhara subit une touche à <3\" de ce modèle, vous pouvez transférer cette touche et tous ses effets sur ce modèle."},"the-terrors-below":{"name":"The Terrors Below","desc":"Un Tomb Scorpion ou une unité de Necroserpents peut avoir cette règle pour +2 pts/figurine. Placé via From Beneath the Sands, il peut nommer une unité ennemie d'infanterie à <8\" : celle-ci fait un nombre de tests d'Initiative égal à la Force d'Unité de l'attaquant ; chaque échec = 1 figurine retirée."},"usirians-reaper":{"name":"Usirian's Reaper","desc":"Après le déploiement, nommer un personnage de la liste adverse. Apophas peut relancer ses jets ratés pour Toucher ou Blesser contre lui ; ses touches contre ce personnage gagnent Magical Attacks."},"abominable-attacks":{"name":"Abominable Attacks","desc":"Au lieu d'attaquer normalement, une Hell Pit Abomination peut faire une Abominable Attack : Feed (1 figurine au contact subit D3 blessures auto sans armure ; Ward/Régén OK) ou Avalanche of Flesh (gabarit 3\" centré, touches de Force du modèle AP -2)."},"avalanche-of-flesh":{"name":"Avalanche of Flesh","desc":"Placer un petit gabarit (3\") centré sur l'unité cible. Toute figurine (ami/ennemi, sauf ce modèle) sous le gabarit risque une touche de Force du modèle, AP -2."},"crushing-bulk":{"name":"Crushing Bulk","desc":"Les Stomp Attacks d'un Doomwheel ont un Armour Piercing de -1. De plus, une unité ennemie subissant des Impact Hits de ce modèle fait immédiatement un test de Commandement ; échoué = Disrupted jusqu'à la fin de la phase de Combat."},"deploying-weapon-teams":{"name":"Deploying Weapon Teams","desc":"Un Weapon Team doit être déployé en même temps que son unité 'parente' (celle pour laquelle il a été acheté), à moins de 3\" d'elle."},"eshin-infiltration":{"name":"Eshin Infiltration","desc":"Quand une unité amie de Gutter Runners avec Ambushers arrive de réserve, elle peut être placée n'importe où entièrement à 12\" d'un Master Assassin révélé, mais pas à <6\" d'ennemis (au lieu d'entrer en renforts). Elle ne peut pas charger ce tour et compte comme ayant bougé. Inutilisable tant que l'assassin est caché."},"feed":{"name":"Feed","desc":"Désigner une figurine ennemie au contact de la Hell Pit Abomination : si touchée, elle subit D3 blessures automatiques sans sauvegarde d'armure (Ward et Régénération autorisées)."},"hidden-skaven":{"name":"Hidden (Skaven)","desc":"Les Master Assassins ne sont pas déployés au départ : ils sont 'cachés' dans une unité Skaven d'infanterie amie de Force d'Unité 10+. Révélables en sous-phase de Start of Turn ou au début d'une phase de Combat (placés comme un personnage rejoignant l'unité). Si l'unité est détruite/fuit avant révélation, l'assassin est retiré. Ne peut être Général."},"leader-of-the-pack-skaven":{"name":"Leader of the Pack (Skaven)","desc":"Modèles pris seulement dans une unité de Rat Ogres ou Giant Rats. Ils (y compris le commandement) se placent à l'arrière de l'unité ; les Rat Ogres/Giant Rats occupent toujours les rangs de front. Un Master Moulder peut lancer/accepter des défis même hors du rang de combat."},"lightning-strike":{"name":"Lightning Strike","desc":"En tirant, tracer une ligne droite de 8D6\" depuis le bord du socle. Toute figurine (ami/ennemi) sous la ligne subit une touche dont la Force est déterminée par un dé d'artillerie. Misfire → table de Warp Lightning Misfire (Meltdown : détruit ; Energy Overload : Force 6 direction aléatoire ; Fzzzt : pas de tir)."},"pavise":{"name":"Pavise","desc":"Un Pavois est un bouclier qui améliore la valeur d'armure de son porteur de 3 (au lieu du 1 habituel) contre les attaques faites par des figurines ennemies situées dans l'arc frontal du porteur. En revanche, un Pavois n'offre aucune protection contre les attaques faites par des figurines ennemies situées dans son arc arrière ou latéral."},"poisoned-wind":{"name":"Poisoned Wind","desc":"Pour Blesser avec une arme ayant cette règle, un 6+ est toujours une réussite (même si l'Endurance est trop haute). Aucune sauvegarde d'armure permise (Ward/Régén OK). Les porteurs de ces armes sont immunisés à cette règle."},"safe-from-harm":{"name":"Safe From Harm","desc":"Quand l'ennemi tire sur une unité de Rat Ogres contenant un ou plusieurs Packmasters, l'adversaire jette un D6 par touche réussie avant de Blesser : sur 1-4 la touche frappe un Rat Ogre. Au combat, l'ennemi doit allouer ses attaques sur une figurine au contact (ou la plus proche du rang de combat) avant de jeter pour Toucher."},"targeting-weapon-teams":{"name":"Targeting Weapon Teams","desc":"À moins de 3\" de son unité parente (contenant 5+ figurines et ne fuyant pas), un Weapon Team ne peut être ciblé par le tir ou les sorts ennemis, sauf s'il est la cible la plus proche."},"too-horrible-to-die":{"name":"Too Horrible To Die","desc":"La 1re fois qu'une Hell Pit Abomination perd son dernier PV, jet D6 avant de la retirer : 1-3 retirée ; 4-5 placer un Rat Swarm (1 figurine) à <3\" puis la retirer ; 6 elle récupère immédiatement D3 PV."},"weapon-team-leadership":{"name":"Weapon Team Leadership","desc":"À moins de 3\" de son unité parente, un Weapon Team gagne un modificateur positif à son Commandement égal au bonus de rang de l'unité parente, jusqu'à un maximum de Commandement 10."},"zzzzap":{"name":"Zzzzap!","desc":"À la fin de chaque phase de Tir, placer jusqu'à trois petits gabarits (3\") dont le centre est à <6\" de ce modèle ; chacun dévie de D6\". Toute figurine sous un gabarit subit une touche de Force déterminée par un dé d'artillerie, AP -2. Misfire = le gabarit est retiré, ce modèle perd 1 PV."},"big-stabbas":{"name":"Big Stabbas","desc":"Une unité avec Big Stabbas a la règle Impact Hits (D3). Cette règle s'applique à l'unité dans son ensemble, pas aux figurines individuelles."},"big-uns":{"name":"Big 'Uns","desc":"Engagé au combat, un modèle avec cette règle a +1 en Force et gagne la règle Armour Bane (1)."},"bully":{"name":"Bully","desc":"Un Orc Bully est un type de personnage pris en amélioration pour accompagner une machine de guerre. Déployé avec sa machine comme un personnage rejoignant une unité ; il ne peut plus la quitter. Sauf s'il fuit, les machines amies à portée de Commandement peuvent utiliser son Commandement au lieu du leur."},"cunning-hunters":{"name":"Cunning Hunters","desc":"Dans une armée Nomadic Waaagh!, n'importe quel nombre de Goblin Wolf Rider Mobs peut avoir Ambushers pour +1 pt/figurine. De plus, les Goblin Bosses et Shamans montés sur Giant Wolf peuvent avoir Ambushers pour +10 pts."},"da-troll-calla":{"name":"Da Troll Calla","desc":"Sauf s'il fuit, les Troll Mobs amis à portée de Commandement d'Ogdruz peuvent utiliser son Commandement au lieu du leur."},"enhanced-regeneration":{"name":"Enhanced Regeneration","desc":"Les modèles avec Regeneration (X+) dans une armée Troll Horde peuvent relancer les sauvegardes de Régénération ratées contre les blessures causées par des attaques non magiques."},"hit-em-fast-and-hit-em-ard":{"name":"Hit 'em Fast and Hit 'em 'Ard!","desc":"Dans une Nomadic Waaagh!, tout modèle Orc monté sur War Boar gagne Impact Hits (1) (Force du War Boar, AP -1). De plus, 0-1 Boar Boyz Mob par 1000 pts peut avoir Vanguard pour +1 pt/figurine."},"hunting-packs":{"name":"Hunting Packs","desc":"Tout Goblin Wolf Rider Mob dans une Nomadic Waaagh! peut échanger Open Order + Skirmishers contre Close Order + Horde."},"indiscriminate-hunger":{"name":"Indiscriminate Hunger","desc":"En sous-phase de Commandement, une Troll Hag engagée au combat peut faire une attaque 'Indiscriminate Hunger' : l'unité ennemie ciblée fait un test d'Initiative. Échoué : elle perd 1 PV (et la Troll Hag récupère 1 PV). Réussi : aucun effet."},"mob-rule":{"name":"Mob Rule","desc":"Si ce personnage a rejoint une unité d'Orcs avec une Force d'Unité de 10+, il applique +1 à ses jets d'Incantation. Perdu s'il quitte l'unité ou si la FU tombe sous 10."},"bonegrinder-giant-attacks":{"name":"Bonegrinder Giant Attacks","desc":"Les Géants Broyeurs d'Os n'attaquent pas comme les autres créatures. Ils sont bien trop gros et hargneux pour obéir aux ordres, et trop bêtes pour avoir le moindre plan cohérent. Au lieu d'attaquer normalement à la phase de Combat, un Géant Broyeur d'Os doit effectuer une « Attaque de Géant Broyeur d'Os ». Désignez une unité ennemie avec laquelle le Géant Broyeur d'Os est engagé en combat comme cible de l'attaque et faites un jet sur le Tableau d'Attaques de Géant Broyeur d'Os ci-dessous. Le type de troupe de l'unité cible détermine la colonne — Petits Trucs : « infanterie régulière », « infanterie lourde », « nuées », « cavalerie légère », « cavalerie lourde » ou « bêtes de guerre ». Gros Trucs : « infanterie monstrueuse », « cavalerie monstrueuse », « char léger » ou « machine de guerre ». Plus Gros Trucs : « char lourd », « créature monstrueuse » ou « béhémoth ».\n\nÉcraser sous ses Pieds : Le Géant Broyeur d'Os piétine lourdement l'ennemi. Placez un grand (5\") gabarit d'explosion de sorte que son trou central soit directement au-dessus du centre de l'unité cible. Toute figurine (amie ou ennemie, cette figurine exceptée) dont le socle se trouve sous le gabarit risque d'être touchée et de subir une seule touche, en utilisant la caractéristique de Force de cette figurine, avec une PA de -3.\n\nCoup d'Boule : Le Géant Broyeur d'Os jette un regard noir à son adversaire et lui flanque un magistral coup d'boule. L'unité cible subit une seule touche et subit D3+1 blessures sans sauvegarde d'armure ni de Régénération autorisée (les sauvegardes Invulnérables peuvent être tentées normalement).\n\nBroyer les Os : Confronté à des rangs entiers d'amuse-bouches bien alignés, le Géant Broyeur d'Os essaie d'en engloutir autant qu'il peut. Chaque figurine du rang combattant de l'unité cible doit immédiatement effectuer un test d'Initiative. Chaque figurine qui rate ce test est retirée du jeu comme perte ; chaque figurine qui réussit demeure indemne. Tout personnage dans le rang combattant peut effectuer un jet de « Attention, Messire ! », comme si son unité avait été touchée par une attaque de tir.\n\nPuissant Revers : Le Géant Broyeur d'Os assène un revers de sa massue à ses ennemis. L'unité cible subit D6+1 touches de la massue du Géant Broyeur d'Os. Pour cette attaque, la massue a une caractéristique de Force de F+1 et une PA de -2.\n\nVomi : Baisser le regard vers de si petites créatures donne le vertige au Géant Broyeur d'Os ! Placez un gabarit de souffle de sorte que la pointe touche le bord du socle de cette figurine qui est en contact avec l'unité cible et que l'extrémité la plus large soit sur l'unité cible. Toute figurine (amie ou ennemie, cette figurine exceptée) dont le socle est sous le gabarit risque d'être touchée et de subir une seule touche de Force 5 avec une PA de -2.\n\nRaclée : Le Géant Broyeur d'Os saisit sa massue à deux mains et l'abat sur le crâne de l'ennemi. Le Géant Broyeur d'Os effectue une seule attaque contre l'unité cible. Pour cette attaque, la massue a une caractéristique de Force de F+3, une PA de -4 et la règle spéciale Blessures Multiples (2D3)."},"crush-underfoot":{"name":"Crush Underfoot","desc":"Le Bonegrinder Giant piétine l'ennemi. Placer un grand gabarit (5\") centré sur l'unité cible. Toute figurine (ami ou ennemi, sauf le Géant) sous le gabarit risque une touche utilisant la Force du Géant, AP -3."},"eadbutt-bonegrinder-giant":{"name":"'Eadbutt (Bonegrinder Giant)","desc":"Le Bonegrinder Giant donne un coup de tête. L'unité cible subit une touche infligeant D3+1 blessures sans sauvegarde d'armure ni Régénération (Ward autorisée)."},"grind-its-bones":{"name":"Grind its Bones","desc":"Chaque figurine du rang de combat de l'unité cible fait un test d'Initiative. Échoué : retirée comme perte. Réussi : indemne. Les personnages peuvent faire un Look Out, Sir!."},"ker-splat":{"name":"Ker-splat","desc":"Les Mangler Squigs traitent tout terrain difficile comme un terrain dangereux."},"mighty-swing-bonegrinder-giant":{"name":"Mighty Swing (Bonegrinder Giant)","desc":"Le Bonegrinder Giant balaie son gourdin : l'unité cible subit D6+1 touches de Force S+1, AP -2."},"motherly-love":{"name":"Motherly Love","desc":"Au lieu d'attaquer normalement, une Troll Hag fait une attaque 'Motherly Love' : jet D6. 1-2 Smother (gabarit 5\", touche Force du Troll Hag AP -2) ; 3-4 Mother (1 figurine, D3+1 blessures sans armure ni Régén, Ward OK) ; 5-6 Mither (D6+1 touches Force du Troll Hag sans armure, Ward/Régén OK, et -1 Cd à la cible jusqu'à la fin du tour)."},"netters":{"name":"Netters","desc":"Quand le combat de cette unité est choisi (Étape 1.1 de Choose & Fight), elle peut tenter d''entangler' une unité ennemie engagée : D6, sur 1 elle s'entrave elle-même, sur 2+ l'ennemi est entravé. Jusqu'à la fin de la phase de Combat, l'unité entravée subit -1 en Force (min 1). Non cumulatif."},"oi-dis-way":{"name":"Oi! Dis Way!","desc":"Sauf si le personnage fuit, les Troll Mobs amis d'une armée Troll Horde à portée de Commandement d'un Orc Shaman, Goblin Shaman ou Troll Hag peuvent utiliser le Commandement de ce personnage."},"on-da-move":{"name":"On Da Move","desc":"Tous les personnages d'une armée Nomadic Waaagh! doivent être montés."},"protect-da-boss":{"name":"Protect Da Boss","desc":"Ce modèle ne peut pas être ciblé par le tir ou les sorts ennemis tant qu'il est à <3\" d'un Troll Mob ami, sauf s'il est la cible la plus proche."},"skulking-menace":{"name":"Skulking Menace","desc":"Les Nasty Skulkers ne sont pas déployés au départ ; noter quels Goblin Mobs en cachent. Au début de leur 1er round de combat (Étape 1.1 Choose & Fight), l'unité dissimulante doit les révéler (placés comme un personnage rejoignant l'unité). Ils ne peuvent plus la quitter."},"slimy-shanks":{"name":"Slimy Shanks","desc":"Toute figurine ennemie qui dirige ses attaques contre ce modèle en phase de Combat subit -1 à ses jets pour Toucher."},"solitary-fighters":{"name":"Solitary Fighters","desc":"Les Black Orc Bosses d'une armée Nomadic Waaagh! ne sont pas soumis aux règles Da Boyz ni Quell Impetuosity."},"spiked-ball-and-chains":{"name":"Spiked Ball & Chains","desc":"Les Impact Hits causés par ce modèle ont un Armour Piercing de -3."},"squigs-go-wild":{"name":"Squigs Go Wild","desc":"Si un Squig Herd se brise et fuit, et contient 5+ Cave Squigs, chaque unité (ami ou ennemi) à 2D6\" subit D3 touches de Force 5, AP -1 (+1 au D3 par tranche de 5 Cave Squigs supplémentaires). Puis l'unité est retirée comme détruite."},"syphoned-strength":{"name":"Syphoned Strength","desc":"Tant qu'Ogdruz Swampdigga est à <3\" d'un Troll Mob ami de Force d'Unité 6+ qui ne fuit pas, il applique +1 à ses jets d'Incantation."},"troll-tongue":{"name":"Troll Tongue","desc":"En plus des Lores normaux, les Orc Shamans et Goblin Shamans d'une armée Troll Horde peuvent connaître des sorts du Lore of Troll Magic."},"wallop":{"name":"Wallop","desc":"Le Bonegrinder Giant frappe à deux mains : une seule attaque, gourdin de Force S+3, AP -4, avec Multiple Wounds (2D3)."},"warpaint":{"name":"Warpaint","desc":"Donne une sauvegarde Ward 6+ contre toute blessure. Le porteur ne peut jamais porter d'armure (mais peut porter un bouclier)."},"bellowers-and-musicians":{"name":"Bellowers & Musicians","desc":"La plupart des musiciens Ogres appartiennent à une caste de Hurleurs (Bellowers) : leur instrument est leur voix et leurs poumons. Fonctionne comme un musicien."},"blessings-of-the-volcano-god":{"name":"Blessings of the Volcano God","desc":"Un modèle avec cette règle a une sauvegarde Ward 4+ contre toute blessure causée par une attaque ayant la règle Flaming Attacks (attaques enflammées)."},"butchers-cauldron":{"name":"Butcher's Cauldron","desc":"Ce personnage remplace Impact Hits (2) par Impact Hits (D3+1). De plus, pendant la sous-phase de Commandement de son tour, s'il n'est pas engagé au combat, il peut tenter une offrande au Grand Maw via un test de Commandement (avec son propre Cd). Réussi : jusqu'à sa prochaine sous-phase de Début de Tour, lui et l'unité rejointe gagnent Regeneration (5+). Échoué : il perd immédiatement 1 PV."},"look-out-gnoblar":{"name":"Look-out Gnoblar","desc":"Un champion ou personnage ayant rejoint une unité avec cette règle peut faire un jet « Look Out, Sir! » s'il y a au moins deux figurines de rang (au lieu des cinq habituelles). De plus, on peut relancer ce jet s'il y a cinq figurines de rang ou plus."},"mournfang-charge":{"name":"Mournfang Charge","desc":"Les Impact Hits causés par un modèle avec cette règle ont la règle Armour Bane (1) et une caractéristique Armour Piercing de -1."},"ravenous-hunger":{"name":"Ravenous Hunger","desc":"Quand un Gorger déclare une charge, il peut relancer son jet de Charge."},"running-with-the-pack":{"name":"Running with the Pack","desc":"Un Hunter qui rejoint une unité de Sabretusks gagne Swiftstride tant qu'il reste avec l'unité. De plus, tant que le Hunter reste avec elle, les Sabretusks perdent la règle Impetuous."},"traps-and-snares":{"name":"Traps & Snares","desc":"Toute figurine ennemie qui termine son mouvement de charge au contact socle à socle d'un modèle avec cette règle doit effectuer un test de Terrain Dangereux."},"primeval-roar":{"name":"Primeval Roar","desc":"Une fois par partie, lors de la sous-phase de Commandement, effectuez un test de Commandement. En cas de réussite, jusqu'à la fin du tour, toutes les unités Hommes-Lézards amies à moins de 7 ps gagnent Charge Furieuse."},"guardians":{"name":"Guardians","desc":"Si un Slann ami situé à moins de 3 ps subit une touche lors de la phase de Tir, sur 2+ vous pouvez la transférer (avec ses effets) à cette unité. Les Gardiens du Temple à portée de Commandement d'un Slann peuvent lancer et accepter des défis comme des personnages."},"beast-handlers":{"name":"Beast Handlers","desc":"Quand vous tirez sur une meute de Salamandres/Razordons accompagnée de Dresseurs Skinks, lancez un D6 par touche : sur 1-4 la touche frappe une bête, sur 5+ elle frappe un Dresseur. Au corps à corps, les ennemis doivent répartir leurs attaques sur une figurine au contact socle à socle (ou la plus proche dans le rang combattant)."},"skirmish-screen":{"name":"Skirmish Screen","desc":"Une unité ayant cette règle (Kroxigors) peut tracer sa ligne de vue par-dessus ou à travers les unités amies de Skinks Tirailleurs et se déplacer à travers elles (en écartant les figurines). Les Skinks en formation de Tirailleurs peuvent traiter les figurines proches ayant cette règle comme faisant partie de l'unité pour la cohérence."},"engine-of-the-gods":{"name":"Engine of the Gods","desc":"Un Stégadon Ancien doté d'un Autel des Dieux gagne les règles Configuration Arcanique et Alignement Ardent. Avec au moins deux Autels, les Sorciers amis à moins de 6 ps de l'un d'eux ajoutent +1 à leurs jets pour lancer. Il lance un Projectile Magique lien (PL3, 8+, 15 ps) : la cible subit 2D6 touches de Force 4 avec Attaques Enflammées."},"arcane-configuration":{"name":"Arcane Configuration","desc":"Si votre armée comprend au moins deux Autels des Dieux, les Sorciers amis peuvent ajouter +1 à n'importe quel jet pour lancer tant qu'ils se trouvent à moins de 6 ps d'un Autel des Dieux."},"burning-alignment":{"name":"Burning Alignment","desc":"Projectile Magique lien (PL3, jet pour lancer de 8+, 15 ps) : la cible subit 2D6 touches de Force 4 avec Attaques Enflammées."},"solar-engine":{"name":"Solar Engine","desc":"Un Bastiladon doté d'un Autel Solaire gagne les règles Radiance Solaire et Rayon de Chotec, et lance un Projectile Magique lien (PL2, 9+, 24 ps) : la cible subit 3D3 touches de Force 5 avec AP -2 et Attaques Enflammées."},"solar-radiance":{"name":"Solar Radiance","desc":"Tant qu'elles se trouvent à moins de 6 ps d'un ou plusieurs Autels Solaires, les unités amies au Sang Froid gagnent +1 en Initiative."},"beam-of-chotec":{"name":"Beam of Chotec","desc":"Projectile Magique lien (PL2, jet pour lancer de 9+, 24 ps) : la cible subit 3D3 touches de Force 5 avec AP -2 et Attaques Enflammées."},"ark-of-sotek":{"name":"Ark of Sotek","desc":"Un Bastiladon doté d'une Arche de Sotek gagne les règles Serpents Rampants et Engeance de Sotek."},"slithering-serpents":{"name":"Slithering Serpents","desc":"Lors de la sous-phase de Commandement, chaque unité ennemie située à moins de D6 ps de cette figurine subit 2D6 touches de Force 2."},"spawn-of-sotek":{"name":"Spawn of Sotek","desc":"Lors de la sous-phase de Commandement, lancez un D6 : sur 4+, une Nuée de la Jungle amie située à moins de 6 ps récupère D3 Points de Vie perdus."},"the-questing-vow":{"name":"The Questing Vow","desc":"Vœu chevaleresque. La figurine est Tenace, peut relancer ses tests de Peur, Panique et Terreur ratés, et ne subit pas la Panique due à la Paysannerie proche ; elle ne peut pas être équipée d'une lance. L'unité ne peut être rejointe par un personnage ayant le Vœu du Chevalier ou un personnage de la Paysannerie."},"the-grail-vow":{"name":"The Grail Vow","desc":"Vœu chevaleresque. La figurine est immunisée à la Psychologie, aux Attaques Magiques et est Tenace ; elle bénéficie toujours des Bénédictions de la Dame (sans Prière nécessaire) et ne peut refuser un défi. L'unité ne peut être rejointe que par un autre personnage ayant le Vœu du Graal ou une Demoiselle de la Dame."},"the-crusaders-vow":{"name":"The Crusader's Vow","desc":"Vœu chevaleresque (Croisade d'Errance). La figurine gagne Vétéran et ne subit pas la Panique lorsqu'une unité de Paysannerie proche est détruite ou traversée en fuite."},"the-exiles-vow":{"name":"The Exile's Vow","desc":"Vœu chevaleresque (Exilés Bretonniens). La figurine gagne Tenace et Vétéran, et ne subit pas la Panique lorsqu'une unité de Levée ou de Paysannerie proche est détruite ou traversée en fuite."},"forming-the-lance":{"name":"Forming the Lance","desc":"Une Lance regroupe au moins deux figurines bord à bord orientées dans la même direction : 1 figurine au premier rang, 2 au deuxième, 3 au troisième, etc. Les arcs avant, de flanc et arrière sont définis par le deuxième et le dernier rang ; les figurines de commandement se placent au premier ou deuxième rang (le porte-étendard à l'avant)."},"manoeuvring-a-lance":{"name":"Manoeuvring a Lance","desc":"Une Lance ne peut ni pivoter ni se réaligner, mais peut effectuer une roue, reculer, se déplacer latéralement et se reformer. La roue se mesure depuis le deuxième rang ; tout autre mouvement se mesure depuis la figurine de tête."},"the-lance-in-combat":{"name":"The Lance in Combat","desc":"Seule la figurine de tête doit être au contact (sinon la Lance est émoussée). Toute figurine située sur le pourtour de la Lance compte comme étant dans le rang combattant et au contact. Le Bonus de Rang est de +1 par rang complet ; +1 au résultat de combat si la Puissance d'Unité est de 5 ou plus. Une charge de flanc s'aligne sur le rang le plus large et émousse la Lance."},"blunting-the-lance":{"name":"Blunting the Lance","desc":"Une Lance est « émoussée » si sa figurine de tête ne peut atteindre l'ennemi, si elle effectue une charge désorganisée, ou si elle est chargée sans effectuer de Contre-Charge. Une Lance émoussée se reforme immédiatement en Ordre Serré (autant de figurines au contact que ses rangs complets)."},"casualty-removal":{"name":"Casualty Removal","desc":"Lors du retrait des pertes d'une Lance, vous pouvez retirer des figurines au milieu du rang arrière plutôt qu'à l'une de ses extrémités."},"characters-joining-a-lance":{"name":"Characters Joining a Lance","desc":"Un personnage rejoignant une Lance se place sur le pourtour, dans n'importe quel rang (il peut prendre la place d'une figurine de commandement, qui recule alors). Un personnage qui se retire se place au milieu d'un rang (jamais le premier ni le deuxième) et quitte le rang combattant."},"lance-formations-and-skirmishers":{"name":"Lance Formations & Skirmishers","desc":"Quand une unité de Tirailleurs charge une Lance ou est chargée par elle, les Tirailleurs ne se reforment pas : chaque figurine se déplace au contact de la Lance et des autres figurines. Les Tirailleurs ne peuvent pas émousser une Lance."},"crusaders-zeal":{"name":"Crusader's Zeal","desc":"Une unité ayant cette règle augmente sa portée de charge maximale de 1 ps, peut ajouter +1 à son jet de Charge, et gagne la règle spéciale Impétueux."},"earn-your-spurs":{"name":"Earn Your Spurs","desc":"Tout étendard ennemi capturé par des Chevaliers Errants rapporte 100 PV. À moins de 6 ps d'une figurine amie ayant prêté le Vœu du Graal ou de n'importe quel Seigneur Bretonnien, une unité de Chevaliers Errants peut relancer ses jets de 1 naturels pour toucher."},"peasants-duty":{"name":"Peasant's Duty","desc":"Ce personnage et son unité peuvent Céder du Terrain au lieu d'effectuer un Repli en Bon Ordre, et ignorent la Panique quand une unité de Levée amie Cède le Combat et fuit à moins de 6 ps. Sauf si elles fuient, les unités de Levée amies à portée de Commandement peuvent relancer un test de Panique raté."},"grail-monk":{"name":"Grail Monk","desc":"Un Moine du Graal est une figurine de groupe de commandement qui suit les règles de champion (une unité peut ainsi compter deux champions)."},"grail-reliquae":{"name":"Grail Reliquae","desc":"Placée au premier rang, elle occupe et compte comme six figurines (deux par rang sur trois rangs). Elle ne peut perdre de Points de Vie tant qu'il reste des Pèlerins de Bataille. Elle compte comme porte-étendard et comme musicien ; à moins de 12 ps d'une figurine amie ayant prêté le Vœu du Graal et ne fuyant pas, son unité gagne Insensible à la Psychologie et Indéboulonnable."},"retinue-of-the-saints":{"name":"Retinue of the Saints","desc":"Votre armée peut inclure jusqu'à un Reliquaire du Graal par personnage ou unité ayant prêté le Vœu du Graal qu'elle comprend."},"living-saints":{"name":"Living Saints","desc":"Chaque figurine d'une unité de Chevaliers du Graal peut lancer et accepter des défis comme un personnage."},"the-wyrm-slayer":{"name":"The Wyrm Slayer","desc":"Si Sir Cecil Gastonne tue au corps à corps une infanterie ou cavalerie monstrueuse, une créature monstrueuse ou un béhémoth ennemi, il gagne la règle spéciale Terreur pour le reste de la partie."},"aura-of-the-fay":{"name":"Aura of the Fay","desc":"Quand le Chevalier Vert perd son dernier Point de Vie, il est retiré mais non tué et peut être réveillé (Gardien des Sites Sacrés) ; chaque mort impose toutefois -1 au jet de réveil et -1 Point de Vie (minimum 1). L'ennemi ne marque ses Points de Victoire que s'il est hors du champ de bataille à la fin de la partie."},"guardian-of-the-sacred-sites":{"name":"Guardian of the Sacred Sites","desc":"Le Chevalier Vert n'est pas déployé. À chaque Début de Tour où il est hors de la table, lancez un D6 (sur 3+ il se réveille ; automatiquement au tour 5). Il est placé entièrement à l'intérieur d'un élément de terrain naturel. Lors des Mouvements Restants, il peut se téléporter d'un terrain naturel à un autre (sans autre mouvement ensuite). Il respecte la règle de 1 ps."},"reclaimed-glory":{"name":"Reclaimed Glory","desc":"Une armée d'Exilés Bretonniens ne peut pas prier pour obtenir les Bénédictions au début de la partie. Une unité ayant la règle des Bénédictions l'acquiert si elle effectue une percée ou entre en contact avec un ennemi en fuite lors d'une charge ou d'une poursuite ; un personnage l'acquiert en tuant un personnage ennemi en défi. Une fois perdue, elle ne peut plus être regagnée de cette manière."},"crusading-knights":{"name":"Crusading Knights","desc":"Dans une armée de Croisade d'Errance, les personnages et unités de chevaliers listés gagnent le Zèle du Croisé, et tous ceux ayant prêté le Vœu du Chevalier peuvent l'échanger gratuitement contre le Vœu du Croisé."},"banished-lords":{"name":"Banished Lords","desc":"Dans une armée d'Exilés Bretonniens, les Barons et Paladins ne peuvent pas prêter le Vœu du Graal ; les personnages et unités listés peuvent échanger gratuitement le Vœu du Chevalier contre le Vœu de l'Exilé."},"untutored-arcanist":{"name":"Untutored Arcanist","desc":"Quand il lance un dé sur la table des Incidents Magiques, ce Sorcier lance un D6 supplémentaire et écarte le résultat le plus élevé."},"dragon-armour":{"name":"Dragon Armour","desc":"Une figurine ayant cette règle bénéficie d'une sauvegarde invulnérable de 6+ contre toute blessure ; un Sorcier ayant cette règle peut porter une armure sans pénalité."},"enfeebling-cold":{"name":"Enfeebling Cold","desc":"Tant qu'elles sont au contact de cette figurine (la Merwyrm), les figurines ennemies subissent -1 en Force (minimum 1)."},"abyssal-cloak":{"name":"Abyssal Cloak","desc":"Toute figurine ennemie qui prend cette figurine (la Merwyrm) pour cible lors de la phase de Tir subit un malus de -2 pour toucher à longue portée (au lieu de -1)."},"mighty-constitution":{"name":"Mighty Constitution","desc":"Lors d'un tour où Korhil a effectué un mouvement de charge de 3 ps ou plus, il gagne +1 en Force. Il est immunisé aux Attaques Empoisonnées (l'attaquant jette pour blesser normalement)."},"arrows-of-isha":{"name":"Arrows of Isha","desc":"Tout arc porté par une figurine ayant cette règle dispose de Arme Perforante (1) et d'un AP de -1."},"precision-strikes":{"name":"Precision Strikes","desc":"Une unité de Gardes Maritimes de Lothern rejointe par Ishaya Vess améliore de 1 l'AP de ses armes."},"commanding-voice":{"name":"Commanding Voice","desc":"Ishaya Vess possède une portée de Commandement de 12 ps (15 ps si elle est le Général)."},"horn-of-isha":{"name":"Horn of Isha","desc":"Usage unique. Lors de la sous-phase de Commandement, effectuez un test de Commandement ; en cas de réussite, jusqu'à votre prochain Début de Tour, ce personnage et son unité gagnent +1 pour toucher et +1 pour blesser."},"kings-guard":{"name":"King's Guard","desc":"Toute figurine d'une unité de Lions Blancs de Chrace rejointe par votre Général peut lancer et accepter des défis comme un personnage (capacité perdue si le Général quitte l'unité)."},"sons-of-caledor":{"name":"Sons of Caledor","desc":"Une unité de Princes Dragons ne peut être rejointe que par votre Général ou par un personnage ayant l'Honneur Elfique Sang de Caledor."},"chracian-warriors":{"name":"Chracian Warriors","desc":"Une unité de Lions Blancs de Chrace ne peut être rejointe que par votre Général ou par un personnage ayant l'Honneur Elfique Chasseur Chracien."},"warriors-of-nagarythe":{"name":"Warriors of Nagarythe","desc":"Une unité ayant cette règle (Guerriers des Ombres) ne peut être rejointe que par un personnage ayant l'Honneur Elfique Traqueur des Ombres."},"warriors-of-the-white-tower":{"name":"Warriors of the White Tower","desc":"Une unité ayant cette règle (Maîtres-Épées) ne peut être rejointe que par un Mage Haut Elfe ou par un personnage ayant l'Honneur Elfique Gardien de Saphery ou Maître du Savoir."},"warriors-of-chrace":{"name":"Warriors of Chrace","desc":"Armée Chracienne : les unités de Lanciers Elfes ou d'Archers Elfes peuvent prendre la règle spéciale Cape de Lion pour +10 pts par unité."},"chracian-pride":{"name":"Chracian Pride","desc":"Armée Chracienne : les personnages pouvant prendre un Honneur Elfique ne peuvent choisir que Traqueur des Ombres, Chasseur Chracien ou Cœur Pur (les Chefs Chraciens comptent comme ayant Chasseur Chracien pour rejoindre les Lions Blancs)."},"hidden-trails":{"name":"Hidden Trails","desc":"Armée Chracienne : 0-1 unité de Lanciers/Archers Elfes par tranche de 1 000 pts peut prendre Déplacement à Couvert (+1 pt/figurine) ; une fois par partie, vous pouvez appliquer +1/-1 à un jet d'arrivée d'Embusqués."},"warriors-of-the-wilderness":{"name":"Warriors of the Wilderness","desc":"Armée Chracienne : après la mise en place du décor, le joueur peut placer un bois supplémentaire (3-9 ps), n'importe où en dehors de la zone de déploiement adverse et à plus de 6 ps d'un élément spécial (peut être à moins de 12 ps du centre)."},"armies-of-the-sea-lord":{"name":"Armies of the Sea Lord","desc":"Garnison des Gardes Maritimes : les personnages pouvant prendre un Honneur Elfique ne peuvent choisir que Traqueur des Ombres, Cœur Pur ou Garde Maritime."},"from-the-mists":{"name":"From the Mists","desc":"Garnison des Gardes Maritimes : après le déploiement (avant les Éclaireurs/l'Avant-garde), retirez une unité amie déployée et replacez-la n'importe où dans votre zone de déploiement."},"from-the-storm-clouds":{"name":"From the Storm Clouds","desc":"Garnison des Gardes Maritimes : 0-1 Faucheur Céleste de Lothern par tranche de 1 000 pts (montures de personnages comprises) peut prendre Embusqués pour +10 pts/figurine."},"old-world-rangers":{"name":"Old World Rangers","desc":"Garnison de la Garde de la Mer : 0-1 unité de Guerriers de l'Ombre (Puissance d'Unité de 10 ou moins) peut prendre Embusqués gratuitement."},"pride-of-the-fleet":{"name":"Pride of the Fleet","desc":"Garnison des Gardes Maritimes : les unités de Gardes Maritimes gagnent Unité Régimentaire ; 0-1 unité de Gardes Maritimes par tranche de 1 000 pts peut prendre Entraînés gratuitement."},"unity-and-harmony":{"name":"Unity & Harmony","desc":"Toute unité de Guerriers de Jade ou de Lanciers de Jade située à moins de 3 ps d'une unité Mercenaire amie peut relancer ses jets pour toucher de 1 lors de la phase de Combat."},"implacable":{"name":"Implacable","desc":"Une fois par partie, lors d'un tour où elle a été chargée, cette figurine peut choisir de ne pas Céder du Terrain si elle perd le combat. Une fois par partie, elle peut aussi relancer son jet de Charge."},"defensive-stance":{"name":"Defensive Stance","desc":"Sauf si elle a chargé (ou compte comme ayant chargé) ce tour-ci, cette unité peut relancer ses jets de 1 naturels sur ses sauvegardes d'armure lors de la phase de Combat."},"the-elemental-winds":{"name":"The Elemental Winds","desc":"À chaque Début de Tour, lancez un D6 : sur 1-2 rien ; sur 3-4 les Vents de Yang (portée des sorts de Dissipation/Enchantement du Domaine de Yang +3 ps ; les figurines ayant la Volonté des Dragons gagnent +1 M ou +1 I) ; sur 5-6 les Vents de Yin (portée des Maléfices/Projectiles Magiques du Domaine de Yin +3 ps ; +1 CC ou +1 Cd). Toutes les figurines éligibles gagnent le même modificateur."},"dragon-form":{"name":"Dragon Form","desc":"Sous sa forme de Dragon, un Dragon Cathayen est un personnage du type de troupe béhémoth, mais ne bénéficie pas de la Présence Charismatique même s'il est le Général."},"human-form":{"name":"Human Form","desc":"Sous sa forme humaine, un Dragon Cathayen est un personnage du type de troupe infanterie lourde."},"transformation":{"name":"Transformation","desc":"Lors de la sous-phase de Commandement, un Dragon Cathayen peut passer de sa forme Humaine à sa forme Dragon (placé à moins de 6 ps, à plus de 1 ps des alliés et 3 ps des ennemis), récupérant D3 Points de Vie. Il ne peut pas charger ce tour-ci, compte comme s'étant déplacé, quitte son unité et peut quitter un combat en se transformant."},"transformation-of-the-dragon":{"name":"Transformation of the Dragon","desc":"Un Dragon Cathayen possède une forme humaine et une forme de Dragon, chacune avec son propre profil ; choisissez la forme de départ lors du déploiement."},"death-of-a-dragon":{"name":"Death of a Dragon","desc":"Les Points de Vie sont comptabilisés sur les deux profils. La première fois qu'il tombe à zéro PV sous sa forme de Dragon, il reprend sa forme humaine et récupère D3 PV (et ne peut plus reprendre la forme de Dragon). S'il tombe à zéro PV sous sa forme humaine, il est retiré du jeu."},"disdain-of-the-dragons":{"name":"Disdain of the Dragons","desc":"Toute figurine ennemie souhaitant lancer un défi à portée de Commandement de Miao Ying doit réussir un test de Commandement (avec +1/+2 si elle est en forme Humaine/Dragon et engagée dans le même combat) ; ses propres défis ne peuvent être refusés."},"discipline-of-the-dragon":{"name":"Discipline of the Dragon","desc":"Une fois par partie, lors de la sous-phase de Commandement, chaque Lanterne Céleste peut réussir un test de Commandement pour accorder une Grande Stratégie aux unités Cathayennes amies à moins de 12 ps jusqu'à votre prochain Début de Tour : Défi (Tenace, ou Indéboulonnable si déjà Tenace), Force de l'Empire Éternel (l'infanterie et la cavalerie ne peuvent être blessées sur un jet pour blesser de 2), ou Furie de la Lame Tombante (l'infanterie ordinaire gagne +1 Mouvement et relance ses jets de Charge, de Fuite et de Poursuite)."},"grand-strategist":{"name":"Grand Strategist","desc":"Sauf si elles fuient, les unités amies à portée de Commandement (hormis le Général) peuvent utiliser le Commandement de ce personnage ; une fois par tour, une unité qui remporte un combat à portée de Commandement peut effectuer un Repli en Bon Ordre au lieu de suivre ou de poursuivre."},"cathayan-black-powder":{"name":"Cathayan Black Powder","desc":"La première fois qu'une unité de la Flotte de Jade armée d'une arquebuse, d'un pistolet, d'une paire de pistolets ou d'une arme à répétition tire, la portée de cette arme est augmentée de 3 ps."},"granite-sentinel":{"name":"Granite Sentinel","desc":"+1 à la valeur d'armure, et insensibilité à Blessures Multiples (X) : une blessure non sauvegardée d'une telle attaque ne coûte qu'un seul Point de Vie."},"jade-sentinel":{"name":"Jade Sentinel","desc":"Connaît un sort de Magie de Bataille ou d'Élémentalisme (choisi avant le déploiement) et le lance en tant que sort lien, Niveau de Puissance 3."},"obsidian-sentinel":{"name":"Obsidian Sentinel","desc":"Possède Résistance à la Magie (-2). Tout Sorcier ennemi lançant un sort à moins de 12 ps doit réussir un test de Commandement, sous peine de subir -3 à son jet pour lancer (-1 en cas de réussite)."},"terracotta-sentinel":{"name":"Terracotta Sentinel","desc":"Bénéficie de la règle spéciale Régénération (6+)."},"warpstone-sentinel":{"name":"Warpstone Sentinel","desc":"Bénéficie d'Attaques Magiques ; les unités ennemies au contact socle à socle subissent -1 en Endurance (minimum 1)."},"wrath-of-the-storm":{"name":"Wrath of the Storm","desc":"Tous les Guerriers de Jade et Lanciers de Jade d'une armée menée par Miao Ying gagnent Haine (Guerriers du Chaos et figurines Démoniaques)."},"enough-for-everyone":{"name":"Enough for Everyone","desc":"Si un Chargeur Ogre possède des bombes à poudre, l'équipage de sa machine de guerre en possède également."},"mastery-of-the-storm-winds":{"name":"Mastery of the Storm Winds","desc":"Miao Ying peut écarter jusqu'à deux sorts générés aléatoirement (au lieu d'un seul) et les remplacer par des sorts du Domaine de Yang/Yin, son sort de prédilection, ou la Furie du Dragon de la Tempête (Projectile Magique, 10+, 18 ps, 2D3 touches de Force 5 avec AP -3 et Attaques Enflammées, puis la cible doit Céder du Terrain)."},"mercenary-crew":{"name":"Mercenary Crew","desc":"Un Chargeur Ogre rejoint une machine de guerre Cathayenne (qu'il ne peut quitter). Son équipage gagne +1 Mouvement et Tenace ; une fois par partie, une Batterie de Roquettes Pluie de Feu ou un Grand Canon doté d'un Chargeur Ogre peut tirer deux fois ou relancer un dé d'Artillerie."},"mercenary-handgun-drill":{"name":"Mercenary Handgun Drill","desc":"Une fois par partie, chaque unité ou détachement de Tireurs d'État dans une armée de la Flotte de Jade peut tirer avec un rang supplémentaire."},"supreme-matriarch-of-nan-gau":{"name":"Supreme Matriarch of Nan-Gau","desc":"Si l'armée inclut Miao Ying, elle doit être le Général ; 0-1 unité de Guerriers de Jade ou de Lanciers de Jade peut être améliorée en Garde du Dragon Céleste (+2 pts/figurine : +1 CC, +1 Cd, Armure Céleste (6+))."},"wailing-spirits":{"name":"Wailing Spirits","desc":"Toute unité subissant une ou plusieurs blessures non sauvegardées de cette arme doit effectuer un test de Panique comme si elle avait subi de lourdes pertes."},"war-balloons":{"name":"War Balloons","desc":"0-1 Lanterne Céleste par tranche de 1 000 pts peut prendre Embusqués (+15 pts) ; une fois par partie, une Lanterne Céleste en réserve peut relancer son jet d'arrivée."},"warriors-of-the-field":{"name":"Warriors of the Field","desc":"Les unités de Levée Paysanne ne sont pas Désorganisées par un terrain difficile ou dangereux ; 0-1 unité par tranche de 1 000 pts peut prendre Traverse les Couverts (+20 pts)."},"warriors-of-the-land":{"name":"Warriors of the Land","desc":"Quand une unité de Levée Paysanne effectue un Repli en Bon Ordre, elle peut choisir quel dé écarter lors de son jet de Fuite (au lieu du plus bas)."},"warriors-of-the-wind":{"name":"Warriors of the Wind","desc":"0-1 unité de Levée Paysanne par tranche de 1 000 pts peut prendre Mouvement de Réserve et Éclaireurs (+2 pts/figurine)."},"thunderous-impact":{"name":"Thunderous Impact","desc":"Jusqu'à votre prochain Début de Tour, toute unité située à moins de 2D6 ps du point d'impact d'un grand canon cathayen subit -1 en Mouvement et ne peut pas utiliser le Pas Vif."},"tower-shields":{"name":"Tower Shields","desc":"Un pavois améliore la valeur d'armure de 3 (au lieu de 1) contre les attaques provenant de l'arc frontal, mais n'offre aucune protection contre les attaques de flanc ou d'arrière."},"ancestral-fury":{"name":"Ancestral Fury","desc":"Dans une armée de Clan Royal, une figurine ayant effectué un mouvement de charge de 3 ps ou plus, ou un mouvement de poursuite, gagne +1 en Force ce tour-ci."},"stoic-defenders":{"name":"Stoic Defenders","desc":"Lors d'un tour où elle a été chargée, une figurine ayant cette règle gagne +1 en Initiative et +1 Attaque."},"striking-a-grudge":{"name":"Striking a Grudge","desc":"Après le déploiement, désignez un personnage ennemi : toutes les figurines amies gagnent la Haine contre lui, et vous remportez 75 PV bonus s'il est tué, en fuite ou s'est enfui à la fin de la partie."},"grudgelore":{"name":"Grudgelore","desc":"Une fois que Thorgrim a posé la Pierre des Rancunes, lui et son unité remplacent la Haine (Orques & Gobelins) par la Haine (tous les ennemis)."},"the-grudgestone":{"name":"The Grudgestone","desc":"Lors de n'importe quel Début de Tour, Thorgrim peut poser la Pierre des Rancunes : lui et son unité gagnent Indéboulonnable et réussissent automatiquement leurs tests de Panique, mais ne peuvent pas choisir de Fuir comme réaction de charge et ne peuvent se déplacer autrement que par Céder du Terrain, poursuite ou reformation."},"venerable":{"name":"Venerable","desc":"Sauf si elles fuient, les unités amies à moins de 6 ps peuvent relancer un test de Panique raté."},"wards-of-grimnir":{"name":"Wards of Grimnir","desc":"Une unité de Horde de Tueurs dotée d'un porte-étendard peut acheter les Bannissements de Grimnir (+1 pt/figurine) : sauvegarde invulnérable de 6+ contre les blessures non magiques subies lors de la phase de Tir."},"troll-hunters":{"name":"Troll Hunters","desc":"0-1 personnage par tranche de 1 000 pts dans une Horde de Tueurs (sauf Ungrim) peut prendre Éclaireurs pour +10 pts."},"king-of-the-slayer-hold":{"name":"King of the Slayer Hold","desc":"Ungrim peut rejoindre les Marteleurs ou les Tueurs (malgré Solitaire) ; une unité de Marteleurs qu'il rejoint gagne Insensible à la Psychologie et Indéboulonnable. En tant que Général de Clan Royal, il débloque les Tueurs de Démons/Dragons comme Personnages, les Tueurs comme Base et les Chercheurs de Mort comme Spéciaux."},"royal-guard":{"name":"Royal Guard","desc":"Une unité de Marteliers par Roi/Thane. Une unité de Marteliers rejointe par un Roi ou un Thane peut lancer et accepter des défis comme un personnage (capacité perdue s'il quitte l'unité)."},"first-to-the-fray":{"name":"First to the Fray","desc":"Cette figurine augmente de 3 ps sa portée de charge maximale et peut ajouter +D3 à son jet de charge."},"fight-me":{"name":"\"Fight Me!\"","desc":"Toute figurine ayant cette règle peut lancer et accepter des défis comme un personnage."},"whirlwind-of-death":{"name":"Whirlwind of Death","desc":"Les Touches d'Impact utilisent le profil de ses lames tourbillonnantes ; un jet pour blesser de 4+ réussit toujours, quelle que soit l'Endurance."},"whirling-doom":{"name":"Whirling Doom","desc":"Faucheuse à Gobelins : lancez un dé d'Artillerie + D3 pour le nombre de tirs (par rang dans l'arc avant/arrière, par file dans l'arc de flanc). Incident = aucun tir, lancez sur la table d'Incident de Tir."},"from-the-wilds":{"name":"From the Wilds","desc":"0-1 unité de Tueurs (Puissance d'Unité de 10 ou moins) dans une Horde de Tueurs peut prendre Embusqués et Tirailleurs pour +1 pt/figurine."},"prepared-positions":{"name":"Prepared Positions","desc":"Lors du déploiement, retranchez une machine de guerre sans personnage et une unité d'Arbalétriers/Fusiliers (couvert partiel + obstacle bas). Avantage perdu si elles bougent."},"range-finding-optics":{"name":"Range Finding Optics","desc":"Burlok : une fois par tour, une unité amie d'Arbalétriers/Fusiliers ou une machine de guerre naine à portée de Commandement peut relancer ses 1 pour toucher ou un dé d'Artillerie ; Burlok et son unité ignorent le malus de -1 pour toucher à longue portée."},"expeditionary-marksmen":{"name":"Expeditionary Marksmen","desc":"0-1 unité de Fusiliers par tranche de 1 000 pts améliorée (+1 pt/figurine) ne subit pas le malus pour toucher en cas de Mouvement & Tir ; tout Ingénieur peut également être amélioré (+10 pts)."},"function-over-form":{"name":"Function Over Form","desc":"Vous pouvez réduire de 1 l'Endurance d'un Canon/Orgue de Barbarie/Canon à Flammes (minimum 1) ; une machine de guerre ainsi réduite perd aussi Mouvement ou Tir."},"worst-among-equals":{"name":"Worst Among Equals","desc":"Ungrim doit être Général s'il est présent ; sinon, un Tueur de Démons/Dragons est Général (malgré Solitaire), mais un Tueur-Général de Horde de Tueurs ne bénéficie pas de la Présence Charismatique."},"riches-and-heirlooms":{"name":"Riches & Heirlooms","desc":"Les personnages peuvent dépenser +25 points en runes, et les unités pouvant acheter des runes d'Étendard peuvent y consacrer +25 points (sauf les Guerriers du Clan Royal)."},"dive-bomb":{"name":"Dive Bomb","desc":"Une fois par partie, lors des Mouvements Restants, une unité volante peut survoler un ennemi non engagé : il subit D6 touches de Force 3 avec AP -1 par figurine l'ayant survolé (chaque 1 naturel cause un incident et coûte un Point de Vie à cette unité)."},"bugmans-cart":{"name":"Bugman's Cart","desc":"Lors de la sous-phase de Commandement, toute unité naine ne fuyant pas et non engagée à moins de 6 ps d'un Chariot de Bugman ami gagne +1 en Mouvement jusqu'à la fin du tour (non cumulable)."},"miners-cart":{"name":"Miner's Cart","desc":"Toute unité Naine à moins de 3 ps d'un Chariot de Mineurs ami peut effectuer une réaction de charge Tenir la Position & Tirer et/ou une attaque de tir comme si elle était armée de Charges Explosives. Quand le Chariot perd son dernier Point de Vie au combat, sur 4+ il explose (tout ce qui se trouve à moins de 3 ps subit D6 touches de Force 3, AP -1, Enflammées)."},"look-snorri-trolls":{"name":"\"Look Snorri, Trolls!\"","desc":"Après le déploiement (avant les Éclaireurs/l'Avant-garde), les unités de Tueurs et de Confrérie de Grimnir dans une Horde de Tueurs peuvent effectuer un mouvement de D3+1 ps (peut manœuvrer, sans marche)."},"abyssal-howl":{"name":"Abyssal Howl","desc":"Tant qu'elles se trouvent à moins de 6 ps de cette figurine, les unités ennemies subissent -1 Commandement (minimum 2). Non cumulable."},"cry-of-war":{"name":"Cry of War","desc":"Les unités ennemies subissent -1 Commandement tant qu'elles sont à portée de Commandement d'une ou plusieurs Mégères de la Mort ne fuyant pas et ayant cette règle."},"dance-of-death":{"name":"Dance of Death","desc":"Si cette unité réussit une charge (entre en contact avec sa cible), la cible subit -1 à son Bonus de Rang maximal jusqu'à la fin de cette phase de Combat."},"manbane":{"name":"Manbane","desc":"Quand ce personnage effectue un jet pour blesser, un 4+ est toujours une réussite quelle que soit l'Endurance de la cible."},"dark-venom":{"name":"Dark Venom","desc":"Ce personnage bénéficie de la règle spéciale Coup Fatal."},"hidden-dark-elves":{"name":"Hidden (Dark Elves)","desc":"Un Assassin Khainite débute caché au sein d'une unité d'infanterie Elfe Noire amie (Puissance d'Unité 10+, hors Harpies) et peut être révélé lors de n'importe quel Début de Tour ou au début de toute phase de Combat, placé comme un personnage rejoignant une unité. Si l'unité hôte est détruite ou fuit auparavant, l'Assassin est perdu. Il ne peut pas être le Général."},"cursed-coven":{"name":"Cursed Coven","desc":"Une unité de Sorciers du Feu Maudit connaît un sort de Magie Noire ou de Démonologie (choisi avant le déploiement) et le lance en tant que sort lien : Niveau de Puissance 2 (Puissance d'Unité 10+ avec un Maître), 1 (Maître mais Puissance d'Unité de 9 ou moins), ou 0 sinon."},"forbidden-poisons":{"name":"Forbidden Poisons","desc":"Un Assassin Khainite peut prendre un poison interdit : Lotus Noir (les personnages ennemis blessés subissent -1 en Cd pour la partie), Venin Noir (Coup Fatal) ou Fléau des Hommes (jet pour blesser de 4+ toujours réussi)."},"gifts-of-khaine":{"name":"Gifts of Khaine","desc":"Une Hag de la Mort peut prendre un don : Cri de Guerre (-1 en Cd aux ennemis à portée de Commandement), Rune de Khaine (Attaques Supplémentaires +D3) ou Bière de Sorcière (ne peut pas perdre la Frénésie)."},"witchbrew":{"name":"Witchbrew","desc":"Ce personnage, sa monture et toute unité qu'il rejoint ne peuvent pas perdre la règle spéciale Frénésie."},"rune-of-khaine":{"name":"Rune of Khaine","desc":"Ce personnage bénéficie de la règle spéciale Attaques Supplémentaires (+D3)."},"black-lotus":{"name":"Black Lotus","desc":"Pour chaque blessure non sauvegardée infligée par ce personnage, les personnages ennemis subissent -1 Commandement pour le reste de la partie."},"goad-beast":{"name":"Goad Beast","desc":"Lors de la sous-phase de Commandement, ce personnage peut aiguillonner un monstre ami (y compris sa propre monture) à portée de Commandement : jusqu'à la fin du tour, cette figurine gagne +D3 Attaques (maximum 10)."},"wilful-beast":{"name":"Wilful Beast","desc":"Lors du Début de Tour, cette figurine effectue un test de Commandement (avec son propre Cd non modifié) ; en cas d'échec, sa monture devient Frénétique jusqu'au prochain Début de Tour (le cavalier ne gagne pas le +1 Attaque)."},"daemonic-alignment":{"name":"Daemonic Alignment","desc":"Indique le dieu d'un Démon (Khorne/Nurgle/Slaanesh/Tzeentch). Une figurine a au plus un Alignement ; toutes les figurines d'une unité partagent le même ; un personnage ayant un Alignement ne peut rejoindre qu'une unité du même Alignement ou sans Alignement."},"daemonic-locus":{"name":"Daemonic Locus","desc":"Les unités amies du même Alignement Démoniaque situées à moins de 12 ps réduisent de 1 les blessures dues à l'Instabilité Démoniaque, et sur un test d'Instabilité réussi par un double 6 naturel elles ne sont pas retirées mais perdent un nombre de Points de Vie égal à l'écart d'échec."},"chaos-armour-daemons-of-chaos":{"name":"Chaos Armour (Daemons of Chaos)","desc":"Cette figurine bénéficie d'une sauvegarde invulnérable de 4+ contre toute blessure subie ; un Sorcier ayant cette règle peut porter une armure sans malus."},"brazen-wheels":{"name":"Brazen Wheels","desc":"Les Attaques d'Écrasement d'un Canon à Crânes de Khorne ont un AP de -3 (sauf contre les béhémoths)."},"plague-proboscis":{"name":"Plague Proboscis","desc":"+1 en Initiative (s'applique uniquement aux Mouches de la Putréfaction, pas à leurs cavaliers)."},"slime-trail":{"name":"Slime Trail","desc":"Les unités ennemies ne peuvent réclamer aucun point de résultat de combat bonus pour être engagées dans l'arc de flanc ou d'arrière de cette unité."},"cannonade":{"name":"Cannonade","desc":"Quand vous tirez avec une canonnade à vapeur, lancez deux dés d'Artillerie avant le jet pour toucher ; le nombre de tirs est égal à leur total. Sur un Incident de Tir : tous les tirs subissent -1 pour toucher. Sur deux Incidents de Tir : aucun tir et la figurine perd un Point de Vie (pas de table des Incidents de Tir)."},"carriage-hauler":{"name":"Carriage Hauler","desc":"Lors de la phase de Mouvement, jusqu'à deux machines de guerre « Chariot à Vapeur » amies entièrement dans l'arc arrière de cette figurine et à moins de 8 ps peuvent se déplacer avec elle (terminant dans la même zone) ; sauf si elle utilise Destruction Lourde ou charge, ces machines de guerre ne comptent pas comme s'étant déplacées."},"hellbound":{"name":"Hellbound","desc":"Une figurine Damnée bénéficie d'une sauvegarde invulnérable de 6+ contre les attaques non magiques et gagne la Peur et les Attaques Magiques (ou la Terreur si elle avait déjà la Peur). Une fois par partie, elle peut relancer un dé de Déviation ou d'Artillerie, mais subit -1 sur tout jet sur une table des Incidents de Tir."},"lumbering-destruction":{"name":"Lumbering Destruction","desc":"Un Démon de Fer ne peut pas marcher ; à la place, lancez un D6 et ajoutez-le à son Mouvement. Sur un 1 naturel, la machine se grippe : elle s'arrête immédiatement et ne peut plus bouger ce tour-ci."},"quake":{"name":"Quake","desc":"Jusqu'à votre prochain Début de Tour, toute unité (amie ou ennemie) située à moins de 2D6 ps du trou central du gabarit d'explosion (après déviation) subit -1 en Mouvement et ne peut pas utiliser le Pas Vif."},"quell-panic":{"name":"Quell Panic","desc":"Sauf si elle fuit, toute unité amie à moins de 6 ps possédant la règle spéciale Levée peut relancer un test de Panique raté."},"skullcracker":{"name":"Skullcracker","desc":"Un Démon de Fer doté d'un Broie-Crânes remplace ses Touches d'Impact (D6+1) par des Touches d'Impact (2D6+2) et gagne Arme Perforante (1)."},"slow-reload":{"name":"Slow Reload","desc":"Si cette arme a tiré lors de votre tour précédent, lancez un D6 avant de tirer : sur 1-2 elle ne tire pas ce tour-ci (rechargement inachevé). Un Mortier Tremble-Effroi doté d'un Chargeur Ogre applique +1 à ce jet."},"stampede":{"name":"Stampede","desc":"Les Touches d'Impact causées par une figurine ayant cette règle ont un AP de -2."},"backstab":{"name":"Coup dans le Dos","desc":"Si une unité ayant cette règle est engagée contre le flanc ou l'arrière d'une unité ennemie, elle peut relancer ses jets pour toucher ratés contre cette unité."},"blazing-body":{"name":"Corps Enflammé","desc":"La chair de cette créature brûle de l'intensité d'une fournaise, l'enveloppant de fumée noire et de braises ardentes. Au début de chaque phase de Combat, toute figurine (amie ou ennemie) au contact socle à socle qui n'a pas elle-même cette règle subit une touche de Force 3 (AP -, Attaques Enflammées). Les Points de Vie perdus à cause de ces touches ne comptent pas pour le résultat de combat."},"hailfire":{"name":"Hailfire!","desc":"Une unité ayant cette règle peut effectuer un Tir en Salve lors d'un tour où elle a bougé, ou en réaction de charge Tenir la Position & Tirer."},"relentless-march":{"name":"Relentless March","desc":"Lors de la sous-phase de Commandement, ce personnage peut effectuer un test de Commandement ; en cas de réussite, une unique unité d'Infanterie ou de Cavalerie amie à portée de Commandement gagne +D3 en Mouvement (maximum 10). Non cumulatif sur la même unité au même tour."},"infernal-taskmaster":{"name":"Infernal Taskmaster","desc":"Une fois par partie, lors de la sous-phase de Commandement, ce personnage peut effectuer un test de Commandement (avec son propre Cd) ; en cas de réussite, jusqu'à votre prochain Début de Tour, ce personnage et l'unité qu'il a rejointe gagnent les Attaques Supplémentaires (+1) et la Haine (tous les ennemis)."},"indentured-crew":{"name":"Indentured Crew","desc":"L'équipage d'une machine de guerre rejointe par un Chargeur Ogre gagne +1 en Mouvement et la règle Obstiné. De plus, une fois par partie, une machine de guerre incluant un Chargeur Ogre peut tirer deux fois en phase de Tir, ou relancer un dé d'artillerie."},"bestial-charge":{"name":"Bestial Charge","desc":"Lors d'un tour où elle a effectué un mouvement de charge de 3 ps ou plus, une figurine ayant cette règle gagne +1 en Force."},"champions-of-slaughter":{"name":"Champions of Slaughter","desc":"Si le Général d'une Horde Sanglante de Minotaures devient Frénétique par la Rage Sanglante, les unités amies à portée de son Commandement deviennent également Frénétiques."},"bloodshed-and-butchery":{"name":"Bloodshed & Butchery","desc":"Tous les Taureaux de la Mort, Taureaux du Sang, Hordes de Minotaures et Hordes de Gors dans une armée de Horde Sanglante de Minotaures gagnent la règle spéciale Impétueux."},"spurting-bile-blood":{"name":"Spurting Bile Blood","desc":"Pour chaque Point de Vie que cette figurine perd lors de la phase de Combat, l'unité ennemie qui l'a attaquée subit une touche de Force 4 avec AP -1."},"maddening-aura":{"name":"Maddening Aura","desc":"Lors de la sous-phase de Commandement, chaque unité ennemie à moins de 8 ps (même en fuite ou engagée) effectue un test de Commandement, sous peine de subir D3 touches de Force 3 sans sauvegarde d'armure ni de Régénération (la sauvegarde invulnérable reste permise)."},"swallow-whole":{"name":"Swallow Whole","desc":"Lors de la sous-phase de Commandement, un Ghorgon engagé contre de l'infanterie normale ou lourde peut imposer un test d'Initiative à une unité cible : en cas d'échec, une figurine est retirée et le Ghorgon récupère 1 Point de Vie par figurine dévorée."},"eadbutt-giant":{"name":"'Eadbutt (Giant)","desc":"Attaque de Géant : désignez une figurine dans un rang combattant ennemi ; elle subit D3+1 blessures sans sauvegarde d'armure ni de Régénération (la sauvegarde invulnérable reste permise)."},"belly-flop":{"name":"Belly Flop","desc":"Attaque de Géant : placez un gabarit d'explosion de 3 ps centré sur l'unité cible ; chaque figurine recouverte subit une touche à la Force du Géant avec AP -2."},"mighty-swing-giant":{"name":"Mighty Swing (Giant)","desc":"Attaque de Géant : le Géant gagne Attaques Aléatoires avec D6+1 Attaques ; sa massue est de Force F+1 avec AP -2."},"thump-with-club":{"name":"Thump with Club","desc":"Attaque de Géant : un unique coup de massue puissant porté contre la cible (Force élevée, AP) - voir l'entrée Attaques de Géant pour le profil exact."},"jump-up-and-down":{"name":"Jump Up & Down","desc":"Attaque de Géant : le Géant piétine la cible à plusieurs reprises, infligeant de multiples touches de Force élevée - voir l'entrée Attaques de Géant."},"endless-malice":{"name":"Endless Malice","desc":"Si cette figurine remporte un round de combat et choisit de se retenir et de se reformer (en réussissant son test de Commandement), les unités ennemies à moins de 6 ps doivent effectuer un test de Panique comme si une unité amie proche avait été détruite."},"soul-eater":{"name":"Soul-eater","desc":"Tout Sorcier ennemi souhaitant lancer un sort à moins de 12 ps d'un Cygor doit d'abord réussir un test de Commandement ; en cas d'échec, si le sort échoue ensuite à être lancé, il y a incident magique (lancez sur la table d'Incident Magique)."},"ghostsight":{"name":"Ghostsight","desc":"Lors de la phase de Combat, un Cygor peut relancer ses jets pour toucher ratés contre les Sorciers ennemis, les figurines/unités dotées d'objets magiques, ou les figurines/unités disposant d'une sauvegarde invulnérable ou de Régénération."},"storm-call":{"name":"Storm Call","desc":"Sort lien (Niveau de Puissance 1, lançable même en étant engagé) : Projectile Magique, Soi-même, valeur de lancement 7+. S'il est lancé, toutes les unités à moins de 6 ps (amies ou ennemies, y compris au combat) subissent D3 touches de Force 4 avec un AP de -1."},"the-quickening-storm":{"name":"The Quickening Storm","desc":"Sauvegarde invulnérable de 5+ contre les blessures causées par un Projectile Magique ou un Vortex Magique. Si la figurine est touchée par Appel de l'Orage, elle devient Galvanisée : +1 Initiative et +1 Attaque jusqu'à votre prochain Début de Tour."},"dark-coven":{"name":"Dark Coven","desc":"Un Chamane-brai/Grand Chamane-brai dans une armée de Horde Sauvage peut appliquer +1 à un jet pour lancer ou de dissipation si un Sorcier ami ne fuyant pas et non stupide se trouve à portée de Commandement ; sur un double 1 naturel, tous ces Sorciers lancent sur la table d'Incident Magique."},"ancient-sorcery":{"name":"Ancient Sorcery","desc":"Les Chamanes des Hommes-bêtes dans une armée de Horde Sauvage peuvent aussi connaître des sorts du Domaine de la Magie Primordiale, en plus de leurs Domaines habituels."},"magics-of-the-dark-gods":{"name":"Magics of the Dark Gods","desc":"Le Général d'une Horde de Sang de Minotaures (Taureau de la Mort/Taureau de Sang) peut devenir un Sorcier de Niveau 1 (+35) ou de Niveau 2 (+65) connaissant la Magie de Bataille ou la Magie Noire, et peut porter une armure sans pénalité."},"leering-spirit":{"name":"Leering Spirit","desc":"Placez un marqueur Esprit Lorgneur (à plus de 8 ps d'un ennemi) au déploiement de Kralmaw ; il ne peut être chargé ni ciblé, et est retiré si Kralmaw meurt. Lors de chaque phase de Tir de Kralmaw, il peut lancer Dévolution (Domaine des Bêtes) en tant que sort lien, Niveau de Puissance 3."},"herdstones":{"name":"Herdstones","desc":"Élément spécial infranchissable de 6 ps placé par le joueur Hommes-bêtes. Il est contrôlé par une unité amie ne fuyant pas, de Puissance d'Unité 5+, à moins de 6 ps. Une unité Hommes-bêtes qui le contrôle accorde des effets alentour : Résistance à la Magie (-1) ; relance des 1 pour blesser au corps à corps à moins de 12 ps ; +1 pour lancer aux Sorciers amis / -1 aux Sorciers ennemis à moins de 12 ps ; les ennemis à moins de 12 ps subissent -1 en Cd lors des tests de Peur/Panique/Terreur. Le contrôler à la fin de la bataille rapporte +200 Points de Victoire."},"guardians-of-the-herdstones":{"name":"Guardians of the Herdstones","desc":"Les Taureaux de la Mort et Taureaux du Sang dans une Horde Sanglante de Minotaures peuvent prendre des Mutations du Chaos et/ou des Dons du Chaos pour un total maximal de 50 points."},"blessings-of-chaos":{"name":"Blessings of Chaos","desc":"Quand le combat de cette unité est choisi (Étape 1.1), lancez un D6 : 1-2 Attaques Empoisonnées, 3-4 toutes les attaques gagnent AP -2, 5-6 +1 en Endurance - jusqu'à la fin de la phase de Combat."},"brayhorn":{"name":"Brayhorn","desc":"À partir du 2e round, si votre Général (un Seigneur des Bêtes/Wargor) est sur le champ de bataille lors de la sous-phase de Commandement, il peut réussir un test de Commandement pour relancer l'arrivée de chaque unité d'Embusqués encore en réserve qui n'est pas arrivée ce tour-ci."},"roaming-warbands":{"name":"Roaming Warbands","desc":"Dans une armée de Horde Sauvage, les Hordes de Gors, Ungors, Primitifs et Centigors peuvent prendre Embusqués (+1 pt/figurine), les Chefs peuvent la prendre (+10 pts), et 0-1 horde (Puissance d'Unité de 10 ou moins) par tranche de 1 000 pts peut la prendre gratuitement."},"the-sons-of-ghorros":{"name":"The Sons of Ghorros","desc":"0-1 horde de Centigors dans l'armée de Ghorros peut être améliorée en Fils de Ghorros (+2 pts/figurine) : +1 CC, +1 Cd et la règle spéciale Arme Perforante (1)."},"father-of-beasts":{"name":"Father of Beasts","desc":"Tant qu'elles sont à portée de Commandement de Ghorros Warhoof, les Hordes de Centigors amies peuvent relancer le D6 sur la table d'Ivresse."},"future-sight":{"name":"Future Sight","desc":"Kralmaw bénéficie d'une sauvegarde invulnérable de 4+ contre toute blessure subie."},"gifts-from-the-dark-gods":{"name":"Gifts from the Dark Gods","desc":"Les personnages de cette armée peuvent dépenser +25 points en objets magiques et +25 points en Mutations du Chaos."},"leader-of-the-pack-beastmen":{"name":"Leader of the Pack (Beastmen)","desc":"Les Ravageurs Ungors ayant cette règle rejoignent une unité de Molosses Primordiaux, occupant les rangs arrière tandis que les Molosses forment toujours le ou les rangs avant."},"assorted-weapons":{"name":"Assorted Weapons","desc":"L'équipage du Chariot de Guerre porte des armes variées (espingole, long fusil, fusil à répétition, boulet et chaîne, hallebarde à crochet, attrape-homme). Lors de la phase de Tir, chaque membre d'équipage doté d'une arme de tir peut tirer ; lors de la phase de Combat, chacun peut utiliser son arme particulière ou son arme de base. Lancez les dés par groupes séparés selon l'arme."},"big-guns-know-no-fear":{"name":"Big Guns Know No Fear","desc":"Les Ingénieurs de l'Empire dans une armée de Cité-État de Nuln (et toute unité qu'ils ont rejointe) gagnent Insensible à la Psychologie tant qu'une machine de guerre amie se trouve à portée de leur Commandement."},"entrenched-position":{"name":"Entrenched Position","desc":"Lors du déploiement, retranchez une machine de guerre sans personnage par Ingénieur de l'Empire : elle compte comme derrière un couvert partiel et comme défendant un obstacle linéaire bas. Si elle bouge pour quelque raison que ce soit, elle n'est plus retranchée."},"fanatical-zeal":{"name":"Fanatical Zeal","desc":"Une unité ayant cette règle (Flagellants) ne peut être rejointe que par un Lecteur de Sigmar ou un Prêtre de Sigmar ; un tel personnage est traité comme Indéboulonnable tant qu'il reste avec l'unité."},"feel-no-pain":{"name":"Feel No Pain","desc":"Une figurine ayant cette règle bénéficie d'une sauvegarde invulnérable de 6+ contre les blessures causées par des attaques ennemies non magiques, et de 5+ contre les attaques non magiques de Force 5 ou plus."},"grand-master-of-the-knights-panther":{"name":"Grand Master of the Knights Panther","desc":"Harald Gemunsen peut relancer un seul dé montrant un 1 naturel sur un jet de charge (avant de l'écarter). Il ne peut rejoindre qu'une unité de l'Ordre des Chevaliers Panthère."},"grinding-wheels":{"name":"Grinding Wheels","desc":"Les Attaques d'Écrasement de cette figurine disposent d'un AP de -2 (mais pas contre les béhémoths). Contrairement aux autres chars, elle traite les obstacles linéaires bas comme du terrain dégagé."},"guardians-of-the-temple":{"name":"Guardians of the Temple","desc":"Quand elle est engagée au combat, une figurine ayant cette règle peut relancer ses jets pour toucher montrant un 1 naturel."},"gun-limbers":{"name":"Gun Limbers","desc":"0-1 machine de guerre par tranche de 1 000 points (Grand Canon, Mortier, Orgue à Salves Helblaster ou Lance-roquettes Helstorm) peut recevoir les règles spéciales Avant-garde et Vétéran."},"handgun-drill":{"name":"Handgun Drill","desc":"Une fois par partie, chaque détachement de Tirailleurs d'État dans une armée de Cité-État de Nuln peut tirer avec un rang supplémentaire."},"helblaster":{"name":"Helblaster","desc":"Lancez trois dés d'Artillerie avant de jeter pour toucher ; le nombre de coups tirés est égal à leur total. Un Incident de Tir : tous les coups subissent un -1 supplémentaire pour toucher. Deux Incidents : aucun coup, lancez sur la table d'Incident de Tir. Trois Incidents : tire 30 coups puis est détruite (avec -1 pour toucher)."},"helstorm":{"name":"Helstorm","desc":"Aucune ligne de vue requise : choisissez une unité ennemie à portée et placez D3 gabarits d'explosion sur elle, puis faites dévier chacun (dés d'Artillerie + de Déviation). Un Incident de Tir signifie que la roquette ne décolle pas (lancez sur la table d'Incident de Tir). Les figurines sous un gabarit risquent d'être touchées."},"inner-circle":{"name":"Inner Circle","desc":"Quand elle est engagée au combat, une figurine ayant cette règle (mais pas sa monture) peut relancer ses jets pour toucher montrant un 1 naturel."},"the-knightly-orders":{"name":"The Knightly Orders","desc":"Composition d'armée des Ordres Chevaleresques : le Général doit être un Grand Maître ou un Maître de Chapitre d'un Ordre Chevaleresque ; tous les Maîtres de Chapitre et les Chevaliers de l'Empire/du Cercle Intérieur/Demigryphes doivent appartenir au même Ordre (Panthère, Loup Blanc, Soleil Flamboyant, Morr ou Cœur Ardent), chacun avec ses propres autorisations/restrictions."},"knights-of-morr":{"name":"Knights of Morr","desc":"Composition de l'Ordre : peut inclure des Seigneurs Sorciers et des Maîtres Mages comme personnages ; ne peut inclure aucun Lecteur/Prêtre de Sigmar ni aucun Grand Prêtre/Prêtre d'Ulric."},"knights-of-the-blazing-sun":{"name":"Knights of the Blazing Sun","desc":"Order composition: 0-2 Master Mages per 1,000 pts, and 0-1 Great Cannon or Mortar per 1,000 pts; cannot include Lectors of Sigmar or High Priests of Ulric."},"knights-of-the-fiery-heart":{"name":"Knights of the Fiery Heart","desc":"Composition d'Ordre : autant d'unités de Flagellants que voulu comme choix Rares ; ne peut inclure de Grands Prêtres ni de Prêtres d'Ulric."},"knights-of-the-white-wolf":{"name":"Knights of the White Wolf","desc":"Order composition: any number of Teutogen Guard as Special, and 0-1 Free Company Militia per 1,000 pts as Core; cannot include Lectors/Priests of Sigmar or Witch Hunters."},"knights-panther":{"name":"Knights Panther","desc":"Composition d'Ordre : 0-1 unité de Chevaliers de l'Empire/du Cercle Intérieur de l'Ordre du Loup Blanc comme choix Mercenaire, non soumise à la règle des Mercenaires Indisciplinés."},"mercenary-commander":{"name":"Mercenary Commander","desc":"Si Hans est le Général de l'armée, les unités Mercenaires amies bénéficient de sa Présence Charismatique, peuvent être rejointes par lui et ne sont pas soumises à la règle des Mercenaires Indisciplinés."},"prayer-of-the-damned":{"name":"Prayer of the Damned","desc":"Lors de la sous-phase de Commandement, effectuez un test de Commandement ; en cas de réussite, jusqu'à votre prochain Début de Tour, ce personnage et toute unité qu'il a rejointe gagnent une sauvegarde invulnérable de 6+ contre toutes les blessures et de 5+ contre les blessures causées au corps à corps par des ennemis ayant Peur ou Terreur."},"prayers-of-ulric":{"name":"Prayers of Ulric","desc":"Lors de la sous-phase de Commandement, effectuez un test de Commandement et entonnez une Prière : Hurlement de Bataille (+D3 aux jets de Charge de l'infanterie/cavalerie à portée de Commandement), Froid Hivernal (les ennemis doivent relancer leurs 6 naturels pour toucher cette figurine/unité au corps à corps), ou Courroux de l'Hiver (cette figurine et son unité gagnent Blessures Multiples (2)). Non cumulable."},"skilled-duellist":{"name":"Skilled Duellist","desc":"Si Harald Gemunsen tue un ennemi lors d'un défi pendant un tour où il a chargé, il peut immédiatement lancer un second défi, combattant ainsi deux défis dans un même round de combat."},"steam-power":{"name":"Steam Power","desc":"Un Char à Vapeur ne peut pas marcher ; à la place, vous pouvez effectuer un jet de Puissance Vapeur (lancez 2D6 et conservez le résultat le plus élevé) et l'ajouter à la caractéristique de Mouvement de la figurine."},"strategic-mastery":{"name":"Strategic Mastery","desc":"Dans les scénarios où les joueurs lancent un dé pour déterminer qui joue en premier, vous pouvez appliquer un modificateur de +1 ou -1 au résultat de votre jet."},"suffer-not":{"name":"Suffer Not...","desc":"Chaque Chasseur de Sorcières choisit une spécialisation accordant la Haine (et une autre règle) contre un type d'ennemi : La Sorcière (Haine des Sorciers ennemis + Résistance à la Magie -2), Le Revenant (Haine des Morts-Vivants + Attaques Enflammées), Le Mutant (Haine des Guerriers/Bêtes du Chaos + Résistance à la Magie -1), Le Démon (Haine des Démons + Attaques Magiques)."},"temperamental":{"name":"Temperamental","desc":"Si un 1 naturel est obtenu sur l'un des dés d'un jet de Puissance Vapeur ou de charge d'un Char à Vapeur, choisissez Boum ! (perdez 1 Point de Vie) ou Pfuiii ! (arrêt immédiat, plus aucun mouvement ce tour-ci). Un 1 naturel sur les deux dés = perte de 1 Point de Vie ET arrêt pour le tour."},"two-heads":{"name":"Two Heads","desc":"Un Griffon Impérial à Deux Têtes gagne un modificateur de +1 à sa caractéristique d'Attaques."},"veteran-outriders":{"name":"Veteran Outriders","desc":"Les armes de tir maniées par les Hussards dans une armée de Cité-État de Nuln ne sont pas soumises à la règle spéciale Pesant."},"zealot":{"name":"Zealot","desc":"Un personnage ayant cette règle ne peut rejoindre qu'une unité dotée de la règle spéciale Ferveur Fanatique."},"regimental-leadership":{"name":"Regimental Leadership","desc":"Un détachement à moins de 3 ps de son unité régimentaire (sauf si celle-ci fuit) peut utiliser le Commandement du régiment ; si le Commandement propre du détachement est plus élevé, il utilise le sien à la place."},"regimental-psychology":{"name":"Regimental Psychology","desc":"Un détachement situé à moins de 3 ps de son unité de régiment bénéficie de celles des règles spéciales suivantes que possède le régiment : Frénésie, Haine (X), Immunité à la Psychologie, Tenace."},"supporting-actions":{"name":"Supporting Actions","desc":"Quand un ennemi déclare une charge contre une unité de régiment qui ne fuit pas, chaque détachement situé à moins de 3 ps qui n'est ni engagé ni en fuite peut déclarer une Action de Soutien par tour : Tir de Soutien (tire sur l'unité qui charge comme lors d'un Tenir la Position & Tirer ; ses blessures comptent pour le résultat de combat) ou Charge de Soutien (contre-charge l'unité qui charge)."},"ambushers":{"name":"Ambushers","desc":"Cette unité peut être gardée en réserve plutôt que déployée. À partir du deuxième tour, lancez un D6 par unité en réserve à chaque Début de Tour : sur 1-3 elle reste en réserve, sur 4+ elle arrive en renfort pendant les Mouvements Obligatoires, placée sur un bord de table mais à plus de 8 ps d'une figurine ennemie."},"armour-bane":{"name":"Arme Perforante (X)","desc":"Si une figurine ayant cette règle obtient un 6 naturel sur son jet pour Blesser, la Pénétration d'Armure (PA) de son arme est améliorée de la valeur (X) indiquée entre parenthèses pour cette touche."},"armoured-hide":{"name":"Armoured Hide (X)","desc":"La peau naturelle de la créature améliore sa valeur de Sauvegarde d'Armure (et celle de son cavalier) du montant indiqué entre parenthèses. Une figurine sans armure compte comme ayant une valeur d'armure de 7+ pour ces règles."},"breath-weapon":{"name":"Arme Soufflante","desc":"Une fois par partie, au lieu d'attaquer normalement, la figurine projette son arme soufflante via un gabarit de souffle. Chaque figurine partiellement recouverte subit une touche automatique aux caractéristiques indiquées dans le profil."},"chariot-runners":{"name":"Chariot Runners","desc":"Les chars amis peuvent tracer leur ligne de vue par-dessus ou à travers ces figurines et se déplacer à travers les unités amies d'Escorteurs de Chars en formation dispersée. Si un char terminait sur un Escorteur, on écarte celui-ci. En formation dispersée, ils traitent les chars amis à moins de 1 ps comme faisant partie de l'unité pour la cohérence."},"close-order":{"name":"Close Order","desc":"Une unité composée de figurines ayant cette règle spéciale peut adopter une formation en Ordre Serré."},"counter-charge":{"name":"Counter Charge","desc":"Quand elle est chargée dans son arc avant par de la cavalerie, un char ou un monstre, l'unité peut déclarer une Contre-Charge : mesurez la distance ; si elle est inférieure au Mouvement de l'unité qui charge, elle doit Tenir la Position ou Fuir à la place. Sinon, elle pivote pour faire face à l'ennemi et avance de D3+1 ps vers lui. Les deux unités comptent comme ayant chargé. Impossible si l'unité fuit ou est déjà engagée. Une seule Contre-Charge par tour."},"cumbersome":{"name":"Cumbersome","desc":"Une arme ayant cette règle spéciale ne peut pas être utilisée lors d'une réaction de charge Tenir la Position & Tirer."},"detachment":{"name":"Detachment","desc":"Une unité ayant cette règle spéciale peut être alignée en tant que détachement."},"dragged-along":{"name":"Dragged Along","desc":"Une figurine ayant cette règle qui commence son mouvement à moins de 1 ps d'une unité amie d'infanterie qui ne fuit pas et compte au moins dix figurines peut remplacer sa caractéristique de Mouvement par celle de cette unité."},"drilled":{"name":"Drilled","desc":"Sauf si elle fuit, une unité Entraînée peut effectuer gratuitement un réalignement des rangs juste avant de se déplacer. Elle peut aussi marcher à moins de 8 ps d'une unité ennemie sans effectuer de test de Commandement. Tout personnage rejoignant une unité Entraînée est lui aussi considéré comme Entraîné."},"ethereal":{"name":"Ethereal","desc":"Les créatures Éthérées traitent tout terrain comme un terrain dégagé pour le mouvement, mais ne peuvent pas terminer leur mouvement dans un terrain infranchissable (bien qu'elles puissent le traverser). Elles ne peuvent être blessées que par des Attaques Magiques. Les personnages non Éthérés ne peuvent rejoindre des unités Éthérées, et vice versa."},"evasive":{"name":"Evasive","desc":"Une fois par tour, quand une unité dont la majorité des figurines ont cette règle est désignée comme cible lors de la phase de Tir ennemie, elle peut effectuer un Repli en Bon Ordre en fuyant droit à l'opposé de l'unité qui tire. Une fois le mouvement terminé, l'unité ennemie peut poursuivre son tir comme déclaré."},"extra-attacks":{"name":"Extra Attacks (+X)","desc":"Cette figurine bénéficie d'un modificateur à sa caractéristique d'Attaques indiqué entre parenthèses (+X). Si ce modificateur est déterminé par un dé, lancez-le quand le combat de la figurine est résolu lors de la sous-phase Choisir & Livrer les Combats."},"fast-cavalry":{"name":"Fast Cavalry","desc":"Si toutes les figurines d'une unité (personnages compris) en formation d'Ordre Dispersé ont cette règle spéciale, l'unité peut effectuer son Demi-tour Rapide même si elle a marché."},"fear":{"name":"Fear","desc":"Ces figurines causent la Peur. Une unité souhaitant charger un ennemi causant la Peur et ayant une Puissance d'Unité supérieure doit réussir un test de Commandement, sous peine de voir sa charge échouer. Une unité engagée avec un tel ennemi, lorsque le combat est choisi, doit réussir un test de Commandement, sous peine de subir -1 pour toucher contre lui. Un seul test de Peur par tour. Les figurines causant la Peur y sont immunisées."},"feigned-flight":{"name":"Feigned Flight","desc":"Si cette unité choisit de Fuir (ou Tirer & Fuir) comme réaction de charge, elle se rallie automatiquement à la fin de son mouvement."},"fight-in-extra-rank":{"name":"Fight in Extra Rank","desc":"Une figurine ayant cette règle spéciale peut effectuer des attaques de soutien."},"fire-and-flee":{"name":"Fire & Flee","desc":"Si la majorité des figurines d'une unité armée de projectiles ont cette règle, l'unité peut déclarer Tirer & Fuir comme réaction de charge : Tenir la Position & Tirer, puis fuir. En fuyant, lancez deux D6 et écartez le résultat le plus bas. Si la distance jusqu'à l'unité qui charge est inférieure au Mouvement de celle-ci, l'unité doit Tenir la Position ou Fuir à la place."},"first-charge":{"name":"First Charge","desc":"Si la première charge de la partie de cette unité est réussie (entre en contact avec sa cible), la cible devient Désorganisée jusqu'à la fin de la phase de Combat de ce tour."},"flaming-attacks":{"name":"Flaming Attacks","desc":"Les attaques et touches causées par cette figurine (ou une arme/un sort ayant cette règle) sont des Attaques Enflammées. Elles causent aussi la Peur chez les bêtes de guerre et les nuées. Sauf indication contraire, cela s'applique au tir comme au corps à corps."},"flammable":{"name":"Flammable","desc":"Une figurine ayant cette règle spéciale ne peut pas effectuer de sauvegarde de Régénération contre une blessure causée par une Attaque Enflammée."},"fly":{"name":"Fly (X)","desc":"Sauf en suivant ou en poursuivant, la figurine peut voler en utilisant son Mouvement de Vol (X) au lieu de se déplacer au sol. Les figurines volantes passent librement par-dessus les autres figurines, unités et terrains sans pénalité, et peuvent marcher à moins de 8 ps des ennemis sans test de Commandement. Elles peuvent terminer dans un terrain (en en subissant les effets) mais pas sur un terrain infranchissable, sur une autre unité, ni à moins de 1 ps d'un ennemi."},"frenzy":{"name":"Frenzy","desc":"Lors d'un tour où la figurine charge, ou au tour suivant un mouvement de poursuite, une figurine Frénétique gagne +1 Attaque (pas sa monture ni son cavalier). Si la majorité est Frénétique : l'unité réussit automatiquement ses tests de Peur, Panique et Terreur, doit déclarer une charge si possible, et ne peut ni choisir de Fuir comme réaction de charge ni faire de test de Retenue. La Frénésie est perdue immédiatement si l'unité perd un round de combat."},"furious-charge":{"name":"Furious Charge","desc":"Lors d'un tour où elle a effectué un mouvement de charge de 3 ps ou plus, cette figurine gagne un modificateur de +1 à sa caractéristique d'Attaques."},"hatred":{"name":"Hatred (X)","desc":"Une figurine ayant cette règle peut relancer tous ses jets pour toucher ratés contre un ennemi haï lors du premier round de combat. Les ennemis haïs sont indiqués entre parenthèses ; certaines figurines haïssent tous les ennemis."},"horde":{"name":"Horde","desc":"Une unité ayant cette règle spéciale peut augmenter de 1 le Bonus de Rang maximal qu'elle peut recevoir (déterminé par son type de troupe)."},"howdah":{"name":"Howdah","desc":"Un béhémoth ayant cette règle a un profil divisé et suit les règles de Profil Divisé (Chars) et de Plate-forme de Tir pour représenter son howdah blindé et son équipage. À tous les autres égards, il reste un béhémoth."},"ignores-cover":{"name":"Ignores Cover","desc":"Une figurine ayant cette règle qui effectue une attaque de tir ignore tout modificateur pour toucher dû à un couvert partiel ou total."},"immune-to-psychology":{"name":"Immune to Psychology","desc":"Si la majorité des figurines d'une unité sont Immunisées à la Psychologie, l'unité réussit automatiquement tous ses tests de Peur, Panique ou Terreur. En revanche, une telle unité ne peut pas choisir de Fuir comme réaction de charge. Cette règle ne confère aucune immunité aux autres tests de Commandement."},"impact-hits":{"name":"Impacts de Charge","desc":"Lors d'un tour où la figurine charge, elle inflige D6 touches automatiques de sa Force avant le début normal de la phase de Combat."},"impetuous":{"name":"Impetuous","desc":"Si une unité comprenant une ou plusieurs figurines Impétueuses peut déclarer une charge lors de la sous-phase Déclarer les Charges & Réactions de Charge, elle doit effectuer un test de Commandement. En cas d'échec, elle doit déclarer une charge. En cas de réussite, elle agit normalement."},"killing-blow":{"name":"Killing Blow","desc":"Si cette figurine obtient un 6 naturel sur son jet pour blesser au corps à corps, elle porte un Coup Fatal. L'infanterie et la cavalerie ennemies ne peuvent faire ni sauvegarde d'armure ni de Régénération (la sauvegarde invulnérable reste permise). Si la blessure n'est pas sauvegardée, la figurine perd tous ses Points de Vie restants. Inutilisable si l'attaque blesse automatiquement."},"large-target":{"name":"Large Target","desc":"Les Grandes Cibles ne bénéficient ni d'un couvert partiel ni d'un couvert total. Une unité peut tracer sa ligne de vue vers une Grande Cible par-dessus ou à travers une autre unité qui n'en est pas une, et vice versa. Une unité tirant sur une Grande Cible peut tirer avec un rang supplémentaire (par ex. les arbalètes tirent avec les deux premiers rangs au lieu d'un seul)."},"levies":{"name":"Levies","desc":"Les figurines ayant cette règle spéciale ne peuvent bénéficier ni de la Présence Charismatique du Général ni de la règle Tenez vos Rangs du porte-étendard de bataille. En revanche, les unités n'ayant pas cette règle ne sont pas obligées d'effectuer un test de Panique quand une unité amie de Levée Cède le Combat et fuit."},"loner":{"name":"Loner","desc":"Un personnage ayant cette règle ne peut pas être votre Général et ne peut rejoindre une unité n'ayant pas cette règle. Une unité ayant cette règle ne peut être rejointe par un personnage ne l'ayant pas."},"magical-attacks":{"name":"Attaques Magiques","desc":"Les attaques de la figurine comptent comme magiques. Elles peuvent blesser les adversaires Éthérés et ignorent certaines protections comme la Régénération face aux attaques non magiques."},"magic-resistance":{"name":"Magic Resistance (-X)","desc":"Le jet pour lancer de tout sort ennemi (y compris les sorts liens) qui cible une unité comprenant au moins une figurine ayant cette règle subit le modificateur indiqué entre parenthèses (-X). Règle non cumulable : si plusieurs figurines de l'unité l'ont, on utilise le modificateur le plus élevé."},"mercenaries":{"name":"Mercenaries","desc":"Ces unités mercenaires ne peuvent pas bénéficier de la Présence Charismatique du Général ni de la règle Tenez vos Rangs d'un porte-étendard de bataille. Elles ne peuvent pas être rejointes par des personnages issus d'une autre liste d'armée."},"monster-handlers":{"name":"Monster Handlers","desc":"Ce monstre est accompagné d'une ou plusieurs figurines de dresseurs, placées au contact lors du déploiement. Au combat, chaque dresseur ajoute ses attaques à celles du monstre. Quand le monstre subit une blessure non sauvegardée, lancez un D6 : sur 1-4 le monstre perd un Point de Vie, sur 5+ un dresseur est retiré à la place."},"monster-slayer":{"name":"Monster Slayer","desc":"Si cette figurine obtient un 6 naturel sur son jet pour blesser au corps à corps, elle porte un Coup Tueur de Monstres. Les monstres ennemis ne peuvent faire ni sauvegarde d'armure ni de Régénération (la sauvegarde invulnérable reste permise) ; si la blessure n'est pas sauvegardée, le monstre perd tous ses Points de Vie restants. Inutilisable si l'attaque blesse automatiquement."},"motley-crew":{"name":"Motley Crew","desc":"Cette Bande Hétéroclite peut contenir des figurines équipées différemment ou de types différents. Le rang combattant peut comporter des armes différentes (lancez les dés par groupes séparés) ; les valeurs d'armure peuvent varier (utilisez la majorité du rang combattant au corps à corps, la majorité de l'unité au tir). Les pertes sont réparties aussi équitablement que possible."},"move-and-shoot":{"name":"Move & Shoot","desc":"Une arme ayant cette règle peut être utilisée lors de la phase de Tir même si la figurine qui la porte a marché ce tour-ci."},"move-or-shoot":{"name":"Move or Shoot","desc":"Une arme ayant cette règle ne peut pas être utilisée lors de la phase de Tir si la figurine qui la porte s'est déplacée pour quelque raison que ce soit ce tour-ci (y compris en se ralliant ou en se reformant)."},"move-through-cover":{"name":"Move Through Cover","desc":"Une figurine ayant cette règle ne subit aucun malus à son Mouvement pour traverser un terrain difficile ou dangereux. De plus, elle peut relancer ses jets de 1 lors des tests de terrain dangereux."},"multiple-shots":{"name":"Multiple Shots (X)","desc":"Une arme ayant cette règle peut tirer un seul coup normalement, ou un nombre de fois indiqué entre parenthèses (X). En cas de tirs multiples, chaque jet pour toucher subit un malus supplémentaire de -1. Toutes les figurines de l'unité doivent tirer de la même manière. Si le nombre est déterminé par un dé, lancez-le séparément pour chaque figurine."},"multiple-wounds":{"name":"Multiple Wounds (X)","desc":"Chaque blessure non sauvegardée infligée par une attaque ayant cette règle est multipliée par la valeur indiquée entre parenthèses (X). Si ce nombre est déterminé par un dé, lancez-le pour chaque blessure non sauvegardée. Les blessures excédentaires ne se reportent pas sur d'autres figurines."},"open-order":{"name":"Open Order","desc":"Une unité composée de figurines ayant cette règle spéciale peut adopter une formation en Ordre Dispersé."},"poisoned-attacks":{"name":"Poisoned Attacks","desc":"Si cette figurine obtient un 6 naturel sur son jet pour toucher, elle applique un modificateur de +2 au jet pour blesser de cette touche. Sauf indication contraire, cela vaut au tir comme au corps à corps. Inutilisable si l'attaque requiert un 7+ pour toucher ou touche automatiquement."},"ponderous":{"name":"Ponderous","desc":"Une arme ayant cette règle subit un malus de -2 pour toucher en cas de Mouvement & Tir, au lieu du -1 habituel."},"quick-shot":{"name":"Quick Shot","desc":"Une arme ayant cette règle ne subit pas le malus habituel de -1 pour toucher en cas de Mouvement & Tir. De plus, une unité équipée de telles armes peut effectuer une réaction de charge Tenir la Position & Tirer quelle que soit la proximité de l'unité qui charge."},"rallying-cry":{"name":"Rallying Cry","desc":"Lors de la sous-phase de Commandement de son tour, s'il n'est pas engagé au combat, ce personnage peut désigner une unité amie en fuite à portée de Commandement. Cette unité effectue immédiatement un test de Ralliement ; si elle le rate, elle pourra retenter normalement lors de la sous-phase de Ralliement."},"random-attacks":{"name":"Random Attacks","desc":"Cette figurine n'a pas de caractéristique d'Attaques normale ; un jet de dés est indiqué à la place (par ex. D3+1). Chaque fois qu'elle attaque au corps à corps, lancez les dés pour déterminer le nombre d'attaques, puis jetez pour toucher normalement. Plusieurs figurines de ce type dans un rang lancent séparément, sauf indication contraire."},"random-movement":{"name":"Random Movement","desc":"Cette figurine n'a pas de Mouvement normal ; un jet de dés est indiqué à la place (par ex. 2D6). Elle se déplace lors des Mouvements Obligatoires, ne peut ni marcher ni déclarer de charge, et ne peut que pivoter. Si elle entre en contact avec un ennemi durant ces mouvements ou une poursuite, elle compte comme ayant chargé (l'ennemi doit Tenir la Position)."},"regeneration":{"name":"Regeneration (X+)","desc":"Juste après la perte d'un Point de Vie, mais avant de retirer les figurines à zéro PV, cette figurine peut tenter une sauvegarde de Régénération : lancez un D6 et comparez à sa valeur (X+). Si le jet égale ou dépasse la valeur, le PV perdu est récupéré, mais compte tout de même pour le calcul du résultat de combat. Les règles affectant l'armure n'affectent pas la Régénération."},"regimental-unit":{"name":"Regimental Unit","desc":"Une unité ayant cette règle spéciale peut être accompagnée d'un détachement."},"requires-two-hands":{"name":"Requires Two Hands","desc":"Une figurine ne peut pas utiliser de bouclier en plus d'une arme ayant cette règle lors de la phase de Combat. Le bouclier peut toujours servir contre les blessures causées par le tir ou la magie lors des autres phases."},"reserve-move":{"name":"Reserve Move","desc":"Sauf si elle a chargé, marché ou fui lors de la phase de Mouvement, une unité dont la majorité des figurines ont cette règle peut effectuer un Mouvement de Réserve à la fin de la phase de Tir, une fois tous les tirs résolus. Ce mouvement suit les règles de Mouvement de base et peut manœuvrer normalement, mais ne peut pas marcher."},"scouts":{"name":"Scouts","desc":"Ces Éclaireurs sont déployés après toutes les autres unités des deux armées, n'importe où sur le champ de bataille à plus de 12 ps de toute figurine ennemie. Déployés ainsi, ils ne peuvent pas déclarer de charge à leur premier tour. Si les deux armées en possèdent, un jet d'opposition détermine qui déploie en premier, puis on alterne unité par unité."},"shieldwall":{"name":"Shieldwall","desc":"Une fois par partie, lors d'un tour où elle a été chargée, une unité ayant cette règle qui est en Ordre Serré et qui est équipée de boucliers et les utilise peut Céder du Terrain au lieu d'effectuer un Repli en Bon Ordre."},"skirmishers":{"name":"Skirmishers","desc":"Une unité composée de figurines ayant cette règle spéciale peut adopter une formation de Tirailleurs."},"stomp-attacks":{"name":"Stomp Attacks (X)","desc":"Le nombre d'Attaques de Piétinement varie selon la figurine et est indiqué entre parenthèses (X), souvent déterminé par un dé. Elles ne peuvent être portées qu'au contact de l'ennemi et sont résolues en dernier, après toutes les autres attaques y compris celles d'Initiative 1. Elles touchent automatiquement et utilisent la Force non modifiée de la figurine qui les porte."},"strike-first":{"name":"Strike First","desc":"Lors de la phase de Combat, une figurine ayant cette règle et engagée au combat améliore son Initiative à 10 (avant tout autre modificateur). Si une figurine possède à la fois Frappe en Premier et Frappe en Dernier, les deux règles s'annulent."},"strike-last":{"name":"Strike Last","desc":"Lors de la phase de Combat, une figurine ayant cette règle et engagée au combat réduit son Initiative à 1 (avant tout autre modificateur). Si une figurine possède à la fois Frappe en Dernier et Frappe en Premier, les deux règles s'annulent."},"stubborn":{"name":"Stubborn","desc":"La première fois que cette unité doit effectuer un test de Moral, elle peut choisir de ne pas le faire et Cède du Terrain en Bon Ordre à la place, même si la Puissance d'Unité du camp victorieux est plus du double de celle du camp vaincu. Une unité n'est pas Obstinée parce qu'un personnage Obstiné la rejoint, et un personnage Obstiné ne peut pas utiliser cette règle au sein d'une unité qui ne l'est pas."},"stupidity":{"name":"Stupidity","desc":"Sauf si elle fuit ou combat, une unité ayant cette règle doit effectuer un test de Stupidité (test de Commandement) au Début de chaque Tour. En cas d'échec, jusqu'à son prochain Début de Tour, elle ne peut ni se déplacer (sauf pour fuir), ni tirer ou lancer un sort, ni tenter de dissipation, et doit Tenir la Position si elle est chargée."},"swiftstride":{"name":"Allure Rapide","desc":"Lors d'une charge, d'une poursuite ou d'une fuite, la figurine lance 3D6 et conserve les 2 meilleurs résultats pour calculer la distance."},"terror":{"name":"Terror","desc":"Ces figurines causent la Terreur ainsi que la Peur. Quand une unité causant la Terreur déclare une charge, la cible doit effectuer un test de Commandement : en cas d'échec elle doit Fuir ; en cas de réussite elle peut réagir normalement. Si le camp victorieux d'un combat comprend une unité causant la Terreur, les unités du camp vaincu subissent -1 au Commandement pour leurs tests de Moral. Les figurines causant la Peur craignent aussi la Terreur. Les figurines causant la Terreur y sont immunisées."},"timmm-berrr":{"name":"Timmm-berrr!","desc":"Quand cette figurine est réduite à zéro Point de Vie, le gagnant d'un jet d'opposition choisit l'un de ses arcs (front, flanc ou arrière) dans lequel elle s'effondre. Toute unité dans cet arc et au contact subit D6 touches à la Force de cette figurine avec un AP de -1. Une fois ces touches résolues, la figurine est retirée du jeu."},"unbreakable":{"name":"Unbreakable","desc":"Si une unité ayant cette règle perd un round de combat, elle n'a pas à effectuer de test de Moral : elle Cède automatiquement du Terrain, repoussée par l'ennemi. Les personnages qui ne sont pas Indéboulonnables ne peuvent rejoindre des unités qui le sont, et vice versa."},"unstable":{"name":"Unstable","desc":"Si une unité ayant cette règle perd un round de combat, elle perd un Point de Vie supplémentaire pour chaque point de différence du résultat de combat. Ces PV sont perdus après le calcul du résultat de combat mais avant les tests de Moral, et ne peuvent pas être récupérés par une sauvegarde de Régénération. Si l'unité comprend des personnages Instables, répartissez d'abord une blessure sur chaque figurine, puis divisez les blessures restantes."},"vanguard":{"name":"Vanguard","desc":"Après le déploiement, ces unités peuvent effectuer un mouvement d'avant-garde suivant les règles de Mouvement de base (peut manœuvrer normalement mais ne peut pas marcher). Si les deux armées en possèdent, un jet d'opposition détermine qui bouge en premier, puis on alterne unité par unité. Une unité ayant effectué ce mouvement ne peut pas déclarer de charge à son premier tour."},"veteran":{"name":"Veteran","desc":"Si la majorité des figurines d'une unité ont cette règle spéciale, l'unité peut relancer tout test de Commandement raté. À noter qu'un test de Moral n'est pas un test de Commandement."},"volley-fire":{"name":"Volley Fire","desc":"Quand une unité ayant cette règle effectue un tir, la moitié des figurines de chaque rang autre que le premier (ou les deux premiers rangs sur une colline), arrondie au supérieur, peut aussi tirer. Une unité ne peut pas effectuer de Tir en Salve si elle s'est déplacée pour quelque raison que ce soit ce tour-ci (y compris en se reformant) ou lors d'une réaction de charge Tenir la Position & Tirer."},"warband":{"name":"Warband","desc":"Sauf si elle fuit, une Bande de Guerre gagne un modificateur positif à son Commandement égal à son Bonus de Rang actuel (Commandement maximum 10). Ce modificateur ne peut servir ni pour les tests de Retenue ni, si elle est Impétueuse, pour les tests de charge. Si la majorité des figurines de l'unité ont cette règle, elle peut relancer son jet de Charge. Le Commandement des personnages non issus d'une Bande de Guerre ne peut être modifié par cette règle."},"warp-spawned":{"name":"Warp-spawned","desc":"Une figurine ayant cette règle ne peut pas effectuer de sauvegarde de Régénération contre une blessure causée par une Attaque Magique. De plus, les personnages n'ayant pas cette règle ne peuvent pas rejoindre des unités qui l'ont, et vice versa."},"gromril-armour":{"name":"Gromril Armour","desc":"Le gromril, le métal le plus dur et le plus solide du monde connu selon les Nains. Une figurine ayant cette règle peut relancer tout 1 naturel obtenu lors d'un jet de sauvegarde d'armure."},"gromril-weapons":{"name":"Gromril Weapons","desc":"Une arme de base portée par une figurine ayant cette règle dispose d'un AP de -1. Cette règle ne s'applique qu'à une unique arme de base ordinaire : elle cesse de s'appliquer si la figurine utilise deux armes de base, tout autre type d'arme, ou si son arme de base est gravée de runes d'Arme."},"ancestral-shield":{"name":"Ancestral Shield","desc":"Une Enclume du Destin ainsi que le Père Forgeron & la Garde de l'Enclume bénéficient d'une sauvegarde invulnérable de 5+ contre toute blessure subie."},"resolute":{"name":"Resolute","desc":"Une figurine ayant cette règle subit un malus de -1 à tout jet de Fuite ou de poursuite qu'elle effectue (minimum 1). Ce modificateur ne s'applique pas aux personnages montés Nains du Chaos."},"deathblow":{"name":"Deathblow","desc":"Quand une figurine ayant cette règle est réduite à zéro Point de Vie par une attaque ennemie lors de la phase de Combat, l'unité ayant porté l'attaque subit une touche de Force 3 avec AP -1. Si la figurine est réduite à zéro PV lors d'un défi, c'est la figurine ayant porté l'attaque qui subit cette touche, et non son unité."},"slayer":{"name":"Slayer","desc":"Quand cette figurine effectue un jet pour blesser, un résultat de 4+ réussit toujours, quelle que soit l'Endurance de la cible."},"slayer-of-daemons":{"name":"Slayer of Daemons","desc":"Quand ce personnage effectue un jet pour blesser, un résultat de 4+ réussit toujours, quelle que soit l'Endurance de la cible. De plus, chaque blessure non sauvegardée qu'il inflige à une figurine ennemie ayant la règle Engeance de la Distorsion, ou dont le type de troupe est béhémoth, dispose de la règle Blessures Multiples (D3)."},"slayer-of-dragons":{"name":"Slayer of Dragons","desc":"Quand ce personnage effectue un jet pour blesser, un résultat de 4+ réussit toujours, quelle que soit l'Endurance de la cible. De plus, chaque blessure non sauvegardée qu'il inflige à une figurine ennemie dont le type de troupe est béhémoth dispose de la règle Blessures Multiples (D3)."},"rune-lore":{"name":"Rune Lore","desc":"Une figurine ayant cette règle peut être désignée pour tenter une Dissipation comme si elle était un Sorcier. Une Enclume du Destin a une portée de Dissipation de 24 ps et applique +3 à ses jets de dissipation. Un Seigneur des Runes a une portée de 21 ps et applique +2. Un Forgeron des Runes a une portée de 18 ps et applique +1."},"runes-of-protection":{"name":"Runes of Protection","desc":"Une figurine ayant cette règle bénéficie d'une sauvegarde invulnérable de 6+ contre toute blessure subie causée par une attaque ennemie non magique."},"runes-of-warding":{"name":"Runes of Warding","desc":"Une figurine ayant cette règle bénéficie d'une sauvegarde invulnérable de 5+ contre toute blessure subie causée par une attaque ayant la règle spéciale Attaques Enflammées."},"immovable-object":{"name":"Immovable Object","desc":"Une fois placée sur le champ de bataille lors du déploiement, cette figurine ne peut plus être déplacée par son équipage lors de la sous-phase des Mouvements Restants. Elle peut toutefois pivoter librement à tout moment de son tour et effectuer un mouvement de poursuite normalement."},"strike-the-runes":{"name":"Strike the Runes","desc":"Une Enclume du Destin peut lancer les sorts liés suivants (Niveau de Puissance 2) : Rune du Serment & de l'Acier (relancer les sauvegardes d'armure ratées, ou améliorer en plus la valeur d'armure de 1 sur 11+), Rune du Foyer & de l'Âtre (les Nains amis à moins de 21 ps deviennent Immunisés à la Psychologie), Rune de Hâte & d'Urgence (l'unité cible peut se déplacer de nouveau), Rune de Courroux & de Ruine (la cible subit 2D6 touches de Force 4, AP -2)."},"bombing-run":{"name":"Bombing Run","desc":"Cette figurine peut effectuer un Bombardement contre une unité ennemie unique non engagée au combat en la survolant durant les Mouvements Restants. Lancez un D6 : 1 = elle perd un PV ; 2 = l'ennemi perd un PV ; 3-4 = placez le grand gabarit (5 ps), dévie de D6 ps, touches de Force 4 AP -1 ; 5-6 = placez deux petits gabarits (3 ps), chacun déviant de D6 ps, touches de Force 4 AP -1."},"forgefire":{"name":"Forgefire","desc":"Si ce personnage rejoint une unité, celle-ci gagne les règles spéciales Arme Perforante (2) et Attaques Enflammées. S'il quitte l'unité pour quelque raison que ce soit, celle-ci perd ces règles."},"elven-reflexes":{"name":"Elven Reflexes","desc":"Une figurine ayant cette règle (mais pas sa monture) bénéficie d'un modificateur de +1 à sa caractéristique d'Initiative (maximum 10) lors du premier round de tout combat."},"sea-dragon-cloak":{"name":"Sea Dragon Cloak","desc":"Une figurine ayant cette règle spéciale améliore sa valeur d'armure de 1 (jusqu'à un maximum de 2+) contre les attaques de tir non magiques."},"martial-prowess":{"name":"Martial Prowess","desc":"Une unité ayant cette règle spéciale peut effectuer des attaques de soutien vers son flanc ou son arrière, ainsi que vers son front."},"eternal-hatred":{"name":"Eternal Hatred","desc":"Contre les Hauts Elfes, la Haine de cette figurine s'applique à chaque round de corps à corps, et pas seulement au premier. Cette règle spéciale ne s'applique pas à la monture de la figurine (si elle en a une)."},"dark-runes":{"name":"Dark Runes","desc":"Cette unité bénéficie d'une sauvegarde invulnérable de 5+ contre toute blessure subie qui a été causée par une attaque ennemie non magique."},"murderous":{"name":"Murderous","desc":"Au corps à corps, une figurine ayant cette règle qui combat avec une arme de base peut relancer ses jets pour blesser de 1 naturel. Cette règle ne s'applique qu'à une seule arme de base non magique et ne s'applique pas à la monture. Si la figurine utilise deux armes de base ou tout autre type d'arme, cette règle cesse de s'appliquer."},"cleaving-blow":{"name":"Cleaving Blow","desc":"Si une figurine ayant cette règle obtient un 6 naturel sur son jet pour blesser au corps à corps, elle porte un Coup Tranchant. Les figurines ennemies de type infanterie, infanterie lourde, cavalerie légère, cavalerie lourde ou bêtes de guerre ne peuvent faire ni sauvegarde d'armure ni de Régénération contre un Coup Tranchant (la sauvegarde invulnérable reste permise)."},"daemonic":{"name":"Daemonic","desc":"Les figurines ayant cette règle sont Démoniaques et bénéficient d'une sauvegarde invulnérable de 5+ contre les blessures causées par des attaques ennemies non magiques. Toutes les figurines Démoniaques ont aussi : Instabilité Démoniaque, Peur, Insensible à la Psychologie, Attaques Magiques, Indéboulonnable et Engeance du Warp. Un personnage ayant cette règle ne peut pas rejoindre une unité ne l'ayant pas, et vice versa."},"daemonic-instability":{"name":"Daemonic Instability","desc":"Si une unité ayant cette règle perd un round de combat, elle doit effectuer un test de Commandement avec un modificateur de +1 par point de résultat de combat perdu. Si réussi, tout va bien. Si raté, l'unité perd autant de Points de Vie que la marge d'échec. Si l'échec se produit sur un double 6 naturel, l'unité est immédiatement retirée du jeu."},"daemonic-charge":{"name":"Daemonic Charge","desc":"Les Touches d'Impact causées par cette figurine ont un AP de -2."},"daemon-of-khorne":{"name":"Daemon of Khorne","desc":"Les Démons de Khorne bénéficient de la règle Haine (Démons de Slaanesh). De plus, lors d'un tour où il a effectué un mouvement de charge, un Démon de Khorne (mais pas sa monture) gagne un modificateur de +1 à sa caractéristique de Force."},"daemon-of-nurgle":{"name":"Daemon of Nurgle","desc":"Les Démons de Nurgle bénéficient de la règle Haine (Démons de Tzeentch). De plus, toute figurine ennemie qui dirige ses attaques contre un Démon de Nurgle lors de la phase de Combat doit relancer ses jets pour toucher de 6 naturel."},"daemon-of-slaanesh":{"name":"Daemon of Slaanesh","desc":"Les Démons de Slaanesh bénéficient de la règle Haine (Démons de Khorne). De plus, les Démons de Slaanesh augmentent leur portée de charge maximale de 1 ps et bénéficient d'un modificateur de +1 au résultat de tout jet de Charge ou de poursuite qu'ils effectuent."},"daemon-of-tzeentch":{"name":"Daemon of Tzeentch","desc":"Les Démons de Tzeentch bénéficient de la règle Haine (Démons de Nurgle). De plus, un Démon de Tzeentch qui est aussi un Sorcier peut appliquer un modificateur de +1 à tout jet pour lancer qu'il effectue. Ce modificateur n'annule pas un double 1 naturel."},"infernal-favour":{"name":"Infernal Favour (X)","desc":"Une unité ayant cette règle spéciale réduit le nombre de blessures subies à cause de l'Instabilité Démoniaque du montant indiqué entre parenthèses (X). Règle non cumulable : si plusieurs figurines de l'unité l'ont, on utilise la valeur la plus élevée pour toute l'unité."},"scintillating-sorcery":{"name":"Scintillating Sorcery","desc":"Une unité d'Horreurs Roses connaît l'un des sorts correspondant à son Alignement Démoniaque (choisi par son joueur avant le déploiement des armées). L'unité peut lancer ce sort comme un sort lié, avec un Niveau de Puissance égal à son Bonus de Rang actuel."},"soporific-musk":{"name":"Soporific Musk","desc":"Les figurines ennemies engagées au corps à corps avec une figurine ayant cette règle ne peuvent pas utiliser la règle Frappe en Premier. Celles qui ne possèdent pas Frappe en Premier deviennent au contraire soumises à Frappe en Dernier."},"gorefeast":{"name":"Gorefeast","desc":"Pour chaque Point de Vie qu'une unité ennemie perd à cause d'une Touche d'Impact causée par cette figurine, lancez un D6. Pour chaque 6, cette figurine récupère immédiatement un Point de Vie perdu."},"attention-seeker":{"name":"Attention Seeker","desc":"Chaque figurine d'une unité de Bêtes de Nurgle peut lancer et accepter des défis de la même manière qu'un personnage."},"necromantic-undead":{"name":"Necromantic Undead","desc":"Les figurines ayant cette règle sont des 'Morts-Vivants'. Les Morts-Vivants ne peuvent pas marcher (sauf s'ils ont la règle Vol (X) et choisissent de se déplacer en volant). Tous les Morts-Vivants ont : Peur, Immunité à la Psychologie, Indéboulonnable et Instable. Un personnage ayant cette règle ne peut pas rejoindre une unité qui ne l'a pas, et vice versa."},"nehekharan-undead":{"name":"Nehekharan Undead","desc":"Les figurines ayant cette règle sont des 'Morts-Vivants'. Les Morts-Vivants ne peuvent pas marcher (sauf s'ils ont la règle Vol (X) et choisissent de se déplacer en volant). Tous les Morts-Vivants ont : Peur, Immunité à la Psychologie, Indéboulonnable et Instable. Un personnage ayant cette règle ne peut pas rejoindre une unité qui ne l'a pas, et vice versa."},"the-hunger":{"name":"The Hunger","desc":"À la fin de toute phase de Combat où ce personnage a infligé au moins une blessure non sauvegardée, lancez un D6 : sur 6, il récupère un Point de Vie perdu. En revanche, lui (et toute unité qu'il a rejointe) ne lance qu'un seul D6 pour ses jets de poursuite, au lieu des 2D6 habituels."},"invocation-of-nehek":{"name":"Invocation of Nehek","desc":"Lors de la sous-phase de Commandement de son tour, s'il n'est pas engagé au combat, ce personnage peut tenter de ressusciter les morts par un test de Commandement. S'il réussit, une unité amie Morts-Vivants Nécromantiques à moins de 12 ps récupère des Points de Vie perdus : infanterie normale/lourde récupère Niveau +D3 ; nuées/cavalerie légère/bêtes de guerre récupèrent Niveau +1 ; infanterie monstrueuse/cavalerie lourde/cavalerie monstrueuse récupèrent un nombre selon leur type de troupe."},"dry-as-dust":{"name":"Dry as Dust","desc":"Chaque fois que cette figurine subit une blessure non sauvegardée d'une Attaque Enflammée, votre adversaire peut lancer un D6 : sur 1-3, les flammes s'éteignent et la figurine est épargnée ; sur 4+, l'incendie prend et la figurine perd un Point de Vie supplémentaire. Les blessures excédentaires n'ont d'autre effet que l'Achèvement lors d'un duel ; elles ne se reportent pas sur d'autres figurines."},"khopesh":{"name":"Khopesh","desc":"Une arme de base portée par une figurine ayant cette règle a une caractéristique d'AP de -1. Cela ne vaut que pour une seule arme de base ordinaire et ne s'applique pas à la monture. Si la figurine utilise deux armes de base ou tout autre type d'arme, cette règle cesse de s'appliquer."},"choppas":{"name":"Choppas","desc":"Lors d'un tour où elle charge, une figurine ayant cette règle peut relancer ses jets pour blesser obtenant un 1 naturel et améliore l'AP de ses armes de 1. Cela ne vaut que pour les armes non magiques et ne s'applique pas à la monture. Si la figurine utilise une arme magique, cette règle cesse de s'appliquer."},"da-boyz":{"name":"Da Boyz","desc":"Votre armée doit inclure un Black Orc Boss pour chaque Black Orc Mob qu'elle contient, et vice versa. Pour chaque Black Orc Mob, l'armée doit aussi inclure un Black Orc War Boss ou Big Boss ; et pour chaque Black Orc War Boss ou Big Boss, elle doit inclure un Black Orc Mob."},"waaagh":{"name":"Waaagh!","desc":"Une fois par partie, lors de la sous-phase de Commandement de son tour, ce personnage peut tenter de déclencher le Waaagh! par un test de Commandement. S'il réussit, jusqu'à la prochaine sous-phase de Début de Tour, ce personnage, sa monture et toute unité d'Orcs rejointe peuvent relancer leurs jets pour toucher de 1 et revendiquer un point de résultat de combat supplémentaire (+1). Non cumulable. Une unité d'Orcs doit être entièrement composée d'Orcs."},"ignore-panic":{"name":"Ignore Panic","desc":"Cette unité n'a pas à effectuer de test de Panique quand une unité amie ne possédant pas cette règle est détruite, ou Cède et fuit le combat à moins de 6 ps d'elle. De même, elle n'a pas à tester la Panique si une unité amie ne possédant pas cette règle fuit à travers elle."},"quell-impetuosity":{"name":"Quell Impetuosity","desc":"Tant qu'elle se trouve à moins de 6 ps d'une unité ayant cette règle, une unité amie Impétueuse peut relancer un test de Commandement raté lorsqu'elle teste pour déterminer si elle doit déclarer une charge ou agir normalement."},"primal-fury":{"name":"Primal Fury","desc":"Quand le combat de cette unité est choisi à l'Étape 1.1 d'une sous-phase Choisir & Livrer les Combats, elle doit effectuer un test de Commandement. S'il est réussi, l'unité devient soumise à la 'Furie Primale' jusqu'à la fin de cette phase de Combat : elle peut alors relancer ses jets pour toucher de 1 naturel."},"blood-rage":{"name":"Blood Rage","desc":"Si, en testant pour devenir soumise à la Furie Primale, cette unité réussit son test de Commandement sur un double naturel, elle devient aussi Frénétique. Une unité ayant cette règle peut redevenir Frénétique ainsi même si elle avait perdu la Frénésie plus tôt dans la partie."},"ensorcelled-weapons":{"name":"Ensorcelled Weapons","desc":"Une arme de base portée par une figurine ayant cette règle dispose de la règle Attaques Magiques et d'un AP de -1. Cela ne s'applique qu'à une unique arme de base non magique et pas à la monture. Si la figurine utilise deux armes de base ou tout autre type d'arme, cette règle cesse de s'appliquer."},"gaze-of-the-gods":{"name":"Gaze of the Gods","desc":"Lors de la sous-phase de Commandement de son tour, un personnage ayant cette règle peut lancer sur la table du Regard des Dieux (D6) : 1 - Stupidité pour la partie (ou -1 Cd) ; 2 - +1 Initiative jusqu'au prochain Début de Tour ; 3 - +1 Endurance jusqu'au prochain Début de Tour ; 4 - +1 CC pour la partie ; 5 - +1 Attaque pour la partie ; 6 - +1 Force et +1 Cd pour la partie. Les bénéfices ne s'appliquent qu'au personnage."},"mark-of-chaos-undivided":{"name":"Mark of Chaos Undivided","desc":"Les figurines portant la Marque du Chaos Non Divisé peuvent relancer tout test de Peur, Panique ou Terreur raté."},"chaos-armour-warriors-of-chaos":{"name":"Chaos Armour (Warriors of Chaos)","desc":"Une figurine ayant cette règle a une sauvegarde invulnérable contre toute blessure subie ; sa valeur est indiquée entre parenthèses après le nom de la règle (X+). De plus, un sorcier ayant cette règle peut porter une armure sans malus."},"cold-blooded":{"name":"Cold Blooded","desc":"Lorsqu'une figurine dotée de cette règle spéciale doit effectuer un test de Peur, de Panique ou de Terreur, elle peut lancer un D6 supplémentaire et écarter le dé au résultat le plus élevé."},"spawn-kin":{"name":"Spawn-kin","desc":"Quand une unité de Cohortes de Skinks incluant des Kroxigors se déploie ou se reforme, les Kroxigors sont placés au second rang. En combat, un Kroxigor au contact d'un Skink de son unité lui-même au contact d'un ennemi compte comme étant au contact de cet ennemi et fait partie du rang combattant. Les Kroxigors ne subissent de Touches d'Impact ou d'Attaques de Piétinement que s'il reste moins de cinq Skinks de rang. Les Blessures sont comptées séparément et ne débordent pas entre Skinks et Kroxigors."},"slashing-talons":{"name":"Slashing Talons","desc":"Arme de Combat : F, PA -3, avec Blessures Multiples (D3). Notes : la règle Blessures Multiples (D3) ne s'applique que contre les figurines ennemies dont le type de troupe est « monstre »."},"venom-spray":{"name":"Venom Spray","desc":"Arme à Souffle : Portée N/A, F3, PA -1, avec Arme à Souffle. Notes : lors d'un jet pour Blesser avec cette arme, un résultat de 5+ est toujours une réussite, quelle que soit l'Endurance de la cible."},"impervious-defence":{"name":"Impervious Defence","desc":"Les unités ennemies ne peuvent réclamer aucun point de résultat de combat bonus pour être engagées dans l'arc de flanc ou d'arrière de cette figurine."},"valour-of-ages":{"name":"Valour of Ages","desc":"Une unité ayant cette règle peut relancer tout test de Panique raté causé par de lourdes pertes ou par le passage à travers elle d'une unité amie en fuite."},"blessings-of-the-lady":{"name":"Blessings of the Lady","desc":"Une fois le déploiement terminé, l'armée de Bretonnie peut s'agenouiller et prier, cédant le premier tour à l'adversaire. Si elle est accordée, toutes les figurines ayant cette règle gagnent : une sauvegarde invulnérable de 6+ contre toute blessure, et une sauvegarde invulnérable de 5+ contre les blessures causées par une Force de 5 ou plus. Cette règle est perdue si la figurine ou l'unité fuit, ou si un personnage refuse un défi. Inutilisable dans un duel en miroir."},"the-knights-vow":{"name":"The Knight's Vow","desc":"Une figurine ayant ce Vœu de Chevalerie n'a pas à effectuer de test de Panique quand une unité amie ayant la règle Paysannerie est détruite à moins de 6 ps ou fuit à travers elle. Une unité ayant ce vœu ne peut être rejointe par un personnage ayant la règle Paysannerie, et inversement."},"battle-magic":{"name":"Battle Magic","desc":"Un domaine de magie largement pratiqué à travers le Vieux Monde, conçu pour le champ de bataille ; ses praticiens puisent dans plusieurs Vents de Magie. Les sorts incluent : Marteau de Force (signature, Assaut, 7+, Combat, 2D3 touches F4 AP-2), Boule de Feu (Projectile Magique, 8+, 24 ps, 2D6 touches F4 Enflammées), Malédiction d'Attraction des Flèches (Maléfice, 7+, 21 ps, relance des 1 pour toucher contre la cible), Pilier de Feu (Vortex, 9+) et d'autres."},"high-magic":{"name":"High Magic","desc":"Le savoir le plus raffiné, rassemblant les huit Vents de Magie. Sorts notables : Drain de Magie (Maléfice Distinctif, 9+, Reste en Jeu, les Sorciers ennemis à moins de 24 ps augmentent leurs valeurs de lancement de 2), Marche entre les Mondes (Transport, 10+, Éthéré + Mouvement de Réserve), Convocation Ardente (Projectile Magique, 10+, 18 ps, touches Enflammées sur grand gabarit), Tempête (Vortex, 9+), Défaire la Matière (Assaut, 8+), et d'autres."},"strength-in-numbers":{"name":"Scurrying Masses","desc":"Bien que peu courageux par nature, les Skavens puisent courage et discipline dans le nombre. Tant qu'elle se trouve à moins de 3 ps d'une unité amie, cette figurine gagne un modificateur positif (+) à son Commandement égal au Bonus de Rang actuel de cette unité, jusqu'à un maximum de Commandement 10."},"warpstone-weapons":{"name":"Warpstone Weapons","desc":"Une arme de base portée par une figurine ayant cette règle bénéficie de la règle Attaques Magiques et d'une caractéristique d'AP de -1. Cela ne vaut que pour une seule arme de base ordinaire. Si la figurine utilise deux armes de base ou tout autre type d'arme, cette règle cesse de s'appliquer."},"cornered-rats":{"name":"Cornered Rats","desc":"Si une unité de Déchets Skavens est démoralisée et fuit le combat, elle est considérée comme entièrement détruite et retirée du jeu. Si l'unité compte dix figurines ou plus, avant de la retirer, chaque unité (amie ou ennemie) à 2D6 ps subit D3 touches de Force 3. Pour chaque tranche de cinq Déchets Skavens au-delà de cinq, ajoutez +1 au D3 (maximum +3). Les adversaires qui étaient au contact de cette unité peuvent alors tenter de se retenir et se reformer, ou de « foncer »."},"warpstone-spikes":{"name":"Warpstone Spikes","desc":"Toutes les Touches d'Impact infligées par une figurine ayant cette règle ont une caractéristique de Pénétration d'Armure de -2 et la règle Attaques Magiques."},"plague-disciples":{"name":"Plague Disciples","desc":"Utilisées comme détachement, les figurines ayant cette règle ne peuvent être prises que comme détachement d'un régiment de Moines de la Peste."},"leader-of-the-pack":{"name":"Leader of the Pack","desc":"Les figurines ayant cette règle ne peuvent être prises que dans une unité de Déchets Skavens, Rat-ogres ou Rats Géants. Elles peuvent être placées derrière le premier rang de leur unité. Un Maître corrupteur peut « traverser les rangs » comme s'il était un personnage, et peut lancer et accepter des duels même s'il n'est pas dans le rang de combat."},"dodge":{"name":"Dodge","desc":"Cette figurine bénéficie d'une sauvegarde invulnérable de 5+."},"always-strikes-first":{"name":"Always Strikes First","desc":"Une figurine ayant cette règle effectue toujours ses attaques de corps à corps en premier, quelle que soit son Initiative ou l'ordre du combat. De plus, si son Initiative est supérieure ou égale à celle de son adversaire, elle peut relancer ses jets pour toucher ratés contre cet adversaire. Si les deux combattants ont cette règle, les attaques sont résolues dans l'ordre d'Initiative normal."},"swarm":{"name":"Swarms","desc":"Les nuées sont des masses grouillantes de petites créatures (rats, serpents, insectes) invoquées ou menées sur le champ de bataille. Chaque socle compte comme une seule figurine. Type de troupe : Nuées. Puissance d'Unité par figurine : 3. Règles spéciales : Insignifiant, Personne ne s'en Soucie, Indiscipliné. Aucune figurine par rang ni bonus de rang maximal."},"mixed-unit":{"name":"Mixed Unit","desc":"Les figurines d'un Troupeau Primal ont des caractéristiques de Capacité de Combat et d'Endurance différentes. Avant de jeter pour blesser, les touches du tir ennemi sont réparties aussi équitablement que possible entre Gors et Ungors. Au corps à corps, les figurines ennemies doivent diriger leurs attaques contre les figurines du rang combattant de cette unité."},"largely-insignificant":{"name":"Largely Insignificant","desc":"Les unités ayant cette règle ne provoquent jamais de test de Panique chez les unités amies. En revanche, une unité ayant cette règle ne peut pas être rejointe par un personnage ne l'ayant pas."},"skirmish-formation":{"name":"Skirmish Formation","desc":"Une unité en formation de Tirailleurs n'a jamais de rangs ni de files rigides : elle se déplace en un groupe lâche ou une ligne approximative. Les figurines sont déployées en un seul groupe lâche mais contigu, chaque figurine se trouvant à moins de 1 ps d'une autre de la même unité. Cela permet aux Tirailleurs de se déplacer vite et d'exploiter le terrain pour se mettre à l'abri."},"open-order-formation":{"name":"Open Order Formation","desc":"Une unité en formation d'Ordre Dispersé ressemble de près à une unité en Ordre Serré : les figurines sont disposées au contact socle à socle, bord à bord et coin avant à coin avant, en rangs et colonnes orientés dans la même direction. Les différences tiennent à la manière dont l'unité se déplace et interagit avec le terrain : elle bénéficie d'une grande mobilité et, en Ordre de Combat, peut revendiquer un Bonus de Rang."},"arme-de-base":{"name":"Arme de base","desc":"Arme à une main portée par défaut. Utilisable avec un bouclier."},"arme-lourde":{"name":"Arme lourde","desc":"+2 Force au CàC. Frappe toujours en dernier. Incompatible avec bouclier."},"arme-a-deux-mains":{"name":"Arme à deux mains","desc":"+2 Force au CàC. Frappe toujours en dernier."},"hallebarde":{"name":"Hallebarde","desc":"+1 Force au CàC et Armour Bane (1). Frappe avant les armes à 2 mains."},"lance":{"name":"Lance de joute","desc":"Profil : Combat, Force +2, PA -2. Règle spéciale : Arme Perforante (1). Notes : figurines de type « cavalerie » ou « monstre » uniquement. Utilisable seulement au tour où le porteur a chargé ; les bonus de Force et de PA ne s'appliquent que contre les figurines ennemies chargées ce tour-là (errata). Aux tours suivants, le porteur utilise son arme de base."},"lance-de-cavalerie":{"name":"Lance de cavalerie","desc":"+2 Force lors d'une charge (cavalerie seulement)."},"arbalete":{"name":"Arbalète","desc":"Portée 30'', Force 4, Perforant (1). Mouvement OU Tir."},"arc":{"name":"Arc","desc":"Portée 24'', Force 3. Peut tirer en se déplaçant (demi-portée)."},"arc-court":{"name":"Arc court","desc":"Portée 18'', Force 3. Peut tirer en se déplaçant."},"arc-long":{"name":"Arc long","desc":"Portée 30'', Force 3. Peut tirer en se déplaçant (demi-portée)."},"pistolet":{"name":"Pistolet","desc":"Portée 8'', Force 4, Ignorer Armure. CàC : +1 Attaque F4 Ignorer Armure (1er tour)."},"pistolets":{"name":"Pistolets (paire)","desc":"2 tirs portée 8'', F4, Ignorer Armure. CàC : +1 Attaque F4 Ignorer Armure."},"armes-additionnelles":{"name":"Armes additionnelles","desc":"+1 Attaque en CàC (deux armes simultanées)."},"arme-de-tir":{"name":"Arme de tir","desc":"Arme à distance (portée et Force selon la fiche)."},"armure-legere":{"name":"Armure légère","desc":"Sauvegarde 6+. Avec bouclier : 5+ en CàC."},"armure-lourde":{"name":"Armure lourde","desc":"Sauvegarde 5+. Avec bouclier : 4+ en CàC."},"armure-de-plate-complete":{"name":"Armure de plate complète","desc":"Sauvegarde 4+. Avec bouclier : 3+ en CàC."},"armure-runique":{"name":"Armure runique","desc":"Sauvegarde 4+. Peut recevoir des Runes naines."},"carapace":{"name":"Carapace","desc":"Protection naturelle. Sauvegarde 5+."},"bouclier":{"name":"Bouclier","desc":"+1 Sv en CàC. Parade : Sv+ 6+ en CàC."},"bouclier-runique":{"name":"Bouclier runique","desc":"+1 Sv en CàC. Parade 6+. Peut recevoir des Runes."},"arme-magique":{"name":"Arme magique","desc":"Arme enchantée (effets selon l'objet choisi). Compte comme magique."},"armure-magique":{"name":"Armure magique","desc":"Protection enchantée (effets selon l'objet choisi)."},"objet-enchante":{"name":"Objet enchanté","desc":"Objet magique divers : talisman, parchemin, pierre runique, etc."},"marque-de-khorne":{"name":"Marque de Khorne","desc":"+1 Attaque. L'unité gagne Frénésie (doit charger si possible)."},"marque-de-nurgle":{"name":"Marque de Nurgle","desc":"+1 Endurance. L'unité gagne la règle Pestiféré."},"marque-de-slaanesh":{"name":"Marque de Slaanesh","desc":"+1 Initiative. Immunisé à la Peur et à la Terreur."},"marque-de-tzeentch":{"name":"Marque de Tzeentch","desc":"Sauvegarde Invulnérable 6+. Accès aux sorts de Tzeentch."},"don-de-khorne":{"name":"Don de Khorne","desc":"+1 Attaque ou capacité spéciale de Khorne."},"don-de-nurgle":{"name":"Don de Nurgle","desc":"+1 Endurance ou capacité spéciale de Nurgle."},"don-de-slaanesh":{"name":"Don de Slaanesh","desc":"+1 Initiative ou capacité spéciale de Slaanesh."},"don-de-tzeentch":{"name":"Don de Tzeentch","desc":"Sort supplémentaire ou capacité de Tzeentch."},"rune-de-combat":{"name":"Rune de combat","desc":"Rune gravée sur l'arme. Effets : Puissance (+1F), Feu, Tranchant, etc."},"rune-de-protection":{"name":"Rune de protection","desc":"Rune défensive : Préservation (+1Sv), Résistance (Sv+ 5+), etc."},"benediction-de-sigmar":{"name":"Bénédiction de Sigmar","desc":"Prière divine. Effets selon la prière choisie dans le livre d'armée."},"priere-de-la-dame":{"name":"Prière de la Dame","desc":"Sauvegarde Invulnérable 6+ pour l'unité. Peut relancer un test de Panique."},"benediction-de-la-dame":{"name":"Bénédiction de la Dame","desc":"Sauvegarde Invulnérable 6+ (foi en la Dame du Lac)."},"sorcier-niveau-1":{"name":"Sorcier Niveau 1","desc":"1 Dé de Pouvoir. Connaît 1 sort. Lance 1 sort/phase de Magie."},"sorcier-niveau-2":{"name":"Sorcier Niveau 2","desc":"1 Dé de Pouvoir. Connaît 2 sorts. Lance 2 sorts/phase de Magie."},"sorcier-niveau-3":{"name":"Sorcier Niveau 3","desc":"2 Dés de Pouvoir. Connaît 3 sorts. Lance 3 sorts/phase de Magie."},"sorcier-niveau-4":{"name":"Sorcier Niveau 4","desc":"2 Dés de Pouvoir. Connaît 4 sorts. Accès à tout le domaine."},"hand-weapon":{"name":"Arme de base","desc":"Profil : Combat, Force du porteur, PA —, aucune règle spéciale. Sauf indication contraire, toutes les figurines sont équipées d'une arme de base (y compris la plupart des montures)."},"additional-hand-weapon":{"name":"Arme de base additionnelle","desc":"Profil : Combat, Force du porteur, PA —. Règles spéciales : Attaques Supplémentaires (+1), Arme à Deux Mains."},"great-weapon":{"name":"Arme lourde","desc":"Profil : Combat, Force +2, PA -2. Règles spéciales : Arme Perforante (1), Arme à Deux Mains, Frappe en Dernier."},"halberd":{"name":"Hallebarde","desc":"Profil : Combat, Force +1, PA -1. Règles spéciales : Arme Perforante (1), Arme à Deux Mains. Notes (errata) : la PA passe à -2 contre les figurines ennemies que le porteur a chargées ce tour-ci."},"spear":{"name":"Lance / Pique","desc":"Profil : Combat, Force du porteur, PA —. Règle spéciale : Combat sur Plusieurs Rangs. Notes : figurines de type « infanterie » uniquement. Pas d'attaque de soutien au tour où elle charge ; lorsqu'elle est chargée de face, +1 en Initiative contre les unités qui la chargent."},"shield":{"name":"Bouclier","desc":"Améliore la valeur d'armure de 1 (par exemple armure légère 6+ → 5+). Ne peut pas être utilisé avec une arme « Arme à Deux Mains ». Une figurine dont la seule protection est un bouclier a une valeur d'armure de 6+."},"light-armour":{"name":"Armure légère","desc":"Sauvegarde d'Armure de 6+."},"heavy-armour":{"name":"Armure lourde","desc":"Sauvegarde d'Armure de 5+."},"full-plate-armour":{"name":"Armure de plate complète","desc":"Sauvegarde d'Armure de 4+."},"barding":{"name":"Caparaçon","desc":"La monture caparaçonnée améliore la valeur d'armure de la figurine de 1. (Aucune pénalité de Mouvement dans The Old World.)"},"no-armour":{"name":"Aucune armure","desc":"La figurine ne porte pas d'armure : elle est traitée comme ayant une valeur d'armure de 7+ pour les modificateurs de Sauvegarde d'Armure et les règles qui améliorent l'armure. Avec un bouclier seul, sa valeur d'armure devient 6+."},"crossbow":{"name":"Arbalète","desc":"Profil : Tir, Portée 30 ps, Force 4, PA —. Règles spéciales : Arme Perforante (2), Incommode."},"longbow":{"name":"Arc long","desc":"Profil : Tir, Portée 30 ps, Force 3, PA —. Règles spéciales : Arme Perforante (1), Tir de Volée."},"handgun":{"name":"Arquebuse","desc":"Profil : Tir, Portée 24 ps, Force 4, PA -1. Règles spéciales : Arme Perforante (1), Incommode."},"pistol":{"name":"Pistolet","desc":"Profil : Tir, Portée 12 ps, Force 4, PA -1. Règles spéciales : Arme Perforante (1), Tir Rapide. Une fois déchargé, peut servir d'arme de base au corps à corps."},"brace-of-pistols":{"name":"Paire de pistolets","desc":"Profil de tir : Portée 12 ps, Force 4, PA -1 ; Arme Perforante (1), Tirs Multiples (2), Tir Rapide. Profil de combat : Combat, Force du porteur, PA — ; Attaques Supplémentaires (+1), Arme à Deux Mains."},"flail":{"name":"Fléau","desc":"Profil : Combat, Force +2, PA -2. Règles spéciales : Arme Perforante (1), Arme à Deux Mains. Notes (errata) : le bonus de Force et l'Arme Perforante (1) ne s'appliquent que contre les figurines ennemies chargées ce tour-ci."},"morning-star":{"name":"Masse d'armes à pointes","desc":"Profil : Combat, Force +1, PA -1. Règle spéciale : Arme Perforante (1). Notes (errata) : le bonus de Force et l'Arme Perforante (1) ne s'appliquent que contre les figurines ennemies chargées ce tour-ci."},"great-axe":{"name":"Grande hache","desc":"Profil : Combat, Force +2, PA -2. Règles spéciales : Arme Perforante (1), Arme à Deux Mains, Frappe en Dernier."},"pike":{"name":"Pique","desc":"La première et la deuxième rangée peuvent attaquer. Une unité équipée de piques peut compter jusqu'à 2 rangées supplémentaires pour le bonus de rang. Frappe toujours en dernier (Initiative 1) sauf si l'ennemi charge."},"bow":{"name":"Arc","desc":"Portée 24 ps, Force 3."},"repeater-crossbow":{"name":"Arbalète répétitrice","desc":"Profil : Tir, Portée 24 ps, Force 3, PA —. Règles spéciales : Arme Perforante (1), Tirs Multiples (2)."},"throwing-weapons":{"name":"Armes de jet","desc":"Profil : Tir, Portée 9 ps, Force du porteur, PA —. Règles spéciales : Tirs Multiples (2), Mouvement & Tir, Tir Rapide."},"javelin":{"name":"Javeline","desc":"Portée 8 ps, Force utilisateur. Lance comme une arme de trait avant le combat."},"cavalry-spear":{"name":"Lance de cavalerie","desc":"Profil : Combat, Force +1, PA -1. Règle spéciale : Combat sur Plusieurs Rangs. Notes : figurines de type « cavalerie », « monstre » ou « char » uniquement. Les bonus de Force et de PA ne s'appliquent qu'au tour où le porteur a chargé ; pas d'attaque de soutien au tour de la charge."},"thrusting-spear":{"name":"Lance d'infanterie","desc":"Profil : Combat, Force du porteur, PA —. Règle spéciale : Combat sur Plusieurs Rangs. Notes : figurines de type « infanterie » uniquement. Pas d'attaque de soutien au tour où elle charge ; lorsqu'elle est chargée de face, +1 en Initiative contre les unités qui la chargent."},"throwing-spear":{"name":"Javelot (corps à corps)","desc":"Profil : Combat, Force du porteur, PA —. Règle spéciale : Combat sur Plusieurs Rangs. Notes : utilisable uniquement au tour où le porteur a chargé ; sinon, le porteur utilise son arme de base."},"two-hand-weapons":{"name":"Deux armes de base","desc":"Profil : Combat, Force du porteur, PA —. Règles spéciales : Attaques Supplémentaires (+1), Arme à Deux Mains."},"shortbow":{"name":"Arc court","desc":"Profil : Tir, Portée 18 ps, Force 3, PA —. Règles spéciales : Tir Rapide, Tir de Volée."},"warbow":{"name":"Arc de guerre","desc":"Profil : Tir, Portée 24 ps, Force du porteur, PA —. Règle spéciale : Tir de Volée."},"sling":{"name":"Fronde","desc":"Profil : Tir, Portée 18 ps, Force 3, PA —. Règle spéciale : Tirs Multiples (2)."},"throwing-axe":{"name":"Hache de lancer","desc":"Profil : Tir, Portée 9 ps, Force +1, PA —. Règle spéciale : Tir Rapide."},"whip":{"name":"Fouet","desc":"Profil : Combat, Force du porteur, PA —. Règles spéciales : Combat sur Plusieurs Rangs, Frappe en Premier."},"hellblade":{"name":"Lame Infernale","desc":"Profil : Combat, Force du porteur, PA -1. Règle spéciale : Coup de Fendoir."},"plaguesword":{"name":"Épée Pestilentielle","desc":"Profil : Combat, Force du porteur, PA —. Règle spéciale : Arme Perforante (1). Note : les sauvegardes de Régénération ne sont pas autorisées contre les blessures causées par cette arme (les sauvegardes d'Armure et Invulnérables restent possibles)."},"death-s-heads":{"name":"Têtes de Morts","desc":"Profil : Tir, Portée 12 ps, Force +1, PA -1. Règles spéciales : Mouvement & Tir, Blessures Multiples (D3)."},"piercing-claws":{"name":"Pinces Perforantes","desc":"Profil : Combat, Force du porteur, PA -1. Règles spéciales : Arme Perforante (2), Arme à Deux Mains, Attaques Supplémentaires (1)."},"flames-of-tzeentch":{"name":"Flammes de Tzeentch","desc":"Profil : Tir, Portée 18 ps, Force 3, PA —. Règles spéciales : Attaques Enflammées, Tirs Multiples (2), Tir Rapide."},"lamprey-s-bite":{"name":"Morsure de Lamproie","desc":"Profil : Combat, Force du porteur, PA -1. Règle spéciale : Blessures Multiples (D3). Note : Blessures Multiples (D3) ne s'applique qu'aux figurines ennemies de type « monstre »."},"stomp":{"name":"Piétinement","desc":"À la fin de chaque phase de corps à corps, la figurine inflige D3 touches automatiques de Force 3 à une unité ennemie en contact socle à socle (sauf Monstres ou Machines de Guerre)."},"thunder-stomp":{"name":"Piétinement Dévastateur","desc":"À la fin de chaque phase de corps à corps, la figurine inflige D6 touches automatiques de Force 3 à une unité ennemie en contact socle à socle (sauf Monstres ou Machines de Guerre)."},"battle-line":{"name":"Formation de Bataille","desc":"L'unité peut compter ses rangs complets de la même façon qu'une infanterie en rangs serrés. Elle ne souffre pas des pénalités habituelles pour formation ouverte."},"ward-save":{"name":"Sauvegarde Invulnérable","desc":"La figurine dispose d'une Sauvegarde Invulnérable (valeur indiquée). Cette sauvegarde peut être tentée même si la Sauvegarde d'Armure a échoué. Elle ne peut pas être améliorée au-delà de 4+."},"dark-magic":{"name":"Magie Noire","desc":"Magie des Elfes Noirs alimentée par l'énergie corrompue du vortex. Sorts offensifs puissants mais dangereux pour le lanceur."},"daemonology":{"name":"Démonologie","desc":"Domaine de magie qui invoque et manipule les forces daemoniques. Sorts offensifs et d'invocation, risques élevés."},"necromancy":{"name":"Nécromancie","desc":"Magie des morts-vivants. Invoque des squelettes, ranime des cadavres et draine la vie des ennemis."},"lore-of-daemons":{"name":"Lore des Daémons","desc":"Magie des Démons du Chaos. Sorts chaotiques qui reflètent la corruption et la puissance des dieux du Chaos."},"lore-of-undeath":{"name":"Lore des Morts-Vivants","desc":"Magie nécromantique avancée permettant d'invoquer de puissants morts-vivants et de drainer la vie."},"waaagh-magic":{"name":"Magie Waaagh!","desc":"Magie des Orques et Gobelins, alimentée par l'énergie brute des combattants verts. Imprévisible mais puissante."},"lore-of-saphery":{"name":"Lore de Saphery","desc":"Domaine de magie des Hauts Elfes, héritage de la cité de Saphery. Sorts défensifs et de soutien."},"lore-of-beasts":{"name":"Lore des Bêtes","desc":"Magie qui invoque et transforme des créatures sauvages. Sorts de métamorphose et d'invocation animale."},"lore-of-chaos":{"name":"Lore du Chaos","desc":"Magie de mutation et de corruption. Sorts qui transforment les ennemis et invoquent les puissances du Chaos."},"lore-of-the-lady":{"name":"Lore de la Dame","desc":"Magie de Bretonnie, accordée par la Dame du Lac. Sorts de protection, purification et guérison."},"lore-of-athel-loren":{"name":"Lore d'Athel Loren","desc":"Magie des Elfes des Bois issue de la forêt sacrée. Sorts de croissance, de nature et de soin."},"lore-of-chaos-undivided":{"name":"Lore du Chaos Individu","desc":"Magie des Guerriers du Chaos non alignés. Sorts de destruction pure et de corruption."},"lore-of-mork":{"name":"Lore de Mork","desc":"Magie des Gobelins et orques cunning. Sorts de tromperie, pièges et attaques sournoises."},"lore-of-gork":{"name":"Lore de Gork","desc":"Magie des Orques forts. Sorts de combat brutal, d'augmentation de Force et de destruction directe."},"lore-of-nehekhara":{"name":"Incantations de Nehekhara","desc":"Magie des Rois des Tombes. Invoque des squelettes, anime des construits et maudit les ennemis."},"lore-of-the-horned-rat":{"name":"Lore du Rat Cornu","desc":"Magie Skaven canalisée depuis leur dieu. Sorts de pestilence, corruption et manipulation warp."},"lore-of-hashut":{"name":"Lore de Hashut","desc":"Magie des Nains du Chaos dédiée au Père des Ténèbres. Sorts de feu, forge et pétrification."},"lore-of-lustria":{"name":"Lore de Lustria","desc":"Magie ancienne des Hommes-Lézards héritée des Slann. Sorts de contrôle du destin et puissance cosmique."},"lore-of-the-great-maw":{"name":"Lore du Grand Mâchoire","desc":"Magie des Ogres centrée sur la faim dévorante. Sorts d'engloutissement, d'augmentation et de destruction."},"lore-of-the-great-winds":{"name":"Lore des Grands Vents","desc":"Magie de Grand Cathay manipulant les vents magiques. Sorts de tempête, foudre et contrôle des éléments."},"lore-of-the-shadowlands":{"name":"Lore des Terres des Ombres","desc":"Magie des Elfes Noirs issue des Terres des Ombres. Sorts d'obscurité et d'ombre."},"lore-of-naggaroth":{"name":"Lore de Naggaroth","desc":"Magie des Elfes Noirs spécifique à leur continent. Sorts de froid extrême et de malédictions."},"indomitable":{"name":"Indomptable","desc":"Une unité ayant cette règle réduit le nombre de blessures subies à cause de la règle Instable du montant indiqué entre parenthèses (X). Règle non cumulable : si plusieurs figurines de l'unité l'ont, on utilise la valeur la plus élevée pour toute l'unité."},"lance-formation":{"name":"Formation en Lance","desc":"Quand cette unité charge, tous les combattants de la première rangée peuvent attaquer, pas uniquement le premier rang."},"run-with-the-pack":{"name":"Courir avec la Meute","desc":"Tant qu'au moins un Gardien des Bêtes elfe reste dans l'unité, celle-ci n'est pas soumise à la règle Indiscipliné et ses bêtes de guerre ne craignent pas les figurines ayant les Attaques Enflammées. De plus, l'unité peut utiliser la caractéristique de Mouvement de la majorité de ses figurines."},"tree-spirit":{"name":"Esprit des Bois","desc":"Créature magique liée à la forêt. Traite comme Éthéré pour certains effets et bénéficie de protections liées à Athel Loren."},"blood-greed":{"name":"Soif de Sang","desc":"Tant qu'elle est Frénétique, cette figurine bénéficie d'un modificateur de +2 à sa caractéristique d'Attaques (au lieu du +1 habituel). Mais son besoin désespéré de se repaître de chair est tel qu'elle ne lance qu'un seul D6 lors d'un jet de Poursuite (au lieu des 2D6 habituels)."},"ithilmar-weapons":{"name":"Armes en Ithilmar","desc":"Quand elle est engagée au combat et qu'elle combat avec une arme de base, une figurine ayant cette règle peut relancer ses jets pour toucher montrant un 1 naturel. Cela ne s'applique qu'à une unique arme de base non magique et pas à la monture ; si la figurine utilise deux armes de base ou tout autre type d'arme, cette règle cesse de s'appliquer."},"lion-cloak":{"name":"Cape de Lion","desc":"Une figurine ayant cette règle améliore de 1 sa valeur d'armure (maximum 2+) contre les attaques de tir non magiques."},"blessings-of-asuryan":{"name":"Bénédictions d'Asuryan","desc":"Une figurine ayant cette règle bénéficie d'une sauvegarde invulnérable de 5+ contre toute blessure subie causée par une attaque ayant la règle spéciale Attaques Enflammées."},"lileaths-blessing":{"name":"Bénédiction de Lileath","desc":"Une fois par tour, une figurine ayant cette règle peut relancer un seul jet pour lancer raté."},"fear-of-elves":{"name":"Peur des Elfes","desc":"Les Gobelins n'aiment pas les Elfes. Les Elfes de tout type causent la Peur chez les figurines ayant cette règle spéciale."},"scurry-away":{"name":"Décampade Rapide","desc":"Les figurines ayant cette règle bénéficient d'un modificateur de +1 au résultat de tout jet de fuite qu'elles effectuent."},"ogre-charge":{"name":"Charge Ogre","desc":"L'AP de tout Impact de Charge causé par une figurine ayant cette règle (mais pas sa monture) est amélioré du Bonus de Rang actuel de son unité (ou, pour les personnages, du Bonus de Rang actuel de l'unité qu'ils ont rejointe)."},"tusker-charge":{"name":"Charge des Défenses","desc":"Lors d'un tour où il a chargé, les défenses (arme de base) d'un Sanglier de Guerre ont une Force de F+1 et une caractéristique d'AP de -1. Cette règle ne s'applique qu'aux attaques du Sanglier de Guerre lui-même, pas à son cavalier, ni à un char ou son équipage."},"foe-render":{"name":"Déchiqueteur","desc":"Tant qu'elle est soumise à la Furie Primale, une arme de base portée par une figurine ayant cette règle a une caractéristique d'AP de -2. Cela ne vaut que pour une seule arme de base non magique et ne s'applique pas à la monture. Si la figurine utilise deux armes de base ou tout autre type d'arme, cette règle cesse de s'appliquer."},"nuln-state-troops":{"name":"Troupes de Nuln","desc":"Troupes d'élite de la cité de Nuln, maîtres des armes à feu. Bénéficient d'une Formation En Rang et de règles spéciales de fusiliers."},"naval-discipline":{"name":"Discipline Navale","desc":"Une unité de Gardes Maritimes de Lothern peut effectuer une réaction de charge Tenir la Position & Tirer quelle que soit la proximité de l'unité qui charge. Une fois résolue, l'unité chargée peut effectuer gratuitement une manœuvre de remise en ordre des rangs, après quoi elle Tient la Position. Les unités qui fuient, déjà engagées au combat, ou rejointes par un personnage n'ayant pas cette règle ne peuvent pas l'utiliser."},"peasantry":{"name":"Paysannerie","desc":"Si une unité ayant cette règle est à moins de 6 ps d'une figurine amie ayant le Vœu du Chevalier, le Vœu de la Quête ou le Vœu du Graal (et que cette figurine ne fuit pas), elle peut utiliser le Commandement de cette figurine au lieu du sien. De plus, un étendard porté par une unité ayant cette règle ne peut pas compter comme trophée de guerre. Un personnage ayant cette règle ne peut rejoindre qu'une unité ayant aussi cette règle."},"aura-of-the-lady":{"name":"Aura de la Dame","desc":"Toute unité que ce personnage a rejointe gagne la règle spéciale Attaques Magiques."},"shield-of-the-lady":{"name":"Bouclier de la Dame","desc":"Si ce personnage a rejoint une unité de Puissance d'Unité 10 ou plus ayant un Vœu de Chevalerie, il peut volontairement se 'retirer' à l'arrière de l'unité à tout moment. Dans ce cas, il n'est plus dans le rang combattant : il ne peut ni porter d'attaques ni en subir. Il continue toutefois à conférer son Commandement et ses règles spéciales à l'unité, et peut lancer des sorts comme s'il était dans le rang combattant."},"blessed-knight":{"name":"Chevalier Béni","desc":"Chevalier ayant accompli le Pèlerinage du Graal ou reçu la bénédiction de la Dame. Immunisé à la Peur et à la Terreur."},"arrows-of-asaph":{"name":"Flèches d'Asaph","desc":"Les unités ayant cette règle n'appliquent jamais aucun modificateur à leurs jets pour toucher lorsqu'elles tirent, quelle qu'en soit la source."},"curse-of-the-necropolis":{"name":"Malédiction de la Nécropole","desc":"Si une figurine ayant cette règle perd son dernier Point de Vie à cause d'une attaque ennemie, l'unité ayant porté l'attaque doit immédiatement effectuer un test de Commandement. En cas d'échec, l'unité ennemie subit D3 touches de Force 2, chacune avec un AP de -."},"dwarf-crafted":{"name":"Artisanat Nain","desc":"Les figurines ayant cette règle ne subissent pas le malus habituel de -1 pour toucher lors d'une réaction de charge Tenir la Position & Tirer."},"ancestral-grudge":{"name":"Rancune Ancestrale","desc":"Les Nains ont une haine ancestrale de leurs ennemis traditionnels. Relancent les jets de toucher ratés lors du premier tour de combat."},"hold-the-line":{"name":"Tenir la Ligne","desc":"Formation défensive naine. L'unité ne peut pas faire de manœuvre mais obtient +1 en Commandement et ne peut jamais être repoussée."},"master-of-battle":{"name":"Maître du Combat","desc":"Général ou personnage d'exception. Étend le rayon d'influence du Commandement de +6 pouces supplémentaires."},"accomplished-archers":{"name":"Archers Accomplis","desc":"Sauf s'il est monté sur un Lothern Skycutter, un Sea Guard Garrison Commander a les règles Évasif et Tirer & Fuir. De plus, toute unité de Lothern Sea Guard qu'il rejoint gagne les règles Évasif et Tirer & Fuir tant que le personnage reste avec elle."},"bull-gors":{"name":"Bull-Gors","desc":"Les Touches d'Impact causées par une figurine ayant cette règle disposent d'un AP de -1."},"drunken":{"name":"Ivre","desc":"Lors de la sous-phase de Début de Tour de chacun de vos tours, lancez sur la table Ivre pour chaque unité ayant cette règle qui n'est pas déjà Frénétique, ni engagée au combat, ni en fuite : 1 = Titubant (Mouvement Aléatoire D6+2 jusqu'au prochain Début de Tour) ; 2-5 = Dégrisement (aucun effet) ; 6 = Soûlards Belliqueux (soumise à la Frénésie jusqu'au prochain Début de Tour, même si elle l'avait perdue auparavant)."},"slashing-attack":{"name":"Attaque Tranchante","desc":"Une unité ayant cette règle peut effectuer une 'Attaque Tranchante' contre une unité ennemie unique non engagée au combat. Pour cela, elle doit la survoler (en volant) durant la sous-phase des Mouvements Restants. Une fois son mouvement terminé, l'unité ennemie subit D3 touches de Force 4, chacune avec un AP de -, pour chaque figurine de l'unité qui l'a survolée."},"stony-stare":{"name":"Regard de Pierre","desc":"Le regard de l'unité peut pétrifier les ennemis. Cibler une unité à 12 pouces : elle doit tester son Commandement ou subir des touches Force 3."},"ignore-goblin-panic":{"name":"Ignorer la Panique Gobeline","desc":"Les unités d'Orques ignorent les tests de Panique causés par les Gobelins alliés qui fuient à travers ou près d'elles."},"arcane-backlash":{"name":"Contre-Choc Arcanique","desc":"Lorsque l'unité dissipe un sort, elle peut infliquer D3 touches Force 3 à l'unité du lanceur du sort dissipé."},"ithilmar-armour-ithilmar-barding":{"name":"Armure et Caparaçon en Ithilmar","desc":"Une figurine ayant cette règle peut relancer ses jets de 1 lors des tests de terrain dangereux. De plus, un Sorcier ayant cette règle peut porter une armure sans pénalité."},"razor-tusks":{"name":"Défenses Tranchantes","desc":"Lors d'un tour où elle a chargé, l'AP des défenses (arme de base) de cette figurine est amélioré de 1. Cette règle ne s'applique qu'aux attaques de la figurine elle-même, pas à un char ou son équipage."},"finest-warhorses":{"name":"Meilleurs Destriers de Guerre","desc":"Les destriers de guerre de Bretonnie sont élevés pour porter le poids d'un chevalier en armure complète. Quand une unité ayant cette règle effectue un jet de Charge, de Fuite ou de poursuite, elle peut relancer tout dé donnant un 1 naturel, avant d'écarter les dés devant l'être."},"oathstone":{"name":"Oathstone","desc":"Un personnage avec l'Oathstone ne peut pas se déplacer normalement, effectuer de marche forcée ou charger. En revanche, l'unité accompagnée du personnage ne peut jamais fuir comme réaction à une charge. Le personnage bénéficie de la règle Immovable Object."},"mastery-of-the-elemental-winds":{"name":"Mastery of the Elemental Winds","desc":"Le Longma est une créature forgée dans les vents élémentaires ancestraux de Grand Cathay. Le Shugengan qui le chevauche gagne un bonus de +1 à ses jets de lancement pour chaque domaine de magie de Grand Cathay qu'il maîtrise."},"celestial-forged-armour":{"name":"Celestial Forged Armour (5+)","desc":"Cette armure forgée dans la magie céleste accorde une sauvegarde d'armure de 5+. Cette sauvegarde ne peut être ignorée que par des armes magiques ou des attaques de Force 7 ou supérieure."},"chill-scales":{"name":"Chill Scales (5+)","desc":"Les Sang-froids sont couverts d'écailles rigides et glissantes qui leur confèrent une sauvegarde d'armure naturelle de 5+. Cette protection ne se cumule pas avec d'autres formes d'armure portée mais s'applique en toutes circonstances."},"accursed-reliquary":{"name":"Accursed Reliquary","desc":"Tant qu'elles se trouvent à portée de Commandement de cette figurine, les unités amies ayant la règle Mort-Vivant Nécromantique bénéficient d'un modificateur de +1 à leurs caractéristiques de Mouvement et d'Initiative."},"all-sneaky-like":{"name":"All Sneaky Like","desc":"0-1 Bandes de Chevaucheurs de Loups Gobelins de la même liste que Kiknik peuvent bénéficier gratuitement de la règle spéciale Embuscade. De plus, vous pouvez appliquer un modificateur de +1 ou -1 au résultat lorsque vous déterminez si une Bande de Chevaucheurs de Loups Gobelins Embusquée tenue en réserve arrive ce tour en renfort ou est retardée."},"arise":{"name":"Arise!","desc":"Lors de la sous-phase de Commandement de son tour, s'il n'est pas engagé au combat, ce personnage peut tenter de ressusciter les morts par un test de Commandement (avec son propre Commandement). En cas de réussite, une unité amie ayant la règle Morts-Vivants Néhékhariens à moins de 12 ps récupère des Points de Vie perdus selon son type de troupe et le Niveau de Sorcellerie du personnage : infanterie normale/lourde/nuées récupèrent Niveau +D3 ; cavalerie légère/lourde/bêtes de guerre récupèrent Niveau +1 ; infanterie monstrueuse/cavalerie/char léger récupèrent Niveau ; char lourd/créature monstrueuse/béhémoth/machine de guerre récupèrent 1 PV."},"artillery-master":{"name":"Artillery Master","desc":"Sauf s'il fuit ou est engagé au combat, une fois par tour lors de la phase de Tir, une unité amie d'Arbalétriers, de Fusiliers ou une machine de guerre naine à portée de Commandement de ce personnage peut soit relancer ses jets pour toucher de 1 naturel, soit relancer un seul dé d'artillerie."},"beguiling-aura":{"name":"Beguiling Aura","desc":"Les figurines ennemies doivent effectuer un test de Commandement avant tout jet pour toucher contre cette figurine lors de la phase de Combat. En cas d'échec, seuls les 6 naturels touchent."},"blasphemous-tome":{"name":"Blasphemous Tome","desc":"Tous les sorciers (amis comme ennemis) peuvent appliquer un modificateur de +1 à leurs jets pour lancer tant qu'ils sont à portée de Commandement de cette figurine. Cependant, si un sorcier subit un incident magique à portée de Commandement, il doit lancer deux fois sur la table d'Incident Magique et appliquer les deux résultats."},"blessings-of-grimnir":{"name":"Blessings of Grimnir","desc":"Une figurine ayant cette règle peut être désignée pour tenter une Dissipation de Sorcier, comme si elle était un Sorcier. Contrairement aux Sorciers ordinaires, un Gardien de Sanctuaire n'a pas de Niveau de Sorcellerie : il dispose d'une portée de Dissipation de 21 ps et peut appliquer un modificateur de +1 à ses jets de Dissipation."},"blessings-of-khaine":{"name":"Blessings of Khaine","desc":"Même engagée au combat, cette figurine peut lancer le sort lié suivant (Niveau de Puissance 2, Enchantement, Valeur de Lancement 9+, Portée Personnelle) : jusqu'à la prochaine sous-phase de Début de Tour, cette figurine et chaque Sorcière de la Mort, unité d'Exécutrices ou unité de Sœurs du Carnage amie à portée de Commandement gagne l'un des effets suivants : Furie de Khaine (Charge Furieuse), Force de Khaine (Coup Fendoir), ou Égide de Khaine (sauvegarde invulnérable 5+)."},"blessings-of-the-horned-rat":{"name":"Blessings of the Horned Rat","desc":"Cette figurine a une sauvegarde invulnérable de 5+ contre toute blessure causée par une attaque ennemie non magique."},"blessings-of-ulric":{"name":"Blessings of Ulric","desc":"Une figurine ayant cette règle a une sauvegarde invulnérable de 6+ contre toute blessure causée par une attaque ayant les Attaques Enflammées."},"blizzard-aura":{"name":"Blizzard Aura","desc":"Tant qu'elles sont au contact socle à socle de cette figurine, les figurines ennemies deviennent soumises à la règle Frappe en Dernier."},"blood-frenzy":{"name":"Blood Frenzy","desc":"Quand cette figurine (mais pas son cavalier) inflige une blessure non sauvegardée à une figurine ennemie, elle devient soumise à la Frénésie. Elle peut le devenir ainsi même si elle avait perdu la Frénésie plus tôt dans la partie. Notez que son cavalier ne gagne pas de modificateur de +1 à sa caractéristique d'Attaques."},"boldest-of-the-bold":{"name":"Boldest of the Bold","desc":"Araloth ignore tous les modificateurs négatifs à sa caractéristique de Commandement."},"born-of-fire":{"name":"Born of Fire","desc":"Un Bale Taurus ou Great Taurus a une sauvegarde invulnérable de 3+ contre toute blessure causée par une attaque ayant les Attaques Enflammées."},"borne-aloft":{"name":"Borne Aloft","desc":"Une figurine avec Porteurs de Bouclier se compose non pas d'une mais de quatre figurines (le personnage et trois fidèles serviteurs) occupant un seul socle et agissant comme une seule entité. Pour le représenter, elle a un profil divisé et suit la règle Profil Divisé (Cavalerie). À tous les autres égards, elle est traitée comme de l'infanterie lourde."},"bull-charge":{"name":"Bull Charge","desc":"Les Impacts de Charge causés par cette figurine (mais pas sa monture) ont une caractéristique d'AP de -1."},"carrion-feeders":{"name":"Carrion Feeders","desc":"Les unités ennemies engagées au combat avec cette figurine subissent un modificateur de -1 à leur caractéristique d'Initiative."},"cathayan-cataphracts":{"name":"Cathayan Cataphracts","desc":"Lorsqu'une unité dont la majorité des figurines ont cette règle effectue un mouvement de suite, elle compte comme ayant chargé lors du tour suivant."},"chainmaker":{"name":"Chainmaker","desc":"Tout étendard ennemi capturé par Frydaal ou par une unité qu'elle a rejointe vaut 100 Points de Victoire en tant que trophée de guerre."},"champions-of-chrace":{"name":"Champions of Chrace","desc":"Toute figurine d'une unité de Lion Guard peut accepter les duels à la manière d'un personnage. De plus, une fois par tour, un personnage ayant rejoint une unité de Lion Guard peut relancer son jet de \"Attention, Messire !\"."},"cloud-of-dust":{"name":"Cloud of Dust","desc":"Toute figurine ennemie qui prend cette figurine pour cible lors de la phase de Tir subit un modificateur supplémentaire de -1 pour toucher."},"cloud-of-flies":{"name":"Cloud of Flies","desc":"Toute figurine ennemie dirigeant ses attaques contre ce personnage lors de la phase de Combat subit un modificateur de -1 à ses jets pour toucher."},"clouds-of-soot-and-smoke":{"name":"Clouds of Soot & Smoke","desc":"Sauf si elle est montée, cette figurine est considérée comme bénéficiant d'un couvert total tant qu'elle se trouve à moins de 3 ps d'une unité amie dont le type de troupe est machine de guerre."},"commander-and-captain":{"name":"Commander & Captain","desc":"Sauf si elle fuit, les unités amies de Maraudeurs du Chaos, Cavaliers Maraudeurs, Huscarls et Berserkers de Tribu Maraudeuse gagnent un modificateur de +1 à leur Commandement tant qu'elles se trouvent à portée de Commandement de Frydaal (jusqu'à un maximum de 10)."},"covenant-of-power":{"name":"Covenant of Power","desc":"Tant qu'ils sont à moins de 12 ps d'un Casket of Souls, les Liche Priests amis peuvent appliquer un modificateur de +1 à leurs jets pour lancer. De plus, toute figurine (amie ou ennemie) lançant un sort lien à moins de 12 ps d'un Casket of Souls peut appliquer un modificateur de +1 à son jet pour lancer. Ce bonus ne s'applique pas aux sorts liens lancés par un Casket of Souls lui-même."},"crown-of-antlers":{"name":"Crown of Antlers","desc":"Les Impacts de Charge causés par une figurine ayant cette règle bénéficient de la règle Armure Brisée (1) et d'une caractéristique d'AP de -1."},"crushing-weight":{"name":"Crushing Weight","desc":"Les Attaques de Piétinement d'un War Wagon ont une caractéristique d'AP de -1. De plus, contrairement aux autres chars, cette figurine traite les obstacles linéaires bas comme un terrain dangereux plutôt que comme un terrain infranchissable."},"dances-of-loec":{"name":"Dances of Loec","desc":"Quand le combat de cette unité est choisi à l'Étape 1.1 d'une sous-phase Choisir & Livrer les Combats, choisissez l'une des Danses de Loec : Mort Tournoyante (AP amélioré de 2 jusqu'à la fin de la phase de Combat) ; Tempête de Lames (+1 Attaque jusqu'à la fin de la phase de Combat) ; La Spirale des Ombres (sauvegarde invulnérable 4+ jusqu'à la fin de la phase de Combat) ; Brume Tissée (les ennemis subissent -1 pour toucher jusqu'à la fin de la phase de Combat). Un Danseur des Ombres rejoignant cette unité est considéré comme ayant aussi cette règle."},"deflect-shots":{"name":"Deflect Shots","desc":"Une figurine ayant cette règle a une sauvegarde invulnérable de 6+ contre toute blessure causée par une attaque de tir non magique."},"dig-in":{"name":"\"Dig In!\"","desc":"Lors de n'importe quelle sous-phase de Commandement, s'il n'est pas engagé au combat, ce personnage peut tenter de faire creuser des fortifications de campagne par un test de Commandement (avec son propre Commandement). En cas de réussite, ce personnage et toute unité rejointe deviennent 'Retranchés' : ils comptent comme étant derrière un couvert partiel et défendant un obstacle linéaire bas. Si l'unité se déplace pour quelque raison que ce soit, elle n'est plus Retranchée."},"disengage":{"name":"Disengage","desc":"Si cette figurine perd un round de combat et Cède du Terrain, elle peut choisir d'effectuer un Repli en Bon Ordre à la place. Les unités ennemies peuvent suivre comme si elle avait cédé du terrain (avance de 2 ps droit vers elle) mais ne peuvent pas la poursuivre. De plus, si elle gagne un round de combat et choisit de se retenir et se reformer, elle peut choisir d'effectuer un Repli en Bon Ordre plutôt que de rester en place."},"dispersed-formation":{"name":"Dispersed Formation","desc":"En formation de Tirailleurs, chaque figurine d'une unité de Chevaliers Pégases doit se trouver à moins de 2 ps d'une autre figurine de la même unité, au lieu du 1 ps habituel."},"drop-rocks":{"name":"Drop Rocks","desc":"Une fois par partie, une unité ayant cette règle peut effectuer une attaque 'Larguer des Rochers' contre une unité ennemie non engagée au combat. Pour cela, elle doit se déplacer (en volant) au-dessus de cette unité lors de la sous-phase des Mouvements Restants. Une fois son mouvement terminé, l'unité ennemie subit D3 touches de Force 4 (AP -) par figurine de cette unité ayant survolé."},"entrenchment":{"name":"Entrenchment","desc":"Lors du déploiement, vous pouvez 'Retrancher' une figurine non-personnage dont le type de troupe est 'machine de guerre' pour chaque personnage de votre armée ayant cette règle. Une machine de guerre Retranchée est considérée comme bénéficiant d'un couvert partiel et défendant un obstacle linéaire bas. Si la machine se déplace pour quelque raison que ce soit, elle n'est plus Retranchée."},"extended-formation":{"name":"Extended Formation","desc":"En formation de Tirailleurs, chaque figurine d'une unité de Gyrocoptères Éclaireurs doit se trouver à moins de 3 ps d'une autre figurine de la même unité, au lieu du 1 ps habituel."},"eye-of-the-dragon":{"name":"Eye of the Dragon","desc":"Les figurines amies dont les armes tirent avec la règle Bombardement peuvent tirer en utilisant la ligne de vue de cette figurine plutôt que la leur."},"favour-of-the-goddess":{"name":"Favour of the Goddess","desc":"Araloth a une sauvegarde invulnérable de 5+ contre toute blessure subie."},"from-beneath-the-sands":{"name":"From Beneath the Sands","desc":"Lors de la sous-phase de Commandement de son tour, s'il n'est pas engagé au combat, ce personnage peut choisir une unité amie ayant à la fois les règles Morts-Vivants Néhékhariens et Embuscade, tenue en réserve, et tenter de l'invoquer par un test de Commandement. En cas de réussite, l'unité est placée entièrement à moins de 12 ps de ce personnage, mais à plus de 6 ps de toute figurine ennemie. En cas d'échec, elle est retardée au moins jusqu'au tour suivant. Les Embusqués arrivent automatiquement au début du cinquième round comme d'habitude."},"from-the-ashes":{"name":"From the Ashes","desc":"Quand un Phénix Flamboyant perd son dernier Point de Vie, lancez un D6 avant de retirer la figurine : sur 1-2, le Phénix se réduit en cendres froides et est retiré du jeu ; sur 3-5, il explose en flammes et chaque unité ennemie au contact socle à socle subit D6 touches de Force 3 (AP -1, Attaques Enflammées) avant que la figurine ne soit retirée ; sur 6, le Phénix (et son cavalier éventuel) est brièvement consumé puis immédiatement renaît, récupérant D3 Points de Vie."},"ghoulish-glamour":{"name":"Ghoulish Glamour","desc":"Les unités ennemies doivent effectuer un test de Commandement avant tout jet pour toucher contre cette figurine lors de la phase de Combat. En cas d'échec, seuls les 6 naturels touchent."},"giant-attacks":{"name":"Giant Attacks","desc":"Au lieu d'attaquer normalement lors de la phase de Combat, un Géant peut choisir d'effectuer une 'Attaque de Géant'. Lancez sur la table des Attaques de Géant (D6) : 1 = Coup de Boule, 2 = Aplatissement, 3-4 = Grand Moulinet, 5 = Coup de Massue, 6 = Sautiller sur Place."},"great-censer":{"name":"Great Censer","desc":"Les Attaques d'Écrasement d'une Châsse à Encens représentent le grand encensoir lâché dans les rangs ennemis : elles ont une valeur de Pénétration d'Armure de -2. De plus, tant qu'elles se trouvent à moins de 3 ps d'une ou plusieurs figurines ayant cette règle, les unités ennemies subissent un modificateur de -1 à leur Endurance (jusqu'à un minimum de 1)."},"handler":{"name":"Handler","desc":"Un Maître-Chien de Limiers du Chaos est un type particulier de personnage pris en amélioration pour accompagner une unité de Limiers du Chaos. Au déploiement, placez-le avec son unité comme un personnage l'ayant rejointe ; une fois placé, il ne peut plus la quitter. Sauf s'il fuit, les unités amies de Limiers du Chaos à portée de Commandement peuvent utiliser son Commandement au lieu du leur."},"heavenly-beacon":{"name":"Heavenly Beacon","desc":"Sauf si cette figurine fuit, les unités amies à moins de 12 ps peuvent relancer tout test de Panique ou de Ralliement raté. De plus, tant qu'elle est sur le champ de bataille et ne fuit pas, vous pouvez appliquer un modificateur de +1 ou -1 pour déterminer si une unité amie Embusquée arrive ou est retardée. Enfin, un Seigneur Magistrat ou Stratège monté sur une Lanterne Céleste a une portée de Commandement de 12 ps."},"hekartis-blessing":{"name":"Hekarti's Blessing","desc":"Une fois par partie, une figurine ayant cette règle peut relancer un seul jet pour lancer raté."},"hit-and-run":{"name":"Hit & Run","desc":"Si elle gagne un round de combat, une unité ayant cette règle peut choisir d'effectuer un Repli en Bon Ordre plutôt qu'un mouvement de suite ou de poursuite."},"holy-fervour":{"name":"Holy Fervour","desc":"Sauf si cette unité fuit, les unités amies à moins de 6 ps d'elle réussissent automatiquement tout test de Peur qu'elles doivent effectuer et peuvent relancer tout test de Panique raté."},"hostile-terrain":{"name":"Hostile Terrain","desc":"Toute figurine ennemie qui termine son mouvement à portée de Commandement d'un ou plusieurs personnages ayant cette règle (qui ne fuient pas et ne sont pas engagés au combat) doit effectuer un test de terrain dangereux."},"immortal-overseer":{"name":"Immortal Overseer","desc":"Lors de la sous-phase de Commandement de son tour, ce personnage peut tenter de pousser une unité amie à portée de Commandement à de plus grands efforts par un test de Commandement. En cas de réussite, jusqu'à la prochaine sous-phase de Début de Tour, cette unité gagne un modificateur de +D3 à son Initiative (jusqu'à un maximum de 10)."},"infernal-engineer":{"name":"Infernal Engineer","desc":"Sauf si cette figurine fuit ou est engagée au combat, une fois par tour une machine de guerre amie située à portée de Commandement peut relancer un dé de dispersion ou un dé d'artillerie."},"infested":{"name":"Infested","desc":"Quand cette figurine perd son dernier Point de Vie, chaque unité au contact socle à socle (amie ou ennemie) subit D6 touches de Force 2, chacune avec un AP de -1."},"it-and-run":{"name":"'It & Run","desc":"S'ils gagnent un round de combat, Kiknik et toute Bande de Chevaucheurs de Loups Gobelins qu'il a rejointe peuvent choisir d'effectuer un Repli en Bon Ordre plutôt qu'un mouvement de suite ou de poursuite."},"marks-of-chaos":{"name":"Marks of Chaos","desc":"De nombreuses figurines ont la Marque du Chaos Non Divisé parmi leurs règles spéciales ; certaines peuvent la remplacer par la Marque d'un dieu du Chaos spécifique. Une figurine ne peut avoir qu'une seule Marque du Chaos, et toutes les figurines d'une unité doivent avoir la même. Un personnage portant la Marque d'un dieu précis ne peut rejoindre qu'une unité ayant la même Marque, la Marque du Chaos Non Divisé, ou aucune Marque. Les bénéfices d'une Marque s'appliquent au seul porteur, pas à sa monture."},"master-of-ballistics":{"name":"Master of Ballistics","desc":"Sauf s'il fuit ou est engagé au combat, une fois par tour, une machine de guerre amie de l'Empire à portée de Commandement de cette figurine peut soit utiliser sa Capacité de Tir, soit relancer un seul dé d'artillerie."},"numbing-chill":{"name":"Numbing Chill","desc":"Tant qu'elles sont au contact de cette figurine, les figurines ennemies subissent un modificateur de -1 à leurs caractéristiques de Capacité de Combat et d'Initiative, jusqu'à un minimum de 1."},"peerless-raider":{"name":"Peerless Raider","desc":"0-1 unité de Chaos Marauders ou Marauder Horsemen de la même liste de rassemblement que Frydaal peut recevoir la règle Embusqués gratuitement. De plus, si Frydaal est votre Général, vous pouvez appliquer un modificateur de +1 ou -1 au jet déterminant si elle, ou toute unité de Chaos Marauders, Marauder Horsemen, Marauder Tribe Huscarls ou Marauder Tribe Berserkers ayant Embusqués, arrive en renfort ou est retardée."},"pick-up-and":{"name":"Pick Up And...","desc":"Au lieu d'attaquer normalement ou de faire une Attaque de Géant, un Géant engagé avec de l'infanterie normale ou lourde peut effectuer une attaque 'Attraper et...'. Désignez une unité ennemie d'infanterie normale ou lourde au contact socle à socle : elle effectue un test d'Initiative ; si raté, une figurine est retirée comme perte ; si réussi, personne n'est attrapé. Lancez ensuite un D6 : sur 1-3 le Géant s'arrête, sur 4+ il tente d'en attraper une autre. On continue jusqu'à ce que le Géant s'arrête ou que l'unité cible soit détruite."},"prayers-of-sigmar":{"name":"Prayers of Sigmar","desc":"Lors de la sous-phase de Commandement, ce personnage peut tenter d'invoquer les bénédictions de Sigmar en récitant une seule Prière et en effectuant un test de Commandement. En cas de réussite : Marteau de Sigmar (ce personnage, sa monture et une unité amie à portée de Commandement peuvent relancer les jets pour toucher ou pour blesser de 1 naturel lors de la phase de Combat) ; Bouclier de la Foi (ce personnage et une unité amie à portée de Commandement gagnent une sauvegarde invulnérable 5+ lors de la phase de Tir) ; ou Feu de l'Âme (une unité ennemie engagée subit D6 touches de Force 3, AP -2, Attaques Enflammées et Magiques)."},"rampant-mutation":{"name":"Rampant Mutation","desc":"Quand le combat de cette unité est choisi lors de l'Étape 1.1 d'une sous-phase Choisir & Livrer les Combats, lancez un D6 : 1-2 = Crocs Venimeux (Attaques Empoisonnées) ; 3-4 = Serres Tranchantes (toutes les attaques à AP -2) ; 5-6 = Griffes Décapitantes (Coup Fatal)."},"release-the-fanatics":{"name":"Release the Fanatics!","desc":"Les Fanatiques ne sont pas placés sur la table au début de la partie ; notez quelles unités de Gobelins de la Nuit en comportent. Sauf si elle fuit ou est en Colonne de Marche, une unité dissimulatrice peut en libérer un ou plusieurs lors de n'importe quelle sous-phase de Début de Tour : placez le Fanatique à moins de 3 ps de son unité, sans toucher d'autres figurines. Lors de la sous-phase des Mouvements Obligatoires de sa libération, il se déplace de 2D6 ps dans une direction choisie par le joueur ; ensuite, il se déplace de 2D6 ps dans une direction aléatoire. S'il entre en contact avec une unité, il la traverse. Un Fanatique est retiré si un double naturel est obtenu pour son mouvement, ou s'il entre dans un terrain difficile, dangereux, infranchissable ou un obstacle linéaire. Si une unité dissimulatrice est détruite ou fuit avant de libérer ses Fanatiques, ceux-ci sont retirés comme pertes."},"scrying-pool":{"name":"Scrying Pool","desc":"Même engagée au combat, cette figurine peut lancer le sort lié suivant (Niveau de Puissance 2, Enchantement, Valeur de Lancement 9+, Portée Personnelle) : jusqu'à la prochaine sous-phase de Début de Tour, cette figurine peut relancer ses jets pour toucher de 1 naturel."},"scurrying-masses":{"name":"Scurrying Masses","desc":"Tant qu'elle se trouve à moins de 3 ps d'une unité amie, cette figurine gagne un modificateur positif (+) à son Commandement égal au Bonus de Rang actuel de cette unité, jusqu'à un maximum de Commandement 10."},"skaryn-the-eye-thief":{"name":"Skaryn the Eye Thief","desc":"Lors de la sous-phase de Commandement de son tour, Araloth peut tenter de lâcher Skaryn en lançant un D6. Sur 1-2, rien ne se passe. Sur 3+, désignez une figurine ennemie à moins de 18 ps d'Araloth : elle subit une touche de Force 4 avec un AP de -1. Si elle subit une blessure non sauvegardée, sa CC et son Initiative sont réduites de D3 (jusqu'à un minimum de 1) pour le reste de la partie."},"slaughterers-call":{"name":"Slaughterer's Call","desc":"Tant que cette figurine est Frénétique, toute unité qu'elle a rejointe devient également Frénétique."},"slavering-charge":{"name":"Slavering Charge","desc":"Lors d'un tour où elle a chargé, cette figurine bénéficie d'un modificateur de +1 à sa caractéristique de Force."},"sorcerers-curse":{"name":"Sorcerer's Curse","desc":"Si cette figurine rate le lancement d'un sort, elle doit immédiatement effectuer un test d'Endurance. En cas d'échec, elle perd un Point de Vie et gagne un modificateur de +1 à son Endurance au lieu de lancer sur la table de Fiasco. En cas de réussite, elle lance normalement sur la table de Fiasco."},"sorcerous-miasma":{"name":"Sorcerous Miasma","desc":"Lors de la phase de Combat, toute figurine ennemie qui utilise une arme magique pour attaquer un personnage monté sur un Lammasu compte comme armée d'une simple arme de base à la place."},"stable-firing-platform":{"name":"Stable Firing Platform","desc":"Pour refléter la stabilité d'un War Wagon, toute arme de tir portée par son équipage peut être utilisée lors de la phase de Tir même si le War Wagon a marché ce tour-ci."},"stand-back-chief":{"name":"\"Stand Back Chief\"","desc":"Un personnage ayant cette règle ne peut pas être pris pour cible par le tir ou les sorts ennemis tant qu'il se trouve à moins de 3 ps d'une unité amie dont le type de troupe est machine de guerre."},"stone-skeleton":{"name":"Stone Skeleton","desc":"Cette figurine est moins vulnérable à la règle Blessures Multiples (X). Si elle subit une blessure non sauvegardée d'une attaque ayant cette règle, réduisez de 1 le nombre de Points de Vie perdus, jusqu'à un minimum de 1."},"symbol-of-might":{"name":"Symbol of Might","desc":"La portée de Commandement d'un Lecteur de Sigmar monté sur l'Autel de Guerre passe de 8 ps à 12 ps. Si cette figurine est votre Général, elle conserve une portée de Commandement de 18 ps comme d'habitude."},"the-arrow-of-kurnous":{"name":"The Arrow of Kurnous","desc":"Une fois le déploiement achevé, mais avant le jet pour déterminer qui joue en premier, si le Général de l'armée adverse est à moins de 36 ps d'une ou plusieurs figurines amies ayant cette règle, l'une d'elles peut tirer la Flèche de Kurnous. Le Général subit une touche de Force 3 sans sauvegarde d'armure ni de Régénération permise (la sauvegarde invulnérable reste autorisée). Toutefois, si la Flèche est tirée, l'adversaire ajoute +1 à son jet pour déterminer qui joue en premier."},"the-newly-dead":{"name":"The Newly Dead","desc":"Lors de la résurrection de figurines tombées, une unité ayant cette règle peut dépasser sa taille de départ (mais pas sa taille maximale)."},"thunderous-charge":{"name":"Thunderous Charge","desc":"Les Impacts de Charge causés par cette figurine ont une caractéristique d'AP de -2."},"toad-rage":{"name":"Toad Rage","desc":"Avant le début de la partie (après le déploiement des Éclaireurs), placez un marqueur de crapaud sur une unité ennemie par unité de Ripperdactyl Riders. Lorsqu'ils sont engagés au combat avec une unité portant un marqueur de crapaud, les Ripperdactyls (pas leurs cavaliers) gagnent Attaques Supplémentaires (+1) et peuvent relancer leurs jets pour toucher obtenant un 1 naturel."},"tolling-the-bell":{"name":"Tolling the Bell","desc":"Une Screaming Bell peut être sonnée lors de la sous-phase de Commandement. Lancez 2D6 : 2 = Retour de Flamme Magique (D3 touches F4 AP-2 à tous à portée de Commandement) ; 3-4 = Carillon Dissonant (-1 Cd aux ennemis à 18 ps) ; 5-6 = Mur de Son Impie (les Skavens amis à 18 ps gagnent la Peur) ; 7 = Puissance Résonnante (+1 aux jets pour lancer des sorciers amis à portée de Commandement) ; 8-9 = Clameur Galvanisante (Immunité à la Psychologie pour les Skavens à 18 ps) ; 10-11 = Tintement Extatique (Attaques Supplémentaires +1 pour les Skavens à 18 ps) ; 12 = Glas Sonore (les ennemis à 18 ps font un test de Cd ou subissent D6 touches F4, sans sauvegarde d'armure ni de Régénération)."},"totem-of-endless-bloodletting":{"name":"Totem of Endless Bloodletting","desc":"Les Démons de Khorne amis situés à portée de Commandement de cette figurine et ayant effectué un mouvement de charge ce tour-ci peuvent relancer leurs jets pour toucher obtenant un 1 naturel lors de la phase de Combat."},"two-headed-dragon":{"name":"Two-headed Dragon","desc":"Un Chaos Dragon / Galruch peut utiliser soit le Feu Sombre du Chaos, soit les Émanations de Contagion lors de la phase de Tir de son tour. Il ne peut pas utiliser les deux durant le même tour."},"unbound-spirits":{"name":"Unbound Spirits","desc":"Si l'équipage d'un Coffre des Âmes est réduit à zéro Point de Vie, lancez immédiatement un D6 pour chaque unité (amie ou ennemie) à moins de 12 ps de la figurine. Sur 4+, l'unité subit D6 touches de Force 3, sans sauvegarde d'armure ni de Régénération (la sauvegarde invulnérable reste permise). Une fois les touches résolues, le Coffre des Âmes est retiré du jeu."},"unstoppable-assault":{"name":"Unstoppable Assault","desc":"Lors de la phase de Combat d'un tour où cette figurine a chargé, chaque attaque qu'elle porte et qui cause une blessure non sauvegardée lui permet d'effectuer immédiatement une attaque supplémentaire. Ces attaques supplémentaires bénéficient aussi de cette règle. Les blessures non sauvegardées causées par Attaques de Piétinement (D3) n'en bénéficient pas."},"vortex-of-souls":{"name":"Vortex of Souls","desc":"Un Coffre des Âmes peut lancer les sorts liés suivants (Niveau de Puissance 2) : Lumière de la Mort & Lumière de Protection. Lumière de la Mort : l'unité ennemie cible effectue un test de Commandement ; si réussi, elle subit D3 touches de Force 3 (AP -1) ; si raté, elle subit D6+3 touches de Force 6 avec Blessures Multiples (2), sans sauvegarde d'armure ni de Régénération. Lumière de Protection (Reste en Jeu) : cette figurine et toute unité amie à moins de 18 ps gagnent une sauvegarde invulnérable 6+, et les unités ennemies subissent -1 pour toucher contre elles."},"wake-of-fire":{"name":"Wake of Fire","desc":"Cette figurine peut effectuer une attaque 'Sillage de Feu' contre une unité ennemie unique non engagée au combat. Pour cela, elle doit la survoler (en volant) durant la sous-phase des Mouvements Restants. Une fois son mouvement terminé, l'unité ennemie subit D6 touches de Force 4, chacune avec un AP de -1 et la règle spéciale Attaques Enflammées."},"witch-bane":{"name":"Witch Bane","desc":"Tous les Sorciers à portée de Commandement de cette figurine (amis ou ennemis) subissent un modificateur de -2 à leurs jets de Lancement."},"witness-to-destiny":{"name":"Witness to Destiny","desc":"Cette unité a une sauvegarde invulnérable de 6+ contre toute blessure causée par une attaque ennemie non magique."}};
